// GENERATED by tools/gen_ko_landmarks.py — Korean landmark texts,
// keyed by '<citySlug>/<icon>'. Regenerate with the script; do not
// hand-edit individual entries.

const Map<String, (String nameKo, String descKo)> kLandmarkKo = {
  'chengdu/panda': ('청두 판다 기지', '청두 자이언트판다 번식연구기지는 세계 최대의 판다 보호·번식 센터예요. 도시의 상징인 판다가 대나무 숲에서 뒹구는 모습을 보려고 해마다 수백만 명이 찾아와요.'),
  'chengdu/hotpot': ('쓰촨 훠궈', '혀를 얼얼하게 하는 쓰촨 산초와 새빨간 고추기름이 보글보글 끓는 훠궈는 청두 식탁 문화의 심장이에요. 식탁 한가운데 놓인 냄비에 저마다 자기 몫을 담가 먹는데, 이곳에서 식사는 함께 즐기는 하나의 놀이랍니다.'),
  'chengdu/bianlian': ('변검', '쓰촨 전통극의 신비로운 예술인 변검(볜롄)에서는 명인들이 손짓 한 번으로 눈 깜짝할 사이에 화려한 가면을 바꿔요. 그 비법은 오직 스승에게서 제자에게로만 전해진답니다.'),
  'chengdu/jinli': ('진리 고거리', '붉은 등불이 밝히는 진리 거리는 삼국시대까지 거슬러 올라가는 오래된 시장 골목이에요. 찻집과 그림자극, 설탕으로 용을 그리는 장인들이 있는 이곳에서 청두 특유의 느긋한 삶의 리듬을 가장 잘 느낄 수 있어요.'),
  'nanjing/citywall': ('난징 명성벽', '명나라를 세운 황제가 수도를 지키기 위해 쌓은 이 거대한 성벽은 현재 남아 있는 세계에서 가장 긴 성벽이에요. 품질 보증을 위해 벽돌마다 만든 장인의 이름이 새겨져 있고, 성벽 위를 걸으면 난징의 옛 모습과 새 모습을 한눈에 볼 수 있답니다.'),
  'nanjing/plum': ('매화', '한겨울 눈 속에서 피어나는 매화는 중국 문화에서 강인함과 희망의 상징이에요. 난징은 매화를 시의 꽃으로 삼았고, 늦겨울이면 메이화산 언덕이 분홍빛과 흰빛 꽃바다로 변해 사람들이 나무 아래를 거닐며 봄나들이를 즐겨요.'),
  'nanjing/duck': ('염수압', '난징 요리의 대표인 소금절임 오리는 향신료 소금물에 재웠다가 은근히 삶아 차갑게 내는 음식이에요. 부드러운 육질과 은은한 간이 일품이라 오리는 이 도시 전체의 열정이 되었죠. \'난징에서는 어떤 오리도 살아서 도시를 떠나지 못한다\'는 우스갯소리까지 있을 정도랍니다.'),
  'nanjing/bridge': ('난징 장강대교', '1968년 중국 기술자들의 손으로만 완성된 난징 창장대교는 도로와 철도를 함께 싣고 강을 건너는 거대한 2층 다리예요. 외국의 도움 없이 지어졌기에 현대 중국의 자립을 상징하는 자랑거리가 되었고, 지금도 교과서에 자랑스럽게 실려 있어요.'),
  'qingdao/beer': ('칭다오 맥주', '독일 통치 시절 세워진 양조장 덕분에 칭다오 맥주는 세계에서 가장 유명한 중국 맥주가 되었어요. 여름마다 열리는 국제 맥주 축제가 도시를 축제 분위기로 물들이고, 갓 뽑은 생맥주를 비닐봉지에 담아 빨대로 마시는 풍경은 칭다오에서 가장 사랑스러운 길거리 전통이랍니다.'),
  'qingdao/sailing': ('요트 도시', '2008년 올림픽 요트 경기가 칭다오의 마리나에서 열렸고, 그 후로 이 도시는 \'요트의 도시\'라는 별명을 갖게 되었어요. 바람 부는 만과 수평선을 수놓은 하얀 돛, 길게 이어진 해안 산책로 덕분에 칭다오는 중국 해양 스포츠의 수도로 꼽혀요.'),
  'qingdao/beach': ('해변', '칭다오의 해변은 언덕 위 붉은 지붕의 독일풍 건축물 앞으로 펼쳐져, 중국에서는 보기 드문 유럽 해안 마을 분위기를 자아내요. 여름이면 백사장이 물놀이하는 사람들로 가득 차고, 만과 만을 잇는 해안 산책로는 해질녘 산책의 고전 코스랍니다.'),
  'qingdao/crab': ('해산물', '황해를 마주한 칭다오에서는 매일 신선한 해산물이 식탁에 올라요. 조개, 굴, 성게, 게를 파는 좌판이 부둣가를 가득 메우죠. 그날 잡은 해산물을 담백하게 쪄서 얼음처럼 차가운 칭다오 맥주와 곁들이는 것이 현지 방식이에요.'),
  'changsha/pepper': ('고추', '후난 요리는 쓰촨의 얼얼한 매운맛과 달리 건조하고 칼칼한 매운맛으로 유명해서, 거의 모든 요리에 생고추와 절임 고추가 들어가요. 창사에서 매운맛은 습한 기후에 맞서 온 오랜 전통이에요. 현지 사람들은 \'매운 건 무섭지 않다, 맵지 않은 게 무섭다\'고 농담하곤 해요.'),
  'changsha/tofu': ('취두부', '발효 소금물에 담갔다가 튀겨 내는 창사의 취두부는 겉은 새까맣고 바삭한데 속은 눈처럼 하얗고 부드러워요. 코를 찌르는 냄새에 속지 마세요. 매콤한 소스를 끼얹은 이 작은 한 입은 창사 야시장에서 가장 긴 줄을 세우는 별미랍니다.'),
  'changsha/fireworks': ('불꽃놀이', '창사 옆 류양은 수백 년 동안 세계 불꽃놀이의 중심지로 여겨져 왔어요. 화약의 고향에서 이 기술은 대대로 전해 내려오죠. 샹장 강변에서 정기적으로 열리는 불꽃 쇼에서는 하늘과 강물이 동시에 형형색색으로 물들어요.'),
  'changsha/orange': ('쥐쯔저우', '샹장 한가운데 길게 뻗은 쥐쯔저우(귤섬)는 강변을 가득 채운 귤나무 밭에서 이름을 얻었어요. 젊은 시절 이 강에서 헤엄치던 마오쩌둥은 이 섬을 노래한 유명한 시를 남겼고, 지금은 섬 끝자락에서 젊은 마오의 거대한 화강암 두상이 강을 내려다보고 있어요.'),
  'zhengzhou/kungfu': ('소림무술', '정저우 근처 쑹산 기슭에 자리한 소림사는 선불교와 소림 쿵후가 태어난 곳이에요. 약 1,500년 역사의 사찰 주변 무술 학교에서는 지금도 수천 명의 학생이 새벽부터 시작되는 수련으로 그 유산을 이어 가고 있답니다.'),
  'zhengzhou/train': ('철도 허브', '정저우는 중국의 남북·동서 주요 철도가 교차하는 지점에서 성장한 교통의 요충 도시예요. \'기차가 실어 온 도시\'라고 불리며, 오늘날에도 중국 고속철도망에서 가장 붐비는 환승 허브 중 하나랍니다.'),
  'zhengzhou/wheat': ('밀 평원', '황허가 적셔 주는 허난 평야는 중국 최대의 밀 곡창지대 중 하나예요. 이 비옥한 땅이 북방 요리의 영혼을 길러 내죠. 손으로 뽑는 국수, 찐만두, 화덕에 구운 빵이 모두 이 들판의 밀에서 시작된답니다.'),
  'zhengzhou/ding': ('청동 정', '정저우와 그 주변에는 중국에서 가장 오래된 왕조 중 하나인 상나라의 수도가 있었고, 발굴 과정에서 제례에 쓰인 청동 솥 \'딩\'이 세상에 모습을 드러냈어요. 이 솥은 권력과 조상에게 바치는 제물의 상징이었기에, 정저우는 중국 문명의 요람 중 하나로 꼽힌답니다.'),
  'wuxi/lake': ('타이후', '우시는 중국에서 가장 큰 담수호 중 하나인 타이후 호숫가에 자리 잡고 있어요. 호수에서 나는 생선과 새우, 수생 채소가 이곳 요리의 바탕이 되죠. 해질녘 위안터우주 곶에서 바라보는 호수는 벚꽃 철이면 한층 더 마법 같은 풍경으로 변해요.'),
  'wuxi/peach': ('양산 복숭아', '우시의 양산 마을은 꿀처럼 달고 과즙이 넘쳐 숟가락으로 떠먹을 수 있을 정도로 부드러운 복숭아로 중국 전역에 이름을 떨쳤어요. 한여름에 열매가 익으면 마을 전체가 축제 분위기가 되고, 과수원이 방문객에게 활짝 열린답니다.'),
  'wuxi/figurine': ('후이산 진흙 인형', '후이산 진흙 인형은 우시의 산기슭에서 나는 부드러운 검은 진흙으로 빚는 수백 년 된 민속 공예예요. 가장 사랑받는 것은 풍요와 기쁨을 상징하는 통통한 얼굴의 아푸 인형이죠. 손으로 곱게 채색한 이 인형들은 우시의 가장 고전적인 기념품이랍니다.'),
  'wuxi/boat': ('운하 유람선', '세계에서 가장 긴 인공 수로인 대운하가 우시 한복판을 가로질러 흘러요. 저녁이면 등불이 밝혀지는 칭밍교 옛 거리에서 배를 타고 흰 벽과 검은 기와의 옛집들 사이를 미끄러져 가는 것이 이 도시를 만나는 가장 아름다운 방법이에요.'),
  'nanning/tree': ('녹색 도시', '중국 남부 열대 지역에 자리한 난닝은 거리를 그늘로 덮는 거대한 가로수와 일 년 내내 푸른 공원 덕분에 \'녹색 도시\'라고 불려요. 베트남 국경과 가까운 이 도시는 중국과 동남아시아를 잇는 무역과 문화 교류의 관문이랍니다.'),
  'nanning/noodle': ('라오유 미펀', '\'오랜 친구 국수\'라는 뜻의 라오유펀은 절인 죽순과 발효 검은콩, 고추를 넣어 끓이는 새콤하고 매콤한 난닝의 대표 음식이에요. 전해 오는 이야기로는 한 찻집 주인이 병든 옛 친구를 낫게 하려고 처음 끓였다고 해요. 그때부터 습한 날의 보약으로 여겨져 왔답니다.'),
  'nanning/song': ('민요', '광시의 좡족은 수백 년 동안 즉흥으로 주고받는 민요로 마음을 표현하는 전통을 이어 왔어요. 봄마다 열리는 \'삼월삼\' 노래 축제에서는 젊은이들이 노래로 겨루고, 전설의 가수 류싼제는 이 전통에서 가장 사랑받는 주인공이랍니다.'),
  'nanning/mango': ('열대 과일', '열대 기후를 지닌 난닝은 망고, 룽옌, 리치, 파파야가 풍성하게 나는 과일의 낙원이에요. 길거리 좌판은 일 년 내내 신선한 과일로 넘쳐 나죠. 더운 저녁이면 얼음을 넣은 과일 디저트와 갓 짠 주스가 이 도시에서 가장 사랑받는 더위 식히기 방법이에요.'),
  'nanchang/pavilion': ('텅왕거', '간장 강변의 등왕각은 당나라 이후 여러 차례 무너지고 다시 세워진, 중국 강남의 3대 누각 중 하나예요. 젊은 시인 왕발이 이곳에서 지은 \'등왕각서\'는 중국 문학의 걸작이 되어 이 누각을 불멸의 존재로 만들었답니다.'),
  'nanchang/star': ('8·1 난창 봉기', '1927년 8월 1일에 일어난 난창 봉기는 중국 인민해방군의 탄생으로 여겨져요. 그래서 난창은 \'영웅의 도시\'라고 불리죠. 군기에 새겨진 \'8·1\'이라는 숫자가 바로 이 날짜를 가리키며, 도시 중앙 광장의 이름도 여기서 왔어요.'),
  'nanchang/porcelain': ('징더전 도자기', '난창이 속한 장시성에는 세계 도자기의 수도 징더전이 있어요. 천 년 동안 황실 가마에서 궁궐을 위해 구워 낸 이 \'하얀 금\'은 대상 행렬과 배에 실려 이곳에서 온 세계로 퍼져 나갔죠. 이 공예는 오늘날에도 젊은 장인들의 손에서 살아 숨 쉬고 있답니다.'),
  'nanchang/sunset': ('간강 야경', '저녁이 되면 간장 양쪽 강변은 전혀 다른 얼굴로 변해요. 수백 채 건물의 외벽이 하나의 거대한 미디어 조명 쇼로 바뀌거든요. 강변 공원과 불빛에 물든 등왕각의 실루엣은 난창 사람들이 가장 사랑하는 저녁 산책 코스랍니다.'),
  'yinchuan/camel': ('실크로드', '황허가 적셔 주는 오아시스 도시 인촨은 실크로드 대상들이 사막으로 나서기 전에 쉬어 가던 서쪽 관문 중 하나였어요. 도시 밖에는 피라미드를 닮은 서하 왕조의 왕릉들이 지금도 사막의 태양 아래 고요히 서 있답니다.'),
  'yinchuan/grapes': ('허란산 와이너리', '풍부한 햇살과 건조한 공기, 자갈 섞인 토양을 지닌 허란산 동쪽 기슭은 중국 최고의 와인 산지로 꼽혀요. 이곳 포도밭에서 나온 와인들이 국제 대회에서 상을 휩쓸면서, 애호가들은 이 지역을 \'중국의 보르도\'라고 부르기 시작했어요.'),
  'yinchuan/desert': ('사포터우 사막', '인촨 근처 사포터우에서는 텅거리 사막의 황금빛 모래언덕이 황허와 만나요. 사막과 강이 나란히 서 있는 보기 드문 풍경이죠. 모래언덕 꼭대기에서 썰매를 타고 내려오기, 낙타 행렬을 따라 사막으로 들어가기, 양가죽 뗏목으로 강 건너기가 이 지역의 대표 모험이랍니다.'),
  'yinchuan/sheep': ('후이족 양고기 요리', '닝샤 후이족 무슬림 요리의 주인공은 양고기예요. 쿠민을 뿌린 양꼬치, 부드러운 수육, 손으로 뽑은 국수를 넣은 국물 요리가 도시의 식탁을 가득 채우죠. 초원 목장에서 자란 이곳 양고기는 부드럽고 잡내 없는 깔끔한 맛으로 중국 전역에서 유명하답니다.'),
  'lhasa/mountain': ('포탈라 궁', '홍산 언덕 위에 우뚝 솟은 포탈라궁은 수백 개의 방과 신성한 영탑, 예배당을 갖춘 티베트 건축의 걸작이에요. 달라이 라마의 겨울 궁전이었던 이 붉고 하얀 건물은 유네스코 세계문화유산으로, 라싸 어디에서나 거의 다 보인답니다.'),
  'lhasa/prayer': ('조캉 사원', '티베트 불교에서 가장 신성한 사원인 조캉 사원에는 순례자들이 때로는 수 킬로미터 길을 오체투지로 엎드리며 찾아와요. 사원을 둘러싼 바코르 순례길에는 마니차를 돌리며 걷는 순례자들의 행렬이 하루 종일 끊이지 않고, 향 내음이 거리를 가득 채운답니다.'),
  'lhasa/yak': ('야크 문화', '고원의 추위에 강한 야크는 티베트 생활의 든든한 기둥이에요. 젖으로는 버터와 치즈를, 털로는 천막과 옷을 만들고, 배설물은 연료로 쓰이죠. 사원에서 밤낮으로 타오르는 등불의 연료조차 야크 젖으로 만든 버터랍니다.'),
  'lhasa/tea': ('수유차', '야크 버터와 소금, 진하게 우린 찻물을 함께 휘저어 만드는 버터차는 티베트 사람들의 일상 음료예요. 고산지대의 건조한 추위 속에서 몸을 데우고 영양까지 채워 주죠. 손님의 찻잔이 빌 때마다 계속 채워 주는 것이 티베트 환대의 가장 다정한 규칙이랍니다.'),
  'zhuhai/shell': ('주하이 어녀상', '바다 위 바위에 서서 진주를 하늘로 들어 올리는 어부 소녀상은 주하이의 상징이에요. 어부를 사랑해 인간의 모습으로 변한 선녀의 전설에서 태어난 이 조각상은 우아한 자태로 해안 도로를 걷는 사람들을 맞이한답니다.'),
  'zhuhai/bridge': ('강주아오 대교', '강주아오대교(홍콩-주하이-마카오 대교)는 총길이 55킬로미터로 세계에서 가장 긴 해상 교량이에요. 다리와 인공섬, 해저터널이 하나로 이어져 있죠. 주장 삼각주의 세 도시를 한 줄로 연결하는 이 거대한 구조물은 현대 공학의 상징적인 프로젝트로 꼽혀요.'),
  'zhuhai/island': ('백도', '주하이라는 이름은 \'진주의 바다\'라는 뜻으로, 해안에는 백 개가 넘는 섬이 흩어져 있어요. 페리로 갈 수 있는 둥아오섬과 와이링딩섬 같은 곳에는 어촌 마을과 조용한 포구, 해산물 식당이 여행자를 기다리죠. 섬마다 저마다의 리듬으로 살아간답니다.'),
  'zhuhai/lobster': ('해산물 요리', '주장이 바다와 만나는 주하이에서는 그날 잡은 해산물로 식탁을 차려요. 바닷가재, 갯가재, 가리비, 굴을 수조에서 산 채로 골라 바로 요리해 주죠. 광둥식으로 살짝 쪄 내는 조리법이 재료의 신선함과 자연스러운 단맛을 한껏 살려 준답니다.'),
  'yantai/apple': ('옌타이 사과', '옌타이의 서늘한 해양성 기후와 풍부한 햇살은 중국에서 가장 유명한 사과를 길러 내요. 빨갛고 아삭하며 꿀 향이 나는 이 사과는 전국 방방곡곡으로 보내지죠. 가을이면 해안을 따라 늘어선 과수원이 수확으로 분주해지고 도시 전체가 사과 향으로 가득 찬답니다.'),
  'yantai/wine': ('창위 와인', '중국 최초의 근대식 와이너리인 장위는 1892년 옌타이에서 문을 열었고, 지금도 중국에서 가장 유서 깊은 와인 브랜드예요. 와인 문화 박물관과 역사 깊은 지하 저장고, 근교의 포도밭 코스 덕분에 옌타이는 아시아에서 손꼽히는 \'와인의 도시\'로 불린답니다.'),
  'yantai/wave': ('펑라이 해안', '옌타이의 펑라이 해안은 중국 신화에서 여덟 신선(팔선)이 바다를 건너 떠난 곳으로 전해져요. 바다 위에 이따금 나타나는 신기루 덕분에 이 해안은 \'신선들의 땅\'이라는 명성을 얻었고, 절벽 위의 유서 깊은 펑라이 누각이 바다를 내려다보고 있답니다.'),
  'yantai/cherry': ('체리 농장', '옌타이는 중국에서 손꼽히는 체리 산지예요. 서늘한 해안 기후가 알이 굵고 과즙 많고 달콤한 체리를 기르기에 안성맞춤이거든요. 초여름이면 과수원이 방문객에게 열리는데, 가지에서 바로 따 먹는 체리는 이 계절의 가장 달콤한 나들이랍니다.'),
  'datong/buddha': ('윈강 석굴', '다퉁 서쪽 절벽에 새겨진 윈강 석굴은 북위 시대에 조성된 수천 구의 불상을 간직한, 중국 불교 예술의 정점 중 하나예요. 손바닥만 한 불상이 있는가 하면 건물만큼 높이 솟은 불상도 있죠. 이 석굴은 유네스코 세계문화유산으로 등재되어 있답니다.'),
  'datong/citywall': ('다퉁 성벽', '옛 변경 요새 도시였던 다퉁은 웅장한 성문과 모서리 망루를 갖춘 명나라 시대 성벽을 다시 일으켜 세웠어요. 저녁 등불이 밝혀진 성벽 위를 걷는 것은 옛 시가지의 지붕들과 새로운 다퉁의 불빛을 한 장면에 담아 보는 가장 근사한 방법이랍니다.'),
  'datong/noodle': ('다오샤오몐', '산시성의 자랑인 도삭면(다오샤오몐)은 장인이 반죽 덩어리를 팔에 받쳐 들고 칼로 깎아 낸 면발을 곧장 끓는 솥으로 날려 보내는 국수예요. 가장자리는 도톰하고 가운데는 얇은 이 면은 소스를 완벽하게 머금죠. 다퉁 식탁에서 빼놓을 수 없는 고전이랍니다.'),
  'datong/lantern': ('현공사', '다퉁 근처 헝산 절벽에 박아 세운 현공사는 가느다란 나무 기둥에 의지해 허공에 매달린 듯 서 있어요. 약 1,500년 된 이 사원은 불교, 도교, 유교를 한 지붕 아래 모셨다는 점에서도 세상에 둘도 없는 곳이랍니다.'),
  'baotou/horse': ('초원 말', '바오터우라는 이름은 몽골어로 \'사슴이 있는 곳\'이라는 뜻이고, 도시는 네이멍구 초원의 가장자리에 자리 잡고 있어요. 주변 초원에서는 말이 여전히 일상의 일부예요. 몽골족 목민들은 경마를 열고, 마두금(모린 호르)의 선율이 게르 안에 울려 퍼져요.'),
  'baotou/deer': ('사슴 공원', '바오터우는 \'사슴의 도시\'라는 별명으로 불리고, 공원을 자유롭게 거니는 사슴들이 그 이름을 지켜 주고 있어요. 방문객이 직접 손으로 먹이를 줄 수도 있어요. 초원 한가운데 펼쳐지는 이 정겨운 풍경은 공업 도시의 뜻밖에 부드러운 얼굴을 보여 줘요.'),
  'baotou/factory': ('철강 도시', '바오터우에는 중국 최대급 철강 기업이 자리해 있어서, 나라의 중공업 지도에서 특별한 위치를 차지해요. 가까이에 있는 광상 덕분에 이 도시는 세계에서 가장 중요한 희토류 중심지 중 하나로도 알려져 있어요.'),
  'baotou/grass': ('초원 여행', '도시에서 조금만 나가면 지평선까지 이어지는 초원이 펼쳐져요. 손님들은 게르에서 묵으며 밀크티와 구운 양고기로 환영받고, 저녁이면 모닥불 곁에서 몽골 노래가 울려 퍼져요. 이곳의 초원 손님맞이는 수백 년을 이어 온 전통이에요.'),
  'weifang/kite': ('연의 도시', '연의 고향으로 여겨지는 웨이팡에서는 대나무 뼈대에 손으로 그림을 그린 비단을 씌우는 연 공예가 수백 년째 이어지고 있어요. 매년 4월에 열리는 웨이팡 국제 연 축제에서는 세계 각지에서 온 연들이 하늘을 알록달록한 축제의 장으로 바꿔 놓는답니다.'),
  'weifang/woodprint': ('양자부 목판화', '웨이팡의 양자푸 마을은 중국 설날에 대문에 붙이는 알록달록한 목판화의 가장 유명한 본고장 중 하나예요. 문신(門神)과 통통한 아기, 풍요의 상징들을 손으로 새긴 목판으로 색을 겹겹이 찍어 내죠. 이 공예는 대대로 전해 내려오고 있답니다.'),
  'weifang/dragon': ('용 연', '웨이팡 하늘의 스타는 용 머리를 단 거대한 지네연이에요. 수십 개의 대나무 고리를 비단 몸통으로 이어 붙여, 바람에 물결치는 연이 수 미터씩 길게 뻗어 나가죠. 이런 거인을 하늘에 띄우려면 여러 사람이 한 팀이 되어 기술과 힘을 모아야 한답니다.'),
  'weifang/radish': ('웨이팡 무', '웨이팡의 초록 무는 어찌나 달고 아삭한지 현지 사람들은 과일처럼 껍질을 깎아 썰어 먹어요. \'웨이팡 무가 배보다 낫다\'는 속담에는 이 소박한 채소에 대한 자부심이 담겨 있죠. 차를 마시며 손님에게 무를 대접하는 것이 이 도시의 정겨운 예절이랍니다.'),
  'dezhou/chicken': ('더저우 닭고기', '더저우의 향신료 조림 닭은 뼈에서 살이 저절로 떨어질 만큼 부드럽게 익혀 내요. 대운하와 철도가 지나는 교통 요지라는 입지 덕분에 그 명성이 전국으로 퍼졌죠. 꿀을 발라 튀긴 뒤 향신료 국물에 오래도록 뭉근히 익히는 이 닭 요리는 한때 황실 식탁에도 올랐답니다.'),
  'dezhou/sun': ('솔라 밸리', '태양광 산업에 일찍 투자한 더저우는 \'태양의 도시\'라는 별명을 갖고 있어요. 거대한 솔라밸리 단지에서는 호텔과 가로등, 집들이 모두 태양의 힘으로 움직이죠. 이 도시는 중국에서 재생에너지를 가장 생생하게 보여 주는 진열장 중 하나랍니다.'),
  'dezhou/grapes': ('멜론과 포도', '황허 평야의 비옥한 토양은 더저우를 여름 과일의 고장으로 만들어 줘요. 밭에는 수박이 가득하고 시렁에는 포도송이가 주렁주렁 매달리죠. 길가 좌판에서 사 먹는 얼음처럼 차가운 수박 한 조각은 무더운 여름날의 가장 고전적인 쉼표랍니다.'),
  'dezhou/train': ('운하 항구', '대운하가 번성하던 시절, 더저우는 곡식을 싣고 북쪽으로 가는 바지선들이 들르는 분주한 항구였어요. 오늘날에는 철도가 운하의 역할을 이어받았죠. 베이징-상하이 노선 위에 자리한 이 도시는 지금도 중국 북부의 중요한 관문으로 남아 있답니다.'),
  'xuzhou/stone': ('한나라 화상석', '한나라를 세운 유방의 고향 쉬저우는 돌에 새겨진 역사 기록 보관소 같은 도시예요. 무덤 벽을 장식하던 한나라 화상석에는 연회와 전차, 신화 속 짐승들이 새겨져 있죠. 2천 년 전의 일상이 마치 오래된 만화처럼 눈앞에 펼쳐진답니다.'),
  'xuzhou/terracotta': ('테라코타 병마용', '시안의 유명한 병마용보다 규모는 작지만, 이곳에서는 초나라 왕의 무덤을 지키던 한나라 시대 도용 병사들이 발견됐어요. 무릎 높이의 작은 병사들이 가지런히 줄지어 서 있죠. 아담한 크기에도 그 엄숙한 질서는 죽음 이후에도 계속 복무하는 군대의 모습을 보여 줘요.'),
  'xuzhou/lake': ('윈룽 호수', '\'구름 용\'이라는 뜻의 이름을 가진 윈룽호는 언덕으로 둘러싸인 넓은 물의 거울로, 도시의 푸른 허파라고 불려요. 호숫가 산책로와 찻집, 사원이 자리한 언덕 덕분에 쉬저우 사람들은 아침 운동부터 저녁 산책까지 하루 종일 이곳으로 모여든답니다.'),
  'xuzhou/skewer': ('꼬치구이 문화', '쉬저우는 스스로 중국의 바비큐 수도라고 자랑스럽게 말해요. 숯불 위에서 익어 가는 양꼬치 연기가 밤늦도록 거리에 퍼지죠. 작은 화로가 식탁까지 올라와 각자 자기 꼬치를 직접 구워 먹는, 친구들과 밤늦게까지 이어지는 시끌벅적하고 즐거운 식문화랍니다.'),
  'zhenjiang/vinegar': ('전장 흑식초', '전장의 흑미 식초는 찹쌀을 오래도록 정성껏 발효시켜 만들어요. 부드러운 산미와 은은한 단맛으로 중국 요리에서 가장 유명한 식초로 꼽히죠. 만두 상에 빠질 수 없는 단짝이라, 현지 사람들 말처럼 전장 거리에는 식초 향이 떠다닌답니다.'),
  'zhenjiang/temple': ('진산사', '양쯔강 기슭의 진산사는 중국에서 가장 사랑받는 민담인 백사전 전설의 가장 극적인 장면이 펼쳐진 곳이에요. 뱀의 정령 백소정이 사랑을 위해 이 절을 물바다로 만들었다는 이야기가 바로 여기서 벌어지죠. 언덕 꼭대기의 탑은 강과 도시를 한눈에 내려다본답니다.'),
  'zhenjiang/pot': ('솥뚜껑 국수', '전장의 궈가이몐은 펄펄 끓는 큰 솥 안에 작은 나무 뚜껑을 띄워 놓고 끓이는 국수예요. 물 위에 떠 있는 뚜껑이 넘침을 막고 면을 알맞게 익혀 주죠. 가는 면발에 현지 식초와 간장 육수가 어우러지는데, 이것이 이 도시에서 하루를 시작하는 고전적인 방법이랍니다.'),
  'zhenjiang/bridge': ('양쯔강 강변', '전장은 양쯔강과 대운하가 만나는 전략적 요충지에 세워진 오래된 항구 도시예요. 강을 바라보는 진산, 베이구산, 자오산 세 언덕이 탑과 사원, 산책 공원으로 강변을 수놓아 물가를 초록빛 문화의 띠로 만들어 준답니다.'),
  'jiaxing/zongzi': ('쭝쯔', '자싱은 대나무 잎에 싸서 찐 찹쌀 음식 쭝쯔의 수도예요. 돤우제(용선 축제)의 상징 음식인 쭝쯔가 이곳에서는 돼지고기, 팥소, 짭짤한 달걀노른자 등 다양한 속을 채워 일 년 내내 팔리죠. 따끈한 쭝쯔를 풀어 보는 건 댓잎 향으로 시작되는 작은 의식이랍니다.'),
  'jiaxing/boat': ('난후 유람선', '1921년 상하이를 떠나야 했던 중국 공산당 제1차 대회는 자싱 난후의 배 위에서 마무리됐어요. \'붉은 배\'라 불리는 그 배의 복제품이 지금도 호수에 떠 있죠. 안개 낀 물과 버드나무, 섬 위의 정자들이 이곳 방문에 고요한 역사의 분위기를 더해 줘요.'),
  'jiaxing/silk': ('비단의 고장', '장난 지방의 뽕나무밭과 누에치기 문화는 수백 년 동안 자싱의 운하 마을들을 먹여 살렸어요. 고치에서 뽑은 실은 이곳에서 이불과 옷감, 자수로 다시 태어나죠. 비단의 부드러움은 물 많고 온화한 이 지역 기후가 밭에서 옷장까지 전해 주는 선물이에요.'),
  'jiaxing/canal': ('우전 수향마을', '자싱 근교의 우전은 돌다리와 검은 기와집, 운하로 내려가는 계단이 어우러진 장난 수향 마을 가운데서도 가장 우아한 곳으로 꼽혀요. 해 질 녘 등불이 켜지면 물이 붉게 물들죠. 쪽 염색과 그림자 인형극 같은 옛 공예도 좁은 골목에서 여전히 살아 있답니다.'),
  'lishui/mountains': ('뤼수이 산맥', '리수이는 저장성에서 가장 산이 많은 고장이에요. 골짜기는 안개로, 능선은 대나무와 소나무 숲으로 가득하죠. 산비탈에 자리 잡은 돌집 마을과 구름에 닿을 듯한 계단식 논이, 해안 지방의 번잡함에서 멀리 떨어진 느리고 푸른 중국을 간직하고 있어요.'),
  'lishui/camera': ('사진 촬영 명소', '새벽안개가 가득 찬 골짜기, 계단식 논에 하나둘 나타나는 농부들, 빛에 따라 변하는 구름바다가 리수이를 사진가들의 성지로 만들었어요. 이 도시는 국제 사진 행사로도 유명하죠. 가장 유명한 장면은 해돋이에 물을 가득 채운 계단식 논이 황금빛으로 반짝이는 순간이에요.'),
  'lishui/mushroom': ('버섯의 고장', '리수이의 칭위안현은 버섯 재배의 요람으로 여겨져요. 통나무에 표고버섯을 키우는 방법이 수백 년 전 바로 이 산속에서 개발됐거든요. 지금도 마을 시장에는 말린 버섯 향이 가득하고, 갓 딴 버섯으로 끓인 국과 찜 요리는 이 고장 부엌의 자랑이랍니다.'),
  'lishui/raft': ('대나무 뗏목 체험', '어우강은 리수이의 푸른 골짜기 사이를 굽이굽이 흘러요. 맑은 물 위를 대나무 뗏목으로 미끄러져 내려가는 것이 이 지역의 대표적인 즐거움이죠. 사공이 긴 장대로 방향을 잡는 동안 어촌 마을과 안개 낀 산, 수묵화에서 튀어나온 듯한 풍경이 강가를 따라 스쳐 지나가요.'),
  'anqing/opera': ('황메이시', '황매희는 안칭 시골의 찻잎 따기 노래에서 태어나 중국에서 가장 사랑받는 지방 전통극 중 하나로 성장했어요. 소박하고 흐르는 듯한 선율과 일상의 말로 풀어내는 사랑 이야기는 대대로 사람들 입에서 입으로 외워져 왔죠. 안칭은 지금도 이 예술의 수도로 꼽힌답니다.'),
  'anqing/pagoda': ('전펑탑', '양쯔강 기슭에 우뚝 선 전펑탑은 수백 년 동안 뱃사람들의 등대 역할을 하며 \'양쯔강 제일탑\'이라는 이름을 얻었어요. 명나라 때 지어진 이 팔각탑은 층계를 오르는 방문객에게 크게 굽이치는 강의 장쾌한 전망을 선물한답니다.'),
  'anqing/tea': ('웨시 차', '안칭 뒤편에 솟은 다볘산의 안개 자욱하고 서늘한 산비탈은 향긋한 녹차를 기르기에 더없이 좋은 정원이에요. 웨시현에서 봄에 손으로 딴 여린 찻잎은 가볍고 꽃향기 도는 차로 우러나죠. 산골 마을에서는 지금도 찻잎 수확이 계절의 가장 큰 행사랍니다.'),
  'anqing/sail': ('안칭 항구', '\'평안한 경사\'라는 뜻의 이름을 지닌 안칭은 안후이성이 양쯔강으로 나가는 유서 깊은 항구 관문이에요. 안후이라는 성 이름의 \'안\'이 바로 이 도시에서 왔죠. 강변 부두와 옛 골목들은 지금도 항구가 북적이던 시절의 흔적을 간직하고 있답니다.'),
  'ganzhou/orange': ('간난 네이블 오렌지', '간저우의 붉은 흙과 온화한 남쪽 기후는 중국에서 가장 달다고 손꼽히는 간난 네이블 오렌지를 키워 내요. 수확철이 되면 언덕이 온통 주황빛으로 물들죠. 즙 많고 씨 없는 이 과일은 도시의 이름을 전국에 알리는 자랑거리랍니다.'),
  'ganzhou/house': ('객가 토루', '북쪽에서 이주해 온 하카족은 간저우의 산골 마을에 요새 같은 집들을 지었어요. 두꺼운 방어벽 안에서 수십 가구가 한 지붕 아래 함께 살았죠. 안에는 공동 마당과 조상을 모시는 사당, 그리고 수백 년 동안 이어져 온 끈끈한 공동체 문화가 살아 있어요.'),
  'ganzhou/pavilion': ('위구정', '위구타이 누각은 장강과 궁강, 두 물줄기가 만나 간강이 태어나는 합류점을 내려다보고 있어요. 송나라 시인들의 시에 노래된 이 목조 누각에서는 강 풍경과 천 년의 시가 전통이 하나로 어우러지죠. 해 질 무렵이면 이곳이 도시에서 가장 애수 어린 장소가 된답니다.'),
  'ganzhou/star': ('대장정', '1934년 홍군은 역사에 대장정으로 기록된 대규모 철수를 간저우의 위두현에서 시작했어요. 밤새 강을 건넌 병사들의 이야기가 이곳의 기념비와 박물관에 새겨져 있죠. 간저우는 중국 현대사의 전환점 하나가 시작된 출발선인 셈이에요.'),
  'putian/shrine': ('마조묘', '뱃사람들의 수호신 마조 여신은 푸톈에서 태어났어요. 여신을 모시는 본산 사원이 메이저우섬에 우뚝 서 있는데, 전 세계 수천 개 마조 사원의 뿌리로 여겨지죠. 마조 신앙과 풍습은 유네스코 인류무형문화유산에 올라 있고, 축제날이면 섬이 향 연기와 순례자들로 가득 찬답니다.'),
  'putian/lychee': ('리치 과수원', '푸톈은 \'리치의 도시\'라고도 불려요. 수백 년 된 리치 나무들이 지금도 열매를 맺으며 거리에 그늘을 드리우죠. 여름 수확철에 껍질이 붉게 물드는 이 달콤한 과일은 옛 시에서도 칭송된 남방의 사치품이었고, 갓 딴 리치를 맛보는 건 푸톈 여름 최고의 즐거움 중 하나예요.'),
  'putian/shoe': ('신발의 도시', '푸톈은 세계 운동화 생산의 조용한 거인 중 하나예요. 이곳의 공방과 공장들이 유명 브랜드를 위해 수백만 켤레를 만들어 내죠. 신발 만들기는 여기서 가업처럼 이어지는데, 금형 장인부터 재봉사까지 이어지는 거대한 장인의 사슬이 세계 스포츠 패션의 보이지 않는 주방 역할을 해요.'),
  'putian/wave': ('메이저우섬', '페리를 타고 들어가는 메이저우섬은 황금빛 모래사장과 바위 해안, 마조 사원 축제로 유명해요. 여신의 탄신일이 되면 섬은 북소리와 행렬로 활기가 넘치죠. 평소에는 바닷바람이 부는 조용한 순례지이자 휴양지랍니다.'),
  'mudanjiang/snow': ('중국 설향', '무단장 근처의 \'중국 눈 마을\' 쉐샹은 중국에서 눈이 가장 많이 내리는 마을 중 하나예요. 지붕마다 두툼한 눈베개가 소복이 쌓여 집들을 동화 속 오두막으로 바꿔 놓죠. 해질녘 붉은 등불이 켜지면 눈 덮인 골목이 따스한 빛으로 반짝인답니다.'),
  'mudanjiang/lake': ('징포호', '징보호는 아주 오래전 화산 폭발로 흘러내린 용암이 강물을 막아 생긴, 중국에서 가장 큰 화산 언색호 중 하나예요. 호수의 물은 댜오수이러우 폭포로 쏟아져 내리는데, 여름철 용감한 다이버들의 폭포 다이빙과 꽁꽁 얼어붙은 겨울 풍경이 이 지역의 명물이랍니다.'),
  'mudanjiang/tiger': ('시베리아 호랑이 공원', '무단장 지역의 헝다오허쯔는 세계에서 가장 큰 고양잇과 동물인 시베리아호랑이를 보호하고 번식시키는 세계 최고 수준의 센터 중 하나예요. 넓은 숲속을 누비는 호랑이들을 보호 통로에서 관찰할 수 있죠. 이 센터는 희귀종의 미래를 지키려는 노력의 심장부랍니다.'),
  'mudanjiang/ski': ('스키 시즌', '중국의 눈 벨트에 자리한 무단장은 겨울이 길고 건조한 눈이 풍성하게 내려요. 도시를 둘러싼 숲 덮인 언덕들은 시즌마다 스키어들로 가득 차죠. 눈 마을 여행과 이어지는 스키 코스 덕분에 이 지역은 중국 동북부 겨울 관광의 중심지가 되었답니다.'),
  'changzhou/dino': ('공룡원', '창저우 공룡공원은 화석 박물관과 놀이공원을 하나로 합친 중국에서 가장 유명한 공룡 테마파크로, \'중국의 쥬라기 공원\'이라는 애칭으로 불려요. 거대한 공룡 모형과 워터 어트랙션, 롤러코스터까지 갖춰 가족 여행객에게 이 도시 최고의 명소랍니다.'),
  'changzhou/pagoda': ('톈닝사 탑', '도심에 있는 톈닝사의 153미터 탑은 세계에서 가장 높은 탑(파고다)으로 꼽혀요. 천 년이 넘는 역사를 지닌 사찰 마당에서 솟아오른 이 탑의 꼭대기 층에 오르면 창저우 전체와 굽이치는 대운하가 발아래 펼쳐진답니다.'),
  'changzhou/comb': ('빗 공예', '창저우 빗은 회양목이나 흑단 같은 귀한 나무를 수십 단계의 수작업으로 다듬어 만드는, 수백 년 역사의 공예품이에요. 한때 황실에 진상되던 이 빗은 섬세한 조각과 손으로 그린 그림 덕분에 지금도 이 도시에서 가장 우아한 기념품으로 사랑받는답니다.'),
  'changzhou/canal': ('대운하', '대운하는 수백 년 동안 창저우 한가운데를 흘러왔고, 도시는 이 물길이 실어 온 무역과 직조업으로 부유해졌어요. 저녁이면 운하 기슭의 옛 동네가 등불로 물들죠. 돌로 쌓은 부두를 따라 걷는 산책이 이 도시의 가장 고전적인 즐거움이랍니다.'),
  'shaoxing/wine': ('사오싱주', '호박빛이 도는 사오싱의 황주(찹쌀술)는 이 고장 젠후 호수의 물로 빚어요. 술로 마시기도 하고 중국 요리에 빠질 수 없는 조미료로도 쓰이죠. 딸이 태어나면 술 단지를 땅에 묻었다가 혼례 날 열어 마시던 풍습은 이 도시의 가장 아름다운 전통 중 하나랍니다.'),
  'shaoxing/bridge': ('석교', '운하로 촘촘히 엮인 사오싱에서는 물길이 거리만큼이나 분주해요. 수백 개의 아치형 돌다리 덕분에 이 도시는 \'다리의 박물관\'이라고 불리죠. 어떤 다리는 수백 년째 그 자리를 지키며, 이끼 낀 돌 아치가 지금도 그 아래를 미끄러져 가는 배들에게 그늘을 드리운답니다.'),
  'shaoxing/pen': ('서예의 성지', '서예 최고의 대가로 추앙받는 왕희지는 사오싱의 대나무 숲 모임에서 걸작 \'난정서\'를 썼어요. 시냇물에 술잔을 띄우고 시를 읊던 풍류가 그날부터 전해 내려오죠. 난정은 오늘날에도 붓글씨를 사랑하는 이들의 성지로 남아 있답니다.'),
  'shaoxing/boat': ('우펑선', '검은 차양을 씌운 사오싱의 우펑선에서는 사공이 발로 노를 젓고 손으로 방향을 잡아요. 대대로 이어져 온 세상에 둘도 없는 기술이죠. 좁은 운하의 돌다리 밑을 미끄러져 가는 이 배들은 이 도시가 길러 낸 작가 루쉰의 어린 시절 추억 속에서도 첫 자리를 차지한답니다.'),
  'bengbu/shell': ('진주의 항구', '벙부라는 이름은 \'조개 부두\'라는 뜻이에요. 화이허의 이 강변은 한때 민물 진주를 캐는 사람들로 유명했거든요. 진주는 오늘날에도 이 도시의 상징으로, 광장의 조각상부터 시의 문장까지 어디서나 만날 수 있답니다.'),
  'bengbu/train': ('철도 교통의 요충지', '벙부는 톈진-푸커우 철도가 화이허를 건너는 지점에서 작은 마을에서 큰 도시로 성장했어요. 남북 간선 철도의 이 관문은 오늘날에도 안후이 북부를 중국의 주요 교통망에 이어 주는 역할을 하고 있답니다.'),
  'bengbu/river': ('화이허 강', '화이허는 중국을 북과 남으로 나누는 자연의 경계선으로 여겨져요. 이 선의 북쪽에서는 밀을, 남쪽에서는 벼를 심고, 겨울철 중앙난방도 북쪽에만 들어오죠. 벙부는 바로 이 전환선 위에서 두 기후와 두 요리 문화의 한가운데 살고 있답니다.'),
  'bengbu/blossom': ('봄꽃 축제', '봄이 오면 화이허 강변 공원들이 꽃으로 활짝 피어나고, 벙부 사람들은 주말이면 강가에서 소풍과 꽃놀이를 즐겨요. 호숫가의 장궁산 공원은 벚꽃과 복숭아꽃이 피는 철이면 도시에서 가장 붐비는 만남의 장소가 된답니다.'),
  'jiujiang/mountain': ('루산', '양쯔강과 포양호 사이에 솟은 루산은 안개에 감싸인 봉우리와 폭포, 서늘한 고원을 지닌 중국에서 가장 시적인 산으로, 유네스코 세계문화유산에 등재되어 있어요. 이백이 폭포를 노래한 시구부터 산비탈 구링 마을의 돌 별장까지, 구석구석이 저마다의 이야기를 들려준답니다.'),
  'jiujiang/tea': ('윈우차', '루산의 구름 덮인 산비탈에서 자라는 윈우차(\'구름안개차\')는 중국의 이름난 녹차 중 하나예요. 산의 촉촉한 습기와 안개를 거쳐 온 햇살이 찻잎에 신선하고 달콤한 향을 불어넣죠. 봄의 첫 새순은 손으로 따며 가장 귀한 수확으로 여겨진답니다.'),
  'jiujiang/lake': ('포양호', '중국에서 가장 큰 담수호인 포양호는 주장 바로 옆에서 양쯔강과 이어져요. 호수의 물은 계절 따라 불어나고 줄어드는데, 겨울에 드러나는 촉촉한 초원은 희귀한 시베리아흰두루미를 비롯한 수만 마리의 철새를 맞이한답니다.'),
  'jiujiang/scroll': ('시의 도시', '양쯔강 기슭의 이 오래된 항구는 중국 시문학의 거장들을 맞이했어요. 백거이는 강 위에서 들려온 선율에 영감을 받아 명작 \'비파행\'을 바로 이곳에서 썼죠. 루산의 그림자 아래 자리한 주장은 시 속에 가장 자주 등장하는 강의 관문 중 하나랍니다.'),
  'quanzhou/ship': ('해상 실크로드', '중세에 \'자이툰\'이라는 이름으로 알려졌던 취안저우는 해상 실크로드 최대의 항구였어요. 마르코 폴로는 이곳을 세계에서 가장 붐비는 항구 중 하나라고 기록했죠. 모스크와 사원, 교회가 나란히 서 있는 이 도시는 그 국제적인 유산 덕분에 유네스코 세계문화유산에 등재되었답니다.'),
  'quanzhou/mosque': ('칭징사', '1009년 아랍 상인들이 세운 칭징사(청정사)는 중국에 남아 있는 가장 오래된 모스크 중 하나예요. 중동 건축에서 영감을 받은 화강암 정문과 돌담은 해상 실크로드 시대의 취안저우가 얼마나 다양한 종교가 어우러진 국제 항구였는지를 보여 준답니다.'),
  'quanzhou/puppet': ('꼭두각시 인형극', '취안저우의 줄인형극에서는 명인들이 수십 가닥의 가는 줄을 동시에 다루며 나무 인형에 그야말로 생명을 불어넣어요. 인형이 붓글씨를 쓰고 칼을 차고 결투까지 벌이죠. 천 년을 이어 온 이 전통은 지금도 사원 축제와 명절 무대의 주인공이랍니다.'),
  'quanzhou/tea': ('철관음', '취안저우의 산악 지역인 안시현은 세계에서 가장 유명한 우롱차인 철관음(톄관인)의 고향이에요. 반쯤 발효된 찻잎은 난초를 닮은 향과 함께 피어나죠. 작은 잔에 우려 마시는 궁푸차 다도는 이곳에서 그저 일상 그 자체랍니다.'),
  'shanghai/pearl': ('동방명주', '푸둥 루자쭈이에 솟아 있는 분홍색 구슬 모양의 타워는 현대 상하이에서 가장 잘 알려진 실루엣이에요. 유리 바닥 전망대에 서면 황푸강과 건너편 와이탄이 발아래 펼쳐지고, 밤이면 형형색색 불빛이 강물 위에 아른거려요.'),
  'shanghai/bund': ('와이탄', '황푸강 변을 따라 늘어선 역사적인 은행과 호텔 건물들은 상하이가 세계적인 항구였던 시절의 위엄을 간직하고 있어요. 저녁 산책길에는 한쪽에서 돌기둥의 옛 상관 건물이, 다른 쪽에서 푸둥의 마천루가 빛나요. 두 세기가 한눈에 만나는 곳이에요.'),
  'shanghai/garden': ('예원', '명나라 때 만들어진 이 고전 정원은 가산과 연못, 지그재그 다리가 어우러진 도심 한복판의 오아시스예요. 정원을 둘러싼 시장 거리는 찻집과 간식 노점으로 북적이고, 용머리 장식 담장 뒤에는 강남(장난) 정원 예술의 섬세함이 숨어 있어요.'),
  'shanghai/xlb': ('샤오룽바오', '얇은 피 안에 뜨거운 육즙을 가둔 샤오룽바오는 상하이 요리의 걸작이에요. 먼저 가장자리를 살짝 베어 물어 국물을 마신 뒤, 생강을 곁들인 흑식초에 찍어 먹어요. 아침이면 대나무 찜통의 김이 도시 골목을 뿌옇게 채워요.'),
  'hangzhou/lake': ('시후', '버드나무와 작은 섬, 아치형 다리가 어우러진 시후(서호)는 중국 시에서 가장 많이 찬미된 풍경이자 유네스코 세계유산이에요. 쑤디와 바이디 둑길을 거니는 일은 수백 년 된 풍습이고, 돤차오(단교)는 백사전 전설 속 연인들이 만난 곳으로 전해져요.'),
  'hangzhou/tea': ('롱징차', '호수 주변 산비탈에서 자라는 \'용의 우물\' 룽징(용정) 녹차는 중국에서 가장 유명한 차예요. 납작한 찻잎은 지금도 뜨거운 솥에서 손으로 덖어 모양을 내고, 이른 봄 첫물차를 최고로 쳐요. 마을 찻집에서 마시는 룽징 한 잔에는 항저우의 정신이 그대로 담겨 있어요.'),
  'hangzhou/temple': ('링인사', '\'영혼이 쉬어 가는 곳\'이라는 뜻의 링인사는 중국에서 가장 오래된 불교 사찰 중 하나예요. 맞은편 페이라이펑(비래봉) 바위에는 수백 년에 걸쳐 수많은 불상이 새겨졌어요. 향 연기와 소나무 그늘 사이를 걷다 보면 도시의 소음을 잊게 돼요.'),
  'hangzhou/silk': ('실크 시티', '항저우 비단은 천 년 넘게 짜여 왔고, 이 도시는 실크로드 동쪽 끝의 부를 상징했어요. 오늘날 비단 시장에서는 옷감과 스카프, 자수가 오가고, 실크 박물관은 누에고치에서 베틀까지의 여정을 보여 줘요. 부드러운 감촉의 항저우 비단은 지금도 가장 우아한 선물이에요.'),
  'chongqing/hongya': ('훙야둥', '절벽에 매달리듯 지어진 전통 고상 가옥 단지 훙야둥은 산악 도시의 옛 건축을 살아 있게 해요. 층층이 쌓인 건물이 밤에 불을 밝히면 자링강 위에 동화처럼 빛나고, 좁은 골목마다 현지 간식과 수공예품 가게가 가득해요.'),
  'chongqing/hotpot': ('충칭 훠궈', '새빨간 매운 기름과 혀를 얼얼하게 하는 쓰촨 산초가 끓어오르는 훠궈는 충칭의 불타는 영혼이에요. 전해지는 이야기로는 강가 부두에서 일하던 짐꾼들의 솥에서 시작되었다고 해요. 식탁 한가운데 아홉 칸 냄비에 담그는 한 점 한 점이 친구들과 나누는 긴 대화가 돼요.'),
  'chongqing/monorail': ('충칭 모노레일', '언덕 위에 세워진 충칭에서는 경전철이 계곡을 훌쩍 건너다니고, 한 역에서는 열차가 아파트 건물 한가운데를 그대로 통과해요. 이 장면은 도시의 상징적인 볼거리가 되었어요. 비탈길과 엘리베이터, 다리로 가득한 \'산의 도시\'는 지도의 평면 논리에 도전해요.'),
  'chongqing/river': ('양쯔강 싼샤', '이 도시는 양쯔강과 자링강이 만나는 지점에 솟아 있고, 차오톈먼 부두에서는 싼샤(삼협) 유람선이 출발해요. 배가 깎아지른 절벽 사이를 미끄러져 갈 때, 중국 최대의 강이 실어 온 수천 년의 교역과 시의 역사가 눈앞을 흘러가요.'),
  'dalian/square': ('싱하이 광장', '바다를 향해 열린 싱하이 광장은 세계에서 가장 큰 도시 광장 중 하나로, \'별의 바다\'라는 이름을 갖고 있어요. 넓은 잔디밭 위로 연이 날아오르고, 저녁이면 해안 길을 따라 자전거가 미끄러지듯 지나가요. 축제 때는 광장이 콘서트와 공연으로 넘쳐 나요.'),
  'dalian/beach': ('다롄 해변', '바위 해안과 깨끗한 해변, 서늘한 여름 덕분에 다롄은 중국 북부에서 가장 사랑받는 바닷가 휴양지예요. 해안을 따라 굽이도는 빈하이루는 절벽과 만 사이로 숨 막히는 경치를 선사해요. 더위에 지친 북방 사람들은 여름이면 이 바다에서 숨을 돌려요.'),
  'dalian/football': ('축구 도시', '다롄은 중국 \'축구의 요람\'으로 불려요. 전국 리그를 주름잡은 챔피언 클럽들과 수많은 국가대표 선수가 이 도시에서 나왔어요. 해변 공원에서 공을 쫓는 아이들이 그 전통을 이어 가고, 경기가 열리는 날이면 도시 전체가 하나의 응원석이 돼요.'),
  'dalian/seafood': ('해산물 요리', '차갑고 맑은 황해는 다롄의 식탁에 가리비, 새우, 성게, 해삼을 올려 줘요. 해안가 식당에서는 수조에서 직접 고른 해산물이 몇 분 만에 쪄져 나와요. 구운 오징어 냄새는 야시장에서 빼놓을 수 없는 매력이에요.'),
  'shenyang/palace': ('선양 고궁', '청나라를 세운 이들이 지은 선양 고궁은 왕조가 베이징으로 옮겨 가기 전의 첫 궁궐이었어요. 자금성의 작은 동생이라 불리지만, 만주족 양식이 배어 있는 팔각 전각들 덕분에 독자적인 매력을 지녔어요. 오늘날에는 유네스코 세계유산으로 지정된 박물관이에요.'),
  'shenyang/tomb': ('청나라 황릉', '도시를 둘러싼 동릉과 북릉은 청나라 창건 군주들의 기념비적인 능묘로, 유네스코 세계유산에 올라 있어요. 오래된 소나무 숲 사이로 돌짐승 조각이 늘어선 신도가 이어지고, 가을이면 능원 전체가 금빛으로 물들어요.'),
  'shenyang/factory': ('산업의 요람', '중국 중공업의 상당 부분이 선양에서 태어났고, 거대한 기계 공장들 덕분에 도시는 \'동방의 루르\'라 불렸어요. 톄시 지구의 옛 작업장들은 이제 박물관과 예술 공간으로 바뀌고 있지만, 선반 앞에서 일한 세대들의 자부심은 여전히 공기 중에 남아 있어요.'),
  'shenyang/dumpling': ('라오볜 만두', '청나라 때부터 만들어 온 라오볜 찐만두는 북방 식탁의 대표 요리예요. 소를 미리 익혀 육즙을 머금게 하는 방식이 만두에 비할 데 없는 부드러움을 줘요. 유서 깊은 식당에서 맛보는 만두 한 찜통은 선양이 건네는 공식 환영 인사나 다름없어요.'),
  'hefei/judge': ('포공사', '송나라의 전설적인 판관 포증은 허페이에서 태어났어요. 사람들은 그를 \'티 없이 맑은 하늘\'이라는 뜻의 \'포청천\'이라 불러요. 뇌물에 굽히지 않은 그의 공정함은 경극과 드라마의 소재가 되었고, 호숫가의 기념 공원은 청렴함에 바쳐진 사당 같은 곳이에요.'),
  'hefei/science': ('과학 도시', '허페이는 중국을 대표하는 대학과 연구소들이 모여 있는 과학 도시예요. 핵융합 실험부터 양자 연구까지 다양한 프로젝트가 이곳에서 진행되고, 캠퍼스와 테크노파크가 도시에 젊고 호기심 가득한 분위기를 더해 줘요.'),
  'hefei/lake': ('차오후', '차오후는 중국 5대 담수호 중 하나로, 허페이 바로 남쪽에 펼쳐져 있어요. 호수에서 나는 뱅어, 흰새우, 민물게는 \'세 가지 보물\'로 불려요. 호숫가 마을에서는 고깃배와 호수 전망 찻집이 느긋한 삶의 리듬을 만들어 줘요.'),
  'hefei/cake': ('루저우 참깨떡', '허페이의 옛 이름은 루저우이고, 달콤한 소가 든 참깨 과자는 그 이름을 간직한 오래된 간식이에요. 고소하게 구운 참깨 향이 바삭한 껍질 아래 부드러운 소와 어우러져요. 명절이면 선물 상자의 가장 좋은 자리는 늘 이 과자 차지예요.'),
  'foshan/wingchun': ('영춘권', '영춘권은 포산에서 무르익었어요. 전설적인 사부 엽문이 이곳에서 수련했고, 그의 제자 이소룡을 통해 이 유산이 전 세계로 퍼졌어요. 시내의 기념관과 무술 도장이 전통을 이어 가고, 아침 공원에서 권법을 연마하는 고수들을 만나는 일은 흔한 풍경이에요.'),
  'foshan/lion': ('사자춤', '포산은 남방 사자춤의 수도이고, 유명한 민중 영웅 황비홍도 이 고장 출신이에요. 축제 때면 화려한 사자들이 북소리에 맞춰 높은 기둥 위를 뛰어다녀요. 사자머리 만들기는 대대로 전해 내려오는 섬세한 수공예예요.'),
  'foshan/ceramic': ('스완 도자기', '스완의 도자기 가마는 수백 년째 꺼지지 않고 타오르고 있어요. 난펑 가마는 아직도 쓰이는 중국에서 가장 오래된 장작 가마 중 하나예요. 생생한 표정의 인형과 유약 입힌 지붕 장식으로 유명한 스완 도자기는 광둥 사원들의 지붕까지 장식하고 있어요.'),
  'foshan/opera': ('광둥 오페라', '중국 남부에서 가장 사랑받는 무대 예술인 광둥 오페라(월극)는 이 고장에서 무르익었어요. 옛날에는 극단들이 \'붉은 배\'를 타고 주장강 삼각주를 돌며 마을마다 공연을 펼쳤어요. 화려한 의상과 곡예, 광둥어 선율이 지금도 극장을 가득 채워요.'),
  'guiyang/pavilion': ('자슈러우', '난밍강 한가운데 바위 위에 세워진 3층 누각 자슈루는 명나라 때부터 도시의 상징이었어요. 이름은 \'으뜸가는 인재\'라는 뜻으로, 과거 시험에서 빼어난 학자들이 나오기를 바라는 마음으로 지어졌어요. 밤에 누각의 불빛이 강물에 비치면 구이양에서 가장 우아한 풍경이 태어나요.'),
  'guiyang/sourfish': ('쏸탕위', '쏸탕위, 곧 신 국물 생선탕은 구이저우의 대표 요리로, 먀오족의 발효 전통에 뿌리를 두고 있어요. 토마토와 쌀 발효액으로 신맛을 낸 새빨간 국물에 민물고기를 끓여요. 신맛과 매운맛, 향신료가 어우러진 이 맛은 산 많은 남부의 기후에 딱 맞아요.'),
  'guiyang/waterfall': ('황궈수 폭포', '구이양에서 갈 수 있는 황궈수 폭포는 아시아에서 가장 큰 폭포 중 하나예요. 굉음을 내며 쏟아지는 물의 장막 뒤로는 수이롄둥(수렴동) 동굴을 걸어서 지날 수 있고, 물보라는 햇빛 속에 무지개를 만들어요. 우기에는 폭포 소리가 계곡 몇 킬로미터 밖까지 울려 퍼져요.'),
  'guiyang/miao': ('묘족 문화', '구이저우의 산골 마을들은 은으로 만든 머리 장식으로 유명한 먀오족의 터전이에요. 축제 때면 젊은 여성들이 수공예 은관과 수놓은 옷을 차려입고, 루성 갈대 피리 선율에 맞춰 둥글게 모여 춤을 춰요. 납염과 자수는 어머니에게서 딸에게 전해지는 언어예요.'),
  'changchun/film': ('영화 도시', '창춘 영화 촬영소는 신중국 영화가 태어난 곳이에요. 여러 세대에 걸쳐 나라의 고전 영화들이 이곳에서 촬영되어, 도시는 \'동방의 할리우드\'라 불려요. 옛 세트장은 영화 테마파크로 바뀌었고, 영화제의 전통은 지금도 이어지고 있어요.'),
  'changchun/car': ('자동차 도시', '중국 최초의 국산 트럭과 최초의 국산 승용차가 창춘의 공장에서 나왔고, 국가 정상들이 타는 훙치 리무진도 이곳에서 생산돼요. \'자동차 도시\'라는 칭호는 괜한 것이 아니에요. 공장과 박물관, 박람회가 어우러진 자동차 문화가 곧 이 도시의 정체성이에요.'),
  'changchun/palace': ('위만황궁', '중국의 마지막 황제 푸이는 만주국 시절 이 궁전에서 꼭두각시 통치자로 살았어요. 지금은 박물관이 된 이곳은 화려한 전각 뒤에 숨어 있던 감시와 외로움을 들려줘요. 이 궁전은 격동의 20세기 역사를 들여다보는 조용한 창이에요.'),
  'changchun/snow': ('겨울 눈', '창춘의 길고 새하얀 겨울은 도시를 눈 축제로 바꿔 놓아요. 얼음 조각들이 밤이면 색색의 조명으로 빛나고, 숲으로 둘러싸인 징웨탄 호수는 스키와 썰매를 즐기는 사람들을 맞이해요. 추위에도 불구하고 이곳의 겨울은 일 년 중 가장 흥겨운 계절이에요.'),
  'xining/lake': ('칭하이호', '칭하이호는 중국에서 가장 큰 호수로, 고원 한가운데 청록빛 바다처럼 펼쳐져 있어요. 여름이면 호숫가가 샛노란 유채꽃밭으로 둘러싸이고, 철새들이 호수의 섬에 내려앉아요. 자전거로 호수를 한 바퀴 도는 일은 여행자들이 가장 사랑하는 고원 모험이에요.'),
  'xining/monastery': ('타르사', '타얼사(쿰붐 사원)는 티베트 불교에서 가장 큰 사원 중 하나로, 겔룩파의 창시자 쫑카파가 태어난 자리에 세워졌어요. 야크 버터로 빚은 알록달록한 조각과 벽화, 천 아플리케는 \'3대 예술\'로 유명해요. 사원 마당에서는 순례자들이 돌리는 마니차가 쉼 없이 돌아가요.'),
  'xining/flower': ('유채꽃', '7월이 오면 칭하이 고원은 지평선까지 황금빛 유채꽃으로 뒤덮여요. 특히 호숫가와 산자락이 천 가지 노란빛으로 물결쳐요. 서늘한 고원 공기 속에 펼쳐지는 이 장관은 해마다 사진가들과 신혼부부들을 이곳으로 불러들여요.'),
  'xining/lamb': ('야크와 양고기', '시닝의 식탁은 후이족과 티베트 요리가 만나는 자리예요. 손으로 뽑은 국수가 김이 모락모락 나는 그릇에 담겨 나오고, 양꼬치가 숯불 위에서 지글거려요. 야크 요구르트와 버터차는 고원의 일상적인 맛이고, 밤이 되면 시장이 향신료 냄새로 가득 차요.'),
  'guilin/karst': ('리강 카르스트 지형', '안개 속에서 솟아오른 석회암 봉우리들 사이로 리장강이 굽이굽이 흘러요. 바로 이 풍경이 20위안 지폐에 새겨져 있어요. 구이린에서 양숴로 미끄러져 가는 배와 대나무 뗏목, 가마우지 어부들이 살아 있는 한 폭의 중국화를 이루어요.'),
  'guilin/elephant': ('상비산', '코를 리장강에 담근 코끼리를 닮은 이 바위는 구이린에서 가장 사랑받는 상징이에요. 코와 몸통 사이의 아치가 물에 비치면 보름달을 닮아서 \'수월동(물과 달의 동굴)\'이라 불려요. 시인들은 수백 년 동안 이 풍경을 시로 노래해 왔어요.'),
  'guilin/terrace': ('룽지 다랭이논', '산등성이를 계단처럼 층층이 감싸는 룽지, 곧 \'용의 등뼈\' 다랑논은 좡족과 야오족이 수백 년 동안 쏟은 노고의 결실이에요. 봄에는 물을 댄 논이 거울처럼 반짝이고, 가을에는 황금빛으로 물들어요. 산마루의 목조 마을들은 전통적인 삶을 이어 가고 있어요.'),
  'guilin/osmanthus': ('계화꽃', '구이린이라는 이름은 \'목서(계화나무) 숲\'이라는 뜻이에요. 가을이면 도시 전체가 이 작은 꽃들의 달콤한 향기에 잠겨요. 목서 차와 술, 사탕은 대표적인 지역 별미예요. 강가의 향기로운 나무 아래를 걷는 일은 이 계절의 가장 아름다운 의식이에요.'),
  'wenzhou/merchant': ('원저우 상인 정신', '원저우 사람들은 중국에서 가장 진취적인 상인 공동체로 이름나 있어요. 가족과 동향 네트워크로 유럽에서 아메리카까지 무역의 다리를 놓았어요. 개혁 시기에 민영 기업의 선구자였던 이 도시에는 작은 공방에서 세계 시장으로 뻗어 나간 이야기가 가득해요.'),
  'wenzhou/shoe': ('신발과 가죽', '원저우는 중국 신발과 가죽의 수도로 꼽혀요. 전 세계 가죽 구두의 큰 몫이 이 공장 도시에서 만들어져요. 라이터부터 안경까지 작은 상품에도 능숙한 이 도시는 \'집집마다 공방\'이던 시절의 장인 정신을 지금도 간직하고 있어요.'),
  'wenzhou/mountain': ('옌당산', '폭포와 뾰족한 봉우리로 유명한 옌당산은 \'바다 위 으뜸가는 산\'이라 칭송받아요. 다룽추 대폭포가 절벽에서 굉음을 내며 떨어지고, 해 질 녘이면 몇몇 봉우리의 실루엣이 모습을 바꾸는 듯 보여요. 이 산은 지질학적 가치로 보호받는 지질공원이에요.'),
  'wenzhou/seafood': ('해산물', '동중국해를 향해 열린 원저우의 요리는 가볍고 신선해요. 오징어와 가리비, 생선이 일상 식탁의 중심이에요. 이 지역의 어우 요리는 해산물 본연의 맛을 앞세워요. 손으로 다져 빚은 어묵 완자탕은 이 도시에서 가장 사랑받는 길거리 음식이에요.'),
  'tangshan/memorial': ('지진 기념비', '1976년의 대지진은 탕산을 폐허로 만들었어요. 오늘날 추모 공원의 긴 화강암 벽에는 희생자들의 이름이 새겨져 있어요. 고요한 연못가에서는 해마다 추모 행사가 열려요. 다시 일어선 이 도시는 회복력과 재생의 상징이 되었어요.'),
  'tangshan/coal': ('탕산 탄광', '중국 최초의 근대식 탄광과 초기 철도 노선 중 하나가 탕산에서 문을 열었고, 나라 최초의 증기 기관차도 이곳에서 만들어졌어요. 그래서 이 도시는 중국 산업의 요람으로 꼽혀요. 광산과 철강의 문화는 오늘날까지 도시의 정체성에 새겨져 있어요.'),
  'tangshan/ceramic': ('탕산 도자기', '탕산은 \'북방의 도자기 도시\'로 불리고, 특히 본차이나 생산으로 유명해요. 빛이 은은히 비치는 얇고 하얀 그릇들이 중국 곳곳의 식탁을 장식해요. 도자기 박람회와 장인들의 공방이 이 도시의 전통을 살아 있게 해요.'),
  'tangshan/lake': ('난후 공원', '난후는 옛 광산 침하 지대를 호수와 푸른 공원으로 바꾸면서 태어났고, 오늘날 도시의 초록 허파 역할을 해요. 호숫가에는 자전거 길과 꽃밭이 이어지고, 공원에서는 대형 원예 박람회가 열리기도 했어요. 공업 도시가 자연과 화해했음을 보여 주는 상징 같은 곳이에요.'),
  'anshan/steel': ('철강 도시', '안산은 중국 최대급 제철소가 세워진 곳으로, \'철강의 수도\'라 불려요. 여러 세대에 걸쳐 용광로의 불빛이 도시의 밤을 밝혔어요. 이곳에서 철강업은 단순한 직업이 아니라 도시 정체성 그 자체예요.'),
  'anshan/jade': ('슈옌 옥', '안산에 속한 슈옌은 중국에서 손꼽히는 옥의 고장이에요. 시내의 위포위안(옥불원)에는 거대한 옥 원석 하나를 통째로 깎아 만든 세계적으로 유명한 불상이 모셔져 있어요. 옥 공방과 시장에는 돌에 생명을 불어넣는 장인의 솜씨가 가득해요.'),
  'anshan/mountain': ('첸산', '\'천 개의 연꽃 봉우리\'라는 뜻의 첸산은 동북 지방의 성스러운 산으로, 화강암 봉우리들이 연꽃잎처럼 늘어서 있어요. 산비탈에는 불교와 도교 사원이 흩어져 있고, 앉아 있는 부처의 모습을 닮은 거대한 바위가 유명해요. 봄이면 산 전체가 꽃향기에 휩싸여요.'),
  'anshan/spring': ('탕강쯔 온천', '탕강쯔 온천에서는 천 년 동안 사람들이 치유를 구해 왔어요. 뜨거운 광천수와 온천 진흙 목욕이 관절에 좋다고 믿어져 여러 세대가 몸을 담가 왔어요. 역사 속 통치자와 유명 인사들을 맞이했던 이 온천은 오늘도 휴식을 찾는 이들의 안식처예요.'),
  'linyi/market': ('도매 시장', '린이는 중국 북부 최대의 도매 상업 중심지예요. 거대한 시장 건물마다 바늘부터 가구까지 없는 게 없어요. 이곳에서 출발한 트럭들이 상품을 전국 방방곡곡으로 실어 나르고, 그 활기가 도시에 \'물류 수도\'라는 칭호를 안겨 주었어요.'),
  'linyi/brush': ('왕희지 생가', '중국 \'서예의 성인\' 왕희지가 린이에서 태어났어요. 물 흐르듯 유려한 그의 필치는 천 년 넘게 본보기가 되어 왔어요. 시내의 기념 사당과 서예 축제가 이 유산을 이어 가요. 린이에서는 먹 향기가 상업의 소란에 우아한 화답을 건네요.'),
  'linyi/mountain': ('멍산', '이멍산맥의 진주인 멍산은 산둥에서 가장 높은 산 중 하나예요. 울창한 숲과 폭포, 맑디맑은 공기 덕분에 \'천연 산소 바\'라는 별명을 얻었어요. 등산로와 산비탈 마을, 산꿀이 있어 여행자에게 고요한 쉼터가 되어 줘요.'),
  'linyi/pancake': ('이멍 지엔빙', '종잇장처럼 얇게 부친 옥수수·잡곡 전병은 이멍 산골 사람들의 오랜 주식이에요. 뜨거운 돌판에서 구운 전병은 전통적으로 싱싱한 대파를 돌돌 말아 먹어요. 든든하고 오래가는 이 빵은 산골 마을의 고단한 삶을 함께해 온 믿음직한 동반자였어요.'),
  'cangzhou/lion': ('철사자', '천 년 넘게 서 있는 거대한 주철 사자상은 창저우의 자랑스러운 상징이자 중국에서 가장 큰 고대 철기 유물 중 하나예요. 사람들은 이 사자를 \'바다를 잠재우는 포효\'라 부르는데, 홍수를 막기 위해 주조되었다고 전해져요. 도시는 이 상징물을 수호신처럼 아껴요.'),
  'cangzhou/martial': ('무술의 고향', '창저우는 중국 \'우슈의 고장\'으로 이름나 있어요. 팔극권처럼 강하고 실전적인 문파들이 이곳에서 발전했어요. 옛날에는 상인 행렬을 지키던 호위 무사들 상당수가 이 도시 출신이었어요. 오늘날에도 무술 도장과 대회가 전통을 굳건히 이어 가고 있어요.'),
  'cangzhou/canal': ('대운하', '베이징과 항저우를 잇는 대운하가 창저우 한복판을 지나가요. 이 도시는 수백 년 동안 운하 무역으로 번영을 누렸어요. 옛 나루터와 부두 거리에는 그 시절의 흔적이 남아 있고, 운하 변 공원들은 이제 저녁 산책 명소로 사랑받아요.'),
  'cangzhou/jujube': ('금사 대추', '껍질이 얇고 꿀처럼 달콤한 창저우의 \'금실 대추\'는 말린 과일의 왕으로 꼽혀요. 반으로 쪼개면 과육에서 가느다란 금빛 실이 늘어나는 데서 이름이 왔어요. 가을 수확기에는 과수원이 붉게 물들고, 대추차와 대추 과자는 이 고장 식탁의 단골손님이에요.'),
  'nantong/textile': ('난퉁 방직성', '난퉁의 현대 섬유 산업은 실업가 장젠이 세운 방적 공장에서 시작되었어요. 오늘날 이 도시는 중국 홈텍스타일의 수도로, 침구부터 커튼까지 그 제품이 세계 시장으로 뻗어 나가요. 직조 문화는 이 지역의 남빛 바탕에 흰 무늬를 찍은 전통 날염 천에도 살아 있어요.'),
  'nantong/mountain': ('랑산', '양쯔강이 바다와 만나는 곳에 솟은 다섯 봉우리의 랑산은 이 지역의 성스러운 산이에요. 순례자와 여행자들이 정상에 있는 수백 년 된 불교 사찰까지 계단을 따라 올라가요. 꼭대기에 서면 큰 강이 바다와 만나는 장관이 발아래 펼쳐져요.'),
  'nantong/kite': ('반야오 연', '난퉁의 \'반야오\' 연은 틀에 매단 수십 개의 작은 호루라기 덕분에 하늘에서 윙윙 노래해요. 바람이 거세질수록 그 소리는 오케스트라처럼 커져요. 소리 나는 연을 만드는 일은 대대로 전해 내려오는 오랜 공예로, 지역 장인들이 정성껏 지켜 가고 있어요.'),
  'nantong/school': ('근대 교육의 발상지', '실업가이자 개혁가인 장젠은 자신이 번 재산을 고향에 바쳤어요. 난퉁에 근대식 학교와 도서관, 그리고 중국인이 세운 최초의 박물관을 열었어요. 덕분에 도시는 교육의 선구자가 되었고, \'산업으로 나라를 구한다\'는 그의 이상은 지금도 시민들의 기억 속에 살아 있어요.'),
  'taizhou/opera': ('메이란팡', '경극의 전설적인 명인 메이란팡의 뿌리는 타이저우에 닿아 있어요. 그가 여성 역할에 불어넣은 우아함은 경극을 세계에 알렸어요. 시내의 기념 공원과 박물관은 의상과 무대 사진으로 그의 이야기를 들려주고, 공원에서는 지금도 경극 가락이 들려와요.'),
  'taizhou/tea': ('자오차', '타이저우의 하루는 \'자오차\', 곧 아침 차로 시작돼요. 진하게 우린 차와 함께 찐빵, 곱게 채 썬 말린 두부 무침, 어묵 완자탕이 상에 올라요. 이곳의 아침 차는 결코 서두르는 법이 없어요. 이웃들이 찻집에 모여 이야기를 나누며 하루를 열어요.'),
  'taizhou/boat': ('친퉁 보트 축제', '봄이 되면 친퉁 마을의 습지에 수백 척의 배가 모여들어요. 북소리 속에 노잡이들이 경주를 벌이고, 삿대가 물을 칠 때마다 하얀 물보라가 솟아올라요. 수백 년 된 이 뱃놀이 축제는 물의 고장 문화에서 가장 흥겨운 날이며, 국가 무형유산에 올라 있어요.'),
  'taizhou/meatball': ('사자두', '크고 부드러운 돼지고기 완자 \'사자머리\'는 화이양 요리의 고전이에요. 폭신한 질감이 사자 갈기를 닮았다고 해서 붙은 이름이에요. 약한 불에서 몇 시간을 뭉근히 익혀 입안에서 사르르 녹아요. 게 알을 더한 버전은 가을 식탁에서 가장 귀한 대접을 받아요.'),
  'jinhua/ham': ('진화 햄', '진화 햄은 수백 년 된 염장과 건조 방식으로 숙성돼요. 단면의 짙은 붉은빛과 깊은 풍미 덕분에 중국에서 가장 유명한 햄이에요. 주로 국물 요리와 찜에 감칠맛을 더하는 데 쓰여요. 좋은 진화 햄 한 덩이는 여러 해에 걸친 인내의 결실이에요.'),
  'jinhua/film': ('헝뎬 스튜디오', '진화에 속한 헝뎬은 세계에서 가장 큰 야외 영화 촬영지예요. 자금성과 옛 왕조 궁전들을 본뜬 거대한 복제 건물이 그 안에 솟아 있어요. 수많은 사극 영화와 드라마가 이곳에서 촬영돼요. 세트장을 거닐다 보면 시대극 의상을 입은 배우들과 마주치기도 해요.'),
  'jinhua/cave': ('솽룽 동굴', '\'쌍룡\'이라는 뜻의 솽룽 동굴은 들어가는 순간부터 잊을 수 없어요. 방문객들은 낮은 바위 문 아래로 배에 반듯이 누운 채 미끄러져 들어가요. 안으로 들어서면 종유석과 석순으로 꾸며진 서늘한 지하 세계가 열려요. 옛 여행가들의 글에도 찬사와 함께 등장하는 동굴이에요.'),
  'jinhua/bridge': ('고대 석교', '옛 이름이 우저우였던 진화의 주변에는 아치형 돌다리와 운하로 엮인 물의 마을이 가득해요. 흰 벽에 검은 기와를 얹은 집들이 물 위에 비치고, 다리 어귀마다 찻집이 늘어서 있어요. 이 풍경은 강남(장난) 지방의 우아한 삶의 방식을 오늘까지 전해 줘요.'),
  'wuhu/park': ('팡터 원더랜드', '우후에는 중국 최대급 테마파크들이 모인 단지가 있어요. 롤러코스터부터 애니메이션 세계까지, 온 가족이 짜릿한 하루를 즐길 수 있어요. 덕분에 도시는 이 지역의 놀이 수도가 되었고, 주말이면 이웃 지역에서 방문객이 물밀듯 몰려와요.'),
  'wuhu/ironart': ('철화', '우후의 \'철화(쇠 그림)\' 예술에서는 단조한 쇠가 붓놀림을 닮은 우아한 그림으로 변신해요. 약 300년 역사의 이 공예는 수묵화의 정신을 금속에 옮겨 담고, 장인들은 망치와 모루로 산과 소나무, 새를 빚어내요. 이 작품들은 이 도시의 가장 독창적인 선물이에요.'),
  'wuhu/rice': ('미시', '우후는 역사적으로 중국 최대의 쌀 시장 중 하나였어요. 양쯔강 변이라는 위치 덕분에 남방의 수확물이 이곳에서 거래되었어요. 부두에서 쌀가마를 나르던 짐꾼들의 자리는 이제 현대식 창고가 대신하지만, 도시는 곡물 무역의 유산을 여전히 자랑스러워해요.'),
  'wuhu/river': ('양쯔강 항구', '양쯔강 변의 분주한 항구는 우후를 안후이성이 세계로 나가는 관문으로 만들어 줘요. 강을 따라 화물선과 컨테이너 크레인이 쉴 새 없이 움직이고, 그 활기찬 모습을 강변 공원에서 즐겁게 바라볼 수 있어요. 강은 도시에 무역과 저녁의 시원한 바람을 함께 실어다 줘요.'),
  'huangshan/peak': ('황산', '화강암 봉우리와 구름 바다, 구불구불한 소나무, 온천을 품은 황산은 중국에서 가장 유명한 산이자 유네스코 세계유산이에요. \'4대 절경\'이라 불리는 이 아름다움은 수백 년 동안 화가와 시인들에게 영감을 주었어요. 해돋이에 구름 위에 서 보는 경험은 평생 남는 추억이에요.'),
  'huangshan/village': ('훙춘 마을', '흰 벽과 검은 기와의 후이저우 마을 훙춘은 물길과 반달 모양 연못이 어우러져 마치 그림에서 튀어나온 듯하고, 유네스코 세계유산에 올라 있어요. 마을의 배치는 소의 몸을 본떠 설계되었어요. 아침 안개가 호수에 내려앉으면 화가들이 물가에 이젤을 세워요.'),
  'huangshan/tea': ('황산모봉', '안개 낀 산비탈에서 따는 황산 마오펑은 중국에서 가장 유명한 녹차 중 하나로, 솜털이 보송하고 산봉우리를 닮은 찻잎에서 이름을 얻었어요. 이른 봄 첫물차를 가장 귀하게 여겨요. 찻잔에 은은한 난초 향이 감도는 게, 마치 산의 구름이 찻잎에 스며든 것 같아요.'),
  'huangshan/ink': ('휘주 먹과 예술', '옛 후이저우 지방은 중국에서 가장 명성 높은 먹과 벼루를 만들어 냈고, 서예가들은 수백 년 동안 이 재료를 찾아왔어요. 나무와 벽돌, 돌 조각으로 꾸며진 고택들도 같은 장인 정신의 산물이에요. 후이저우 문화는 먹과 건축을 하나의 미학으로 아우르고 있어요.'),
  'yichun/moon': ('밍웨산', '\'밝은 달\'이라는 뜻의 밍웨산은 이춘의 상징이에요. 이 도시는 달을 주제로 한 축제로도 유명해요. 케이블카를 타면 절벽 가장자리 산책로와 높은 산속 초원까지 오를 수 있어요. 정상에서 안개가 걷히면 아래 골짜기들이 은은한 은빛으로 반짝여요.'),
  'yichun/spring': ('온천', '이춘 원탕 마을의 온천은 희귀한 셀레늄 성분이 풍부해 예로부터 몸에 좋다고 여겨져 왔어요. 온천 호텔과 노천탕이 일 년 내내 방문객을 맞이해요. 산 공기와 따뜻한 물의 만남이 이 도시를 중국에서 손꼽히는 온천 휴양지로 만들었어요.'),
  'yichun/zen': ('선불교', '이춘의 산들은 중국 선(찬)불교의 중요한 종파들이 뿌리내린 땅이에요. 수백 년 된 사찰들이 고요한 골짜기 곳곳에 자리해요. 스님들의 차밭과 명상 법당은 방문객에게 천천히 쉬어 가라고 손짓하고, 종소리가 안개 낀 숲속에 울려 퍼져요.'),
  'yichun/rice': ('곡창지대', '비옥한 위안강 평야는 오랫동안 장시성의 곡창이었어요. 물이 넉넉한 논에서 해마다 풍성한 쌀이 나요. 마을에서는 수확철이 축제처럼 지나가요. 햅쌀로 만든 지역 쌀국수와 쌀술이 평야의 넉넉함을 식탁에 옮겨 줘요.'),
  'zhangzhou/narcissus': ('수선화', '중국에서 가장 유명한 수선화 구근이 장저우에서 재배돼요. 이 꽃은 춘절(설)에 빼놓을 수 없는 장식이에요. 장인들은 구근에 특별한 칼집을 내어 꽃이 우아한 모양으로 피어나게 해요. 새해에 집에서 피어난 수선화는 다가올 한 해의 복으로 여겨져요.'),
  'zhangzhou/tulou': ('객가 토루', '흙을 다져 만든 거대한 원형 요새 주택 \'토루(투러우)\'는 마을 하나를 한 지붕 아래 모으며, 유네스코 세계유산에 올라 있어요. 두꺼운 흙벽은 방어와 시원함을 함께 주고, 안마당에서는 공동체의 삶이 수백 년째 이어져요. 푸른 언덕 사이에 늘어선 토루 무리는 동화 같은 풍경을 그려 내요.'),
  'zhangzhou/banana': ('열대 과일', '따뜻하고 습한 장저우의 삼각주는 일 년 내내 과일을 내어 줘요. 바나나 농장과 룽옌(용안) 숲, 귤밭이 지평선까지 이어져요. 이 지역의 크고 즙 많은 포멜로도 식탁의 인기 과일이에요. 과일 시장은 계절을 가리지 않고 색과 향의 잔치예요.'),
  'zhangzhou/coast': ('둥산섬', '금빛 모래사장과 어촌 마을이 있는 둥산섬은 남쪽 해안의 진주예요. 섬에서 가장 유명한 볼거리는 절벽 끝에 아슬아슬하게 균형을 잡고 서서 바람에 살짝 흔들린다고 전해지는 거대한 \'바람 바위(펑둥스)\'예요. 저녁이면 항구로 돌아오는 배들이 그날의 싱싱한 어획물을 실어 와요.'),
  'guangzhou/tower': ('광저우 타워', '주장강 기슭에 우뚝 솟은 이 타워는 가늘게 비틀린 몸체 덕분에 \'가는 허리\'라는 애칭으로 불려요. 세계에서 가장 높은 타워 중 하나로, 밤이면 수천 개의 LED 조명이 색을 바꾸며 빛나고, 광저우 현대 스카이라인의 왕관이자 델타 지역을 한눈에 내려다보는 전망 명소예요.'),
  'guangzhou/dimsum': ('얌차', '광저우의 아침은 \'얌차\'로 시작해요. 진하게 우린 차와 함께 대나무 찜통에 김이 오르는 딤섬 접시들이 테이블에 차려지죠. 새우 딤섬, 사오마이, 바삭한 페이스트리를 곁들여 몇 시간이고 이어지는 대화, 이 의식이야말로 광둥 음식 문화의 심장이라고 할 수 있어요.'),
  'guangzhou/academy': ('천씨서원', '청나라 말기에 천(陳)씨 성을 가진 가문들이 함께 세운 이 웅장한 사당은 목조각, 석조 부조, 그리고 지붕을 가득 채운 알록달록한 도자기 인형들로 유명해요. 오늘날에는 민속 예술 박물관으로 쓰이며 중국 남방 공예의 정수를 보여 주고 있어요.'),
  'guangzhou/flower': ('꽃의 도시', '온화한 기후 덕분에 광저우에서는 일 년 내내 꽃이 피어서, 이 도시는 예로부터 \'꽃의 도시\'라고 불려 왔어요. 춘절을 앞두고 거리마다 대규모 꽃 시장이 열리면, 가족들은 새해 행운을 빌며 금귤나무와 복숭아꽃 가지를 사 가요.'),
  'wuhan/crane': ('황학루', '창장강을 굽어보는 황학루는 삼국시대까지 거슬러 올라가는 역사를 지닌, 중국에서 가장 유명한 누각 중 하나예요. 최호와 이백 같은 시인들의 시에 영감을 준 이 누각은 여러 번 무너지고 다시 지어졌지만, 그 시적인 혼만은 늘 그대로 간직하고 있어요.'),
  'wuhan/noodle': ('러간몐', '러간몐, 즉 \'뜨겁고 마른 국수\'는 삶은 면에 고소한 참깨 소스와 장아찌, 쪽파를 버무려 만들어요. 우한 사람들은 길거리 노점에서 산 한 그릇으로 하루를 시작하는데, 우한에서는 아침 식사 문화가 \'궈자오\'라는 이름을 가질 만큼 하나의 생활 방식이에요.'),
  'wuhan/duckneck': ('야보즈', '고추와 갖은 향신료를 넣은 국물에 몇 시간씩 조린 오리목은 우한 사람들이 가장 사랑하는 간식이에요. 뼈에서 살을 발라 먹는 이 얼얼하고 매콤한 맛은, 긴 여름밤 강가에서 수다를 떨며 시원한 맥주를 곁들일 때 빠질 수 없는 단짝이랍니다.'),
  'wuhan/university': ('우한대학교 벚꽃', '봄이 올 때마다 우한대학교의 유서 깊은 캠퍼스는 분홍빛과 흰빛 벚꽃으로 뒤덮이고, 중국 전역에서 방문객이 몰려와요. 뤄자산 기슭의 오래된 건물들과 어우러진 벚꽃은 이 도시에서 가장 낭만적인 봄 풍경을 만들어 내지요.'),
  'tianjin/eye': ('톈진 아이', '하이허강 위 다리 한가운데에 세워진 거대한 관람차 \'톈진 아이\'는 흐르는 물 위에 지어진 세계에서도 보기 드문 관람차예요. 꼭대기에 오르면 강 양쪽이 한꺼번에 펼쳐지는데, 한쪽에는 유럽풍 옛 건물들이, 다른 쪽에는 반짝이는 유리 빌딩들이 늘어서 있어요.'),
  'tianjin/baozi': ('거우부리 만두', '청나라 때부터 만들어 온 거우부리 바오쯔는 얇은 피와 육즙 가득한 소, 정교하게 접은 주름으로 유명한 톈진의 대표 음식이에요. 이름은 \'개도 거들떠보지 않는다\'는 뜻인데, 창업자가 만두를 빚는 데 너무 몰두해 손님과 이야기할 틈도 없었다는 이야기에서 왔다고 해요.'),
  'tianjin/crosstalk': ('샹성', '샹성은 두 명의 공연자가 속사포 같은 입담과 말장난, 성대모사로 관객을 웃기는 전통 무대 예술이에요. 톈진의 찻집에서 뿌리내린 이 예술 덕분에 톈진은 \'중국 코미디의 요람\'이라는 명성을 얻었고, 지금도 사람들은 따끈한 차를 마시며 샹성을 즐긴답니다.'),
  'tianjin/architecture': ('우다다오', '\'다섯 개의 큰 거리\'라는 뜻의 우다다오에는 외국 조계 시절에 지어진 수백 채의 유럽풍 저택이 남아 있어요. 영국식, 프랑스식, 이탈리아식 건물이 나란히 늘어선 이 거리 덕분에 톈진은 \'세계 건축 박물관\'이라는 별명을 얻었고, 마차나 자전거를 타고 둘러보는 것이 제일 좋아요.'),
  'xiamen/island': ('구랑위', '샤먼 앞바다의 구랑위에서는 자동차가 다니지 않아서, 좁은 골목에는 발소리와 피아노 선율만 흐른답니다. 옛 영사관 건물과 부겐빌레아가 감싼 저택들이 있는 이 유네스코 세계유산 섬은, 짧은 페리 여행으로 닿을 수 있는 야외 박물관이에요.'),
  'xiamen/piano': ('피아노의 섬', '19세기에 섬으로 이주해 온 선교사와 상인들과 함께 서양 음악이 구랑위에 뿌리를 내렸어요. 가구당 피아노 수가 유난히 많아 \'피아노 섬\'이라 불리는 이 섬에는 피아노 박물관이 있고, 대를 이어 내려오는 음악 전통이 지금도 살아 숨 쉬고 있어요.'),
  'xiamen/egret': ('백로', '샤먼의 옛 이름 \'루다오\'는 \'백로의 섬\'이라는 뜻이에요. 우아한 백로들은 지금도 해안 습지와 공원 위를 미끄러지듯 날아다니죠. 도시의 상징이 된 이 새는 조각상부터 거리 이름까지 곳곳에서 만날 수 있는데, 샤먼이 바다와 자연과 맺어 온 깊은 인연을 보여 준답니다.'),
  'xiamen/oyster': ('굴전', '신선한 굴을 달걀과 고구마 전분에 섞어 겉은 바삭하고 속은 부드럽게 부쳐 낸 굴전은 민난 지방을 대표하는 길거리 음식이에요. 샤먼 야시장에서 새콤달콤 매콤한 소스와 함께 나오는 이 요리는, 해협 건너 대만에서도 똑같이 사랑받고 있어요.'),
  'harbin/ice': ('하얼빈 빙등제', '겨울이 오면 얼어붙은 쑹화강에서 잘라 낸 거대한 얼음 블록으로 궁전과 탑, 미끄럼틀을 쌓아 올리고, 밤에는 오색 조명이 도시를 동화 나라로 바꿔 놓아요. 하얼빈 빙설제는 세계 최대의 얼음 조각 축제로, 해마다 수백만 명의 방문객을 맞이한답니다.'),
  'harbin/cathedral': ('성 소피아 성당', '초록 양파 모양 돔과 붉은 벽돌이 인상적인 성 소피아 성당은 하얼빈의 러시아 철도 시대가 남긴 가장 웅장한 건축물이에요. 지금은 건축 박물관으로 쓰이고 있고, 성당 앞 광장은 비둘기가 날고 거리 음악가들이 연주하는, 이 도시 사람들이 가장 사랑하는 만남의 장소예요.'),
  'harbin/sausage': ('홍창(하얼빈 소시지)', '100년도 더 전에 러시아 이민자들의 레시피로 만들기 시작한 훈제 붉은 소시지는 하얼빈을 대표하는 맛이에요. 장작 연기로 낸 향과 은은한 마늘 풍미가 갓 구운 빵, 시원한 맥주와 완벽하게 어울리며, 이 도시의 유럽적인 뿌리를 식탁 위로 그대로 옮겨 준답니다.'),
  'harbin/accordion': ('음악의 도시', '러시아 이주민들이 가져온 바이올린과 아코디언, 오페라 문화 덕분에 하얼빈은 일찍부터 중국 서양 음악의 중심지가 되었어요. 중국 최초의 선구적인 교향악단이 자리 잡은 이 도시는, 여름마다 열리는 유서 깊은 음악 축제로 \'음악의 도시\'라는 이름을 이어 가고 있어요.'),
  'fuzhou/alley': ('싼팡치샹', '\'세 갈래 거리와 일곱 골목\'이라는 뜻의 싼팡치샹은 하얀 벽과 검은 기와지붕이 남아 있는 명나라·청나라 시대 옛 동네예요. 좁은 돌길에는 한때 학자와 관리들이 살았고, 지금은 찻집과 공예품 가게, 안뜰 딸린 저택들이 어우러진 살아 있는 박물관이 되었답니다.'),
  'fuzhou/banyan': ('용의 도시', '송나라 때 시작된 나무 심기 덕분에 푸저우 거리는 수백 년 된 반얀나무로 가득해요. 수염처럼 뿌리를 늘어뜨린 이 거대한 나무들은 후텁지근한 여름의 뙤약볕 아래 시원한 그늘을 만들어 주고, 그래서 이 도시는 \'룽청\', 즉 \'반얀의 도시\'라고 불려요.'),
  'fuzhou/hotspring': ('온천', '푸저우 도심 한복판에서는 천연 온천수가 솟아오르는데, 이 온천은 천 년 넘게 목욕 문화를 키워 왔어요. 지금도 주민들은 동네 온천에서 피로를 풀고 있죠. 지열이라는 보물 바로 위에 세워진 푸저우는 중국에서도 보기 드문 온천 수도랍니다.'),
  'fuzhou/soup': ('불도장', '포탸오창(불도장)은 관자와 버섯, 전복 등 수십 가지 귀한 재료를 흙 항아리에 넣고 몇 시간씩 고아 만드는 전설적인 국물 요리예요. 향이 어찌나 유혹적인지 스님마저 담을 뛰어넘어 맛보러 온다는 시구에서 이름이 왔고, 지금도 푸젠 요리의 왕관으로 꼽힌답니다.'),
  'dongguan/robot': ('세계의 공장', '주장 삼각주의 심장부에 자리한 둥관은 세계 전자제품과 장난감의 상당 부분을 만들어 내는 거대한 산업 도시예요. 노동 집약적인 조립 라인은 점점 스마트 공장과 로봇 팔에 자리를 내주고 있고, \'세계의 공장\'은 새로운 시대를 향해 스스로를 바꿔 가고 있어요.'),
  'dongguan/basketball': ('농구의 도시', '둥관에서 농구는 하나의 열정이에요. 거의 모든 동네에 코트가 있고, 놀이터에서 프로 리그까지 이어지는 탄탄한 육성 시스템이 갖춰져 있죠. 중국 리그에서 가장 많은 우승을 차지한 클럽 중 하나인 광둥 서던 타이거스가 이곳을 연고지로 삼고 있으며, 둥관은 공식적으로 중국의 \'농구 도시\'로 지정되었답니다.'),
  'dongguan/keyuan': ('커위안', '청나라 관리가 지은 커위안은 아주 작은 공간 안에 정자와 연못, 구불구불한 회랑을 솜씨 좋게 담아낸 것으로 유명해요. 광둥의 4대 고전 정원 중 하나로 꼽히는 커위안은 중국 남방 조경 예술의 섬세한 아름다움을 응축해 보여 준답니다.'),
  'dongguan/cannon': ('후먼 포대', '후먼 포대는 줄지어 늘어선 대포로 주장강 하구를 지키던 역사적인 요새예요. 1839년 흠차대신 린쩌쉬가 압수한 아편을 이 해안에서 폐기하면서 아편전쟁의 불씨가 되었죠. 오늘날 포대와 박물관은 중국 근대사의 이 전환점을 생생하게 들려주고 있어요.'),
  'lanzhou/beefnoodle': ('란저우 우육면', '란저우의 수타 소고기 국수는 유명한 공식으로 통해요. 맑은 소고기 육수, 하얀 무, 붉은 고추기름, 그리고 초록 고수죠. 장인이 눈앞에서 단 몇 초 만에 반죽을 가늘게 뽑아내는 이 한 그릇은 도시의 아침 의식이자 중국에서 가장 유명한 국수 중 하나랍니다.'),
  'lanzhou/waterwheel': ('수차', '명나라 때 황허의 물을 밭으로 끌어올리기 위해 만든 거대한 나무 물레방아는 란저우의 상징이 되었어요. 강가의 물레방아 공원에서는 이 수백 년 된 공학 걸작의 복원품들이 지금도 돌아가고 있는데, 그 묵직한 삐걱임이 옛 시절의 소리를 전해 준답니다.'),
  'lanzhou/statue': ('황하 어머니상', '강가에 자리한 \'황허 어머니\' 조각상은 물결치는 머리카락의 어머니와 그 품에 안긴 아기를 묘사하고 있어요. 어머니는 중국 문명을 길러 낸 황허를, 아이는 그 물에서 태어난 사람들을 상징하죠. 이 조각상은 란저우가 강과 맺어 온 애틋한 정을 가장 진하게 담아낸 작품이에요.'),
  'lanzhou/raft': ('양가죽 뗏목', '바람을 불어넣은 양가죽을 나무틀에 묶어 만든 뗏목은 수백 년 동안 황허에서 짐과 사람을 실어 날랐어요. 오늘날 이 전통 뗏목은 란저우 강변에서 방문객들을 태우고 있는데, 누런 강물 위를 미끄러지듯 떠가는 경험은 이 도시에서 가장 진짜배기 체험으로 꼽힌답니다.'),
  'urumqi/bazaar': ('국제대바자', '이슬람 건축에서 영감을 받은 탑과 돔 지붕의 상가가 어우러진 우루무치 대바자르는 실크로드 무역의 정취를 그대로 간직하고 있어요. 좌판마다 말린 과일과 향신료, 비단, 수제 칼이 넘쳐 나고, 저녁이 되면 광장은 음악과 춤 공연으로 활기를 띤답니다.'),
  'urumqi/tianshan': ('천지', '톈산산맥의 눈 덮인 보거다봉 아래 자리한 톈츠, 즉 \'하늘 호수\'는 짙푸른 물빛으로 유명해요. 가문비나무 숲에 둘러싸인 이 호수는 전설 속에서 서왕모가 연회를 베풀던 곳으로 전해지며, 유네스코 세계유산인 톈산산맥의 일부이기도 해요.'),
  'urumqi/kebab': ('양꼬치', '숯불 위에서 지글지글 익는 양꼬치에는 쯔란과 고춧가루가 뿌려지고, 그 훈연 향이 우루무치의 거리를 가득 채워요. 위구르 요리의 상징인 양꼬치는 화덕에서 갓 꺼낸 난과 진하게 우린 차를 곁들여 야시장에서 즐길 때 가장 맛있답니다.'),
  'urumqi/dance': ('위구르 전통춤', '북과 러왑, 두타르의 선율에 맞춰 빙글빙글 도는 위구르 춤은 결혼식과 축제의 꽃이에요. 우아한 손동작과 점점 빨라지는 회전이 어우러진 이 춤은 함께 나누는 흥겨운 문화라서, 손님들도 어김없이 원 안으로 이끌려 춤에 동참하게 된답니다.'),
  'haikou/coconut': ('코코넛 시티', '하이난섬의 성도 하이커우에서는 거리마다 코코넛야자가 그늘을 드리우고 있어서, 이 도시는 \'예청\', 즉 \'코코넛의 도시\'라고 불려요. 노점상이 큰 칼로 시원한 코코넛을 쩍 갈라 건네주는 코코넛 워터 한 잔은 열대의 더위를 식혀 주는 가장 자연스러운 처방이랍니다.'),
  'haikou/arcade': ('치러우 거리', '하이커우의 옛 상업 거리에는 동남아시아에서 돌아온 화교 상인들이 지은 아케이드식 \'치러우\' 건물들이 늘어서 있어요. 1층이 그늘진 아치형 통로를 이루는 이 건물들은 열대의 비와 뙤약볕을 막아 주며, 약 한 세기 동안 쇼핑을 한결 즐겁게 해 주었답니다.'),
  'haikou/crater': ('화산 공원', '하이커우 바로 외곽의 화산 지대는 사화산 분화구와 용암 동굴이 있는 푸르른 지질공원으로 변신했어요. 아주 오래전 분출이 남긴 현무암은 지금도 마을 집과 밭담에 쓰이고 있고, 방문객은 걸어서 분화구 입구까지 직접 내려가 볼 수도 있답니다.'),
  'haikou/turtle': ('열대 바다', '하이난 연안의 따뜻하고 맑은 바다는 산호초와 해초 초원이 어우러진 풍요로운 생태계를 품고 있어요. 바다거북은 이 해안에서 먹이를 찾고 알을 낳는데, 보호 프로젝트 덕분에 새끼 거북들이 파도를 향해 달려가는 모습이 다시 희망을 주는 풍경이 되었답니다.'),
  'luoyang/grotto': ('룽먼 석굴', '이허강 양쪽 절벽에 새겨진 룽먼석굴은 수만 점의 불상을 간직한 유네스코 세계유산이에요. 북위 시대에 시작되어 당나라 때 절정에 이른 조각들 가운데 가장 웅장한 것은, 잔잔한 미소를 머금은 거대한 비로자나 대불이랍니다.'),
  'luoyang/peony': ('모란의 도시', '당나라 이래로 뤄양은 모란과 하나로 여겨져 왔어요. 전설에 따르면 측천무후가 한겨울에 꽃을 피우라고 명령했을 때 유일하게 따르지 않은 꽃이 모란이었고, 그 벌로 이곳에 유배되었다고 해요. 해마다 4월이면 모란 축제로 도시가 색의 향연에 물들고, \'꽃의 왕\'이 왕관을 쓴답니다.'),
  'luoyang/whitehorse': ('백마사', '서기 68년에 세워진 백마사는 중국 최초의 불교 사원으로 여겨져요. 인도에서 불경을 등에 싣고 왔다고 전해지는 흰 말에서 이름을 따왔죠. 불교가 중국에 전해진 순간을 상징하는 이 사원은 오늘날에도 활발한 예배와 순례의 장소랍니다.'),
  'luoyang/capital': ('고도', '뤄양은 한나라와 당나라를 포함해 열세 개 왕조의 수도로서 중국 역사의 중심에 서 있었어요. 황허 유역의 이 고도(古都)는 실크로드의 동쪽 종착지 중 하나였고, 박물관과 유적들이 수천 년에 걸친 제국의 기억을 고이 간직하고 있답니다.'),
  'shantou/gongfutea': ('쿵푸차', '차오산 지역의 궁푸차는 아주 작은 찻잔에 차를 여러 번 우려 따르는 격식 있는 차 예술이에요. 이곳에서 손님에게 차를 대접하는 일은 존경을 표현하는 가장 깊은 방식이고, 석 잔을 놓는 다기 배치와 섬세한 손동작은 대를 이어 정성스럽게 전해지고 있어요.'),
  'shantou/beefpot': ('소고기 훠궈', '차오산 소고기 훠궈는 신선함에 대한 헌신으로 유명해요. 당일 잡은 소고기를 부위별로 나누고, 맑은 육수에 단 몇 초 단위로 데쳐 먹지요. 부위마다 정해진 익힘 시간이 따로 있고, 고소한 사차 소스에 살짝 찍으면 고기 본연의 단맛이 한층 살아난답니다.'),
  'shantou/opera': ('차오쥐', '수백 년의 역사를 지닌 차오저우 가극은 차오저우 방언으로 부르는 우아한 선율과 눈부신 자수 의상으로 유명해요. 해외로 이주한 차오산 사람들과 함께 동남아시아 곳곳으로 퍼져 나간 이 무대 예술은, 여러 세대에 걸쳐 공동체의 정체성을 이어 주었답니다.'),
  'shantou/harbor': ('산터우항', '19세기에 대외 무역에 문을 연 산터우 항구는 수많은 차오산 사람들이 바다 건너로 이주해 나간 관문이 되었어요. 오늘날 동남아시아의 많은 화교 가족들이 이곳에 뿌리를 두고 있고, 이민자들이 고향에 보낸 \'차오피\' 편지들이 그 인연을 증언하고 있답니다.'),
  'baoding/mansion': ('직례총독부', '즈리 총독 관저는 청나라 때 수도를 둘러싼 즈리성을 다스리던 총독들의 집무처였어요. 리훙장과 위안스카이 같은 권력자들이 이곳에서 근무했지요. 잘 보존된 안뜰과 대청을 지닌 이 관저는 제국 시대 지방 통치의 살아 있는 기록이랍니다.'),
  'baoding/donkeyburger': ('뤼러우훠사오', '\'뤼러우훠사오\', 즉 당나귀 고기 샌드위치는 오래 조린 향신료 고기를 화덕에서 갓 꺼낸 바삭한 빵에 채워 만들어요. \'하늘에는 용고기, 땅에는 당나귀 고기\'라는 이 지역 속담이 말해 주듯, 바오딩에서 가장 유명한 길거리 음식이자 지역의 뜨거운 자랑거리랍니다.'),
  'baoding/balls': ('바오딩 철구', '손바닥 위에서 굴리는 금속 바오딩 건강구는 명나라 때부터 만들어 온 전통 손 운동 도구예요. 공 안의 울림판이 돌아가면서 하나는 높고 하나는 낮은 두 가지 음을 내는데, 꾸준히 사용하면 손가락의 유연성과 차분하고 집중된 마음을 함께 길러 준다고 믿는답니다.'),
  'baoding/reeds': ('바이양뎬', '중국 북부 최대의 습지 중 하나인 바이양뎬은 갈대숲 수로로 이어진 수백 개의 호수와 못으로 이루어져 있어요. 여름이면 연꽃이 만발하고 갈대밭은 새소리로 가득한데, 마을 사람들은 지금도 좁은 배를 타고 갈대를 베고 고기를 잡아요. 그래서 이곳은 \'북방의 진주\'라고 불린답니다.'),
  'jilin/rime': ('지린 무송', '겨울밤이면 얼지 않는 쑹화강에서 피어오른 수증기가 강가 나뭇가지에 내려앉아 수정처럼 하얀 상고대로 변해요. \'우쑹\'이라 불리는 이 현상은 중국 4대 자연 절경 중 하나로 꼽히고, 아침 햇살에 은빛으로 반짝이는 나무들은 동화 속 한 장면 같은 풍경을 선사한답니다.'),
  'jilin/snowboard': ('지린 스키장', '길고 눈 많은 겨울 덕분에 지린은 중국을 대표하는 겨울 스포츠 지역 중 하나예요. 주변 산에 들어선 현대적인 리조트들은 보송보송한 파우더 스노로 스키어와 스노보더들을 불러 모으고, 이 지역은 중국 동계 스포츠 선수들의 상당수를 길러 냈답니다.'),
  'jilin/meteorite': ('지린 운석 박물관', '1976년 지린 하늘에서 운석이 쪼개지면서, 기록상 가장 큰 석질 운석우 중 하나가 쏟아졌어요. 1톤이 넘는 거대한 본체는 지금 이 도시의 운석 박물관에 전시되어 있어서, 방문객들은 우주에서 온 이 손님과 얼굴을 마주할 수 있답니다.'),
  'jilin/skate': ('쑹화강 빙상장', '겨울이 오면 쑹화강의 잔잔한 구간이 두껍게 얼어붙어 시민들의 야외 스케이트장으로 변신해요. 스케이터들이 미끄러지듯 지나가고, 얼음 위에서 팽이가 돌고, 아이들은 썰매 경주를 벌이죠. 추운 계절이면 강변은 지린에서 가장 흥겨운 만남의 장소가 된답니다.'),
  'ordos/khan': ('칭기즈칸 능', '오르도스 초원에 자리한 칭기즈 칸 능은 몽골 게르 모양의 세 개의 큰 돔 아래 위대한 칸을 기리는 성소예요. 다르하드 수호인들이 수백 년째 이곳에서 의식의 불과 제물을 지켜 오고 있으며, 이 능은 몽골 문화에서 가장 신성한 장소 중 하나로 꼽힌답니다.'),
  'ordos/cashmere': ('오르도스 캐시미어', '오르도스 초원의 혹독한 겨울을 견뎌 낸 염소들의 부드러운 속털에서는 세계 최고 품질의 캐시미어가 나와요. \'부드러운 금\'이라 불리는 이 섬유 덕분에 오르도스는 세계 캐시미어 생산의 중심지가 되었고, 유목의 전통은 현대적인 럭셔리 산업으로 다시 태어났답니다.'),
  'ordos/sanddune': ('샹사완', '쿠부치 사막의 거대한 모래언덕은 미끄러져 내려갈 때 깊은 웅웅 소리를 내서 \'노래하는 모래\'라고 불려요. 방문객들은 낙타 카라반을 타고 사구를 건너거나 샌드보드를 즐기는데, 저녁 해가 모래를 황금빛으로 물들이면 사막은 고요한 한 편의 시가 된답니다.'),
  'ordos/yurt': ('몽골식 게르', '하얀 펠트로 감싼 둥근 몽골 게르는 초원의 바람을 견디면서도 쉽게 접어 옮길 수 있도록 지어졌어요. 문은 남쪽을 향하고, 한가운데의 화덕은 가족 생활의 심장이지요. 오르도스 초원의 게르에서 하룻밤 묵어 보는 것은 유목민의 환대를 맛보는 가장 멋진 방법이랍니다.'),
  'jining/confucius': ('공묘', '지닝에 속한 취푸는 위대한 성인 공자가 태어난 도시예요. 공자를 모신 사당과 후손들이 살던 저택, 그리고 숲으로 둘러싸인 가족 묘역이 함께 유네스코 세계유산으로 등재되어 있죠. 측백나무 우거진 안뜰과 오래된 비석들은 2천 년 넘게 이어진 존경의 조용한 증인이랍니다.'),
  'jining/barge': ('징항 대운하', '베이징과 항저우를 잇는 대운하의 분주한 항구였던 지닝은 수백 년 동안 곡물 바지선과 상인들로 북적였어요. 운하 무역은 이 도시에 부와 활기찬 부두 문화를 가져다주었고, 이 거대한 물길의 남쪽 구간에서는 오늘날에도 화물이 오가고 있답니다.'),
  'jining/sword': ('양산박', '고전 소설 \'수호전\'에서는 억울한 일을 당한 108명의 호걸이 늪지로 둘러싸인 양산의 산채에 모여들어요. 송강이 이끄는 이 의적들은 포악한 권력자에 맞서 가난한 백성 편에서 싸우지요. 오늘날 양산은 소설 속 명장면들을 되살린 문화 명소로 방문객을 맞이하고 있답니다.'),
  'jining/fishnet': ('웨이산호', '중국 북부 최대의 담수호 중 하나인 웨이산호는 여름이면 지평선까지 펼쳐지는 연꽃밭으로 뒤덮여요. 어부 가족들은 대대로 전해 내려온 방식으로 그물을 던지며 호수의 리듬에 맞춰 살아가고, 이 지역 식탁에서는 신선한 생선과 아삭한 연근이 최고의 대접을 받는답니다.'),
  'langfang/culture': ('실크로드 문화센터', '베이징과 톈진 사이에 자리한 랑팡의 거대한 현대식 문화센터는 실크로드를 테마로 한 전시와 공연 예술, 공예를 한 지붕 아래 모아 놓았어요. 옛 카라반 길의 미학에서 영감을 받은 이 건물은, 두 대도시 사이에서 문화의 다리 역할을 하는 랑팡의 위상을 상징한답니다.'),
  'langfang/furniture': ('샹허 가구단지', '랑팡에 속한 샹허현은 중국 최대의 가구 생산·유통 중심지 중 하나예요. 몇 킬로미터씩 이어지는 매장과 공방에는 고전적인 자단목 가구부터 현대적인 디자인까지 온갖 스타일이 다 있어서, 중국 북부에서 새집을 꾸미는 많은 가족들이 이곳으로 발걸음을 옮긴답니다.'),
  'langfang/tunnel': ('고대 지하 군사 터널', '송나라와 북쪽의 요나라가 맞닿아 있던 옛 국경 지대에는 방어를 위해 땅속에 비밀 땅굴망이 파여 있었어요. 약 천 년을 버텨 온 이 벽돌 통로들은 환기구와 매복용 방까지 갖추고 있어서, 옛 국경 전쟁의 지하 증인이 되어 주고 있답니다.'),
  'langfang/themepark': ('제1성 테마파크', '\'톈샤디이청\', 즉 \'천하제일성\'은 옛 베이징의 성벽과 성문을 웅장하게 재현한 대형 테마파크예요. 사원 장터와 전통 공연, 고전 건축이 어우러진 이곳에서 가족들은 제국 시대의 수도로 시간 여행을 떠날 수 있답니다.'),
  'yancheng/salt': ('옌청', '옌청이라는 이름은 \'소금의 도시\'라는 뜻이에요. 해안의 염전은 수백 년 동안 황실의 곳간을 채워 주었죠. 바닷물을 햇볕에 증발시켜 얻은 소금이 이 도시의 운명을 결정지었고, 그 유산은 오늘날 박물관과 지명 곳곳에 살아 숨 쉬고 있답니다.'),
  'yancheng/crane': ('단정학', '옌청의 해안 습지는 야생 두루미(단정학)의 세계 최대 월동지예요. 중국 문화에서 장수와 기품의 상징인 이 우아한 새들은 겨울마다 북쪽에서 이곳으로 날아오는데, 갈대밭 위를 유유히 나는 모습이 자연을 사랑하는 이들의 마음을 사로잡는답니다.'),
  'yancheng/elk': ('다비드사슴', '사불상은 한때 중국 야생에서 자취를 감추고 해외의 공원에서만 명맥을 이어 가던 사슴이에요. 옌청의 다펑 보호구역으로 다시 들여온 뒤 개체 수가 크게 늘었고, 지금은 세계에서 가장 큰 사불상 무리가 이 해안 습초지를 자유롭게 누비고 있답니다. 보전이 이뤄 낸 값진 승리지요.'),
  'yancheng/wetland': ('해안 습지', '황해 연안의 갯벌은 유네스코 세계유산에 오른 거대한 철새 중간 기착지예요. 동아시아-대양주 이동 경로를 따라 나는 수백만 마리의 도요물떼새가 이곳에서 쉬고 먹이를 먹지요. 봄가을이면 갯벌이 온통 날갯짓 소리로 가득 찬답니다.'),
  'huzhou/brush': ('후저우 붓', '후저우에서 만드는 후비(湖筆)는 \'문방사보\'로 꼽히는 붓 가운데서도 가장 명성이 높아요. 염소, 토끼, 족제비 털을 수십 단계의 꼼꼼한 공정으로 다듬어 만든 붓끝은 뾰족하면서도 탄력이 있어서, 서예가들에게는 그 가치를 헤아릴 수 없는 보물이랍니다.'),
  'huzhou/bamboo': ('안지 죽림', '안지현의 언덕을 뒤덮은 대나무 숲은 바람에 일렁이는 끝없는 초록 바다 같아요. 영화 \'와호장룡\'의 잊지 못할 장면들이 촬영된 이 숲은 서늘한 공기와 산책로, 그리고 부드러운 죽순 요리로 방문객들에게 편안한 쉼을 선사한답니다.'),
  'huzhou/silkworm': ('양잠', '타이후호 남쪽 기슭의 후저우는 수천 년 뽕나무 양잠의 심장부예요. 뽕밭과 양어장을 하나로 엮은 전통 생산 방식은 오늘날 세계중요농업유산으로 인정받고 있고, 후저우 비단은 역사 속에서 황제와 궁정의 옷감이 되어 주었답니다.'),
  'huzhou/whitetea': ('안지 백차', '안지 백차는 사실 녹차예요. 봄에 돋는 잎이 거의 하얗게 보일 만큼 옅은 빛을 띠는 희귀한 품종으로 만들지요. 떫은맛이 적고 달콤하며 신선한 맛으로 차 애호가들의 사랑을 받는데, 아주 짧은 수확기 덕분에 중국에서 가장 구하기 어려운 차 중 하나가 되었답니다.'),
  'quzhou/go': ('바둑', '전설에 따르면 한 나무꾼이 란커산에서 두 신선이 바둑 두는 모습을 넋 놓고 구경하다가 세월이 흐르는 줄도 몰랐고, 도끼 자루가 썩어 버렸다고 해요. 이 이야기 덕분에 취저우는 바둑의 성지로 여겨지며, 이 오래된 전략 게임이 도시 곳곳에서 뜨겁게 사랑받고 있답니다.'),
  'quzhou/peaks': ('장랑산', '장랑산의 거대한 바위 기둥 세 개는 푸른 숲을 뚫고 하늘을 향해 곧게 솟아 있어요. \'단샤\'라 불리는 붉은 사암 지형의 빼어난 사례로 유네스코 세계유산에 등재되어 있고, 기둥 사이의 좁은 협곡을 걸어 지나가는 경험은 아찔할 만큼 짜릿하답니다.'),
  'quzhou/ponkan': ('취저우 폰칸(만다린)', '취저우의 온화한 구릉지에서 자라는 폰칸 귤은 잘 벗겨지는 껍질과 꿀처럼 달콤한 과육으로 유명해요. 늦가을이 되면 과수원이 온통 주황빛으로 물들지요. 수확철이면 가족들이 나무 사이에 모여들고, 이 귤은 겨울 식탁의 즐거움이 된답니다.'),
  'quzhou/cake': ('샤오빙(구운 납작빵)', '취저우의 화덕빵은 발효 반죽을 뜨거운 화덕 안쪽 벽에 붙여 구워 만들어요. 참깨를 입힌 바삭한 껍질 속에는 짭조름한 소가 숨어 있죠. 아침마다 빵집 앞에 줄을 서는 사람들에게 이 빵 한 개는 하루의 가장 근사한 시작이랍니다.'),
  'huainan/tofu': ('두부의 발상지', '전설에 따르면 두부는 한나라 때 회남왕 유안의 연금술사들이 바궁산에서 두유를 응고시키면서 태어났다고 해요. 약 2천 년 전 이곳에서 발명된 이 소박한 음식은 세계 요리로 퍼져 나갔고, 화이난은 해마다 두부 축제를 열어 그 유산을 기념하고 있답니다.'),
  'huainan/coalmine': ('석탄 도시', '풍부한 석탄층 위에 세워진 화이난은 오랫동안 중국 동부의 에너지 기지 역할을 해 왔어요. 광산과 발전소가 지역에 전기를 공급하는 한편, 이 도시는 옛 채굴지를 호수와 공원으로 바꾸며 산업 유산을 더 푸른 미래로 이끌어 가고 있답니다.'),
  'huainan/oldtown': ('서우현 고성', '서우현의 옛 성은 송나라 때 성벽이 온전히 남아 있는 중국에서도 보기 드문 도시예요. 두꺼운 벽돌 성벽과 아치형 성문은 홍수로부터도 도시를 지켜 주었죠. 성벽 안 옛 골목들에는 마지막 도읍을 이곳에 두었던 초나라의 흔적이 고스란히 남아 있답니다.'),
  'huainan/classic': ('회남자', '\'회남자\'는 한나라 때 회남왕 유안의 궁정에 모인 학자들이 엮은 철학 고전이에요. 도가 사상과 우주론, 통치술을 아우르는 이 책은, 여신 여와가 무너진 하늘을 메웠다는 이야기 같은 사랑받는 전설들도 오늘날까지 전해 주었답니다.'),
  'jingdezhen/porcelain': ('도자기의 수도', '징더전은 천 년이 넘도록 도자기를 구워 왔어요. 황실 가마의 중심지로서 가장 뛰어난 작품들을 궁정에 올려 보냈지요. 도자기의 원료인 고령토(카올린)라는 이름도 이곳 가오링 마을에서 나왔고, 오늘날에도 이 도시는 세계 곳곳의 도예가들을 끌어모으고 있답니다.'),
  'jingdezhen/kiln': ('고가마', '고요(古窯) 문화유산 단지에서는 장작으로 불을 때는 전통 가마와 공예 공방이 옛 기법을 지켜 가고 있어요. 산비탈을 따라 길게 뻗은 용요부터 달걀 모양 가마까지, 도자기가 불의 시험을 통과하는 과정을 지켜볼 수 있고, 장인들이 물레질과 유약 바르기를 눈앞에서 직접 보여 준답니다.'),
  'jingdezhen/bluewhite': ('청화백자', '새하얀 도자기의 유약 아래에 코발트 블루로 문양을 그려 넣는 \'칭화\', 즉 청화백자는 세계적으로 유명한 징더전의 인장이에요. 원나라와 명나라 때 완성된 이 양식은 실크로드와 바닷길을 따라 세계로 퍼져 나갔고, 유럽 궁정의 수집가들이 열정적으로 모아들였답니다.'),
  'jingdezhen/painting': ('도자기 회화', '징더전에서 도자기는 단순한 그릇이 아니라 캔버스예요. 장인들은 가장 가는 붓으로 산수와 새, 시 구절을 그려 넣지요. 유하채와 유상채 같은 기법은 대를 이어 전해지고, 장인의 낙관이 찍힌 작품은 그림처럼 소중히 수집된답니다.'),
  'jian/jinggang': ('징강산', '안개에 싸인 징강산은 1927년 중국 혁명의 첫 농촌 근거지가 세워진 곳이에요. 오늘날 \'붉은 관광\'의 심장부인 이 산은 역사 유적뿐 아니라 폭포와 대나무 숲, 봉우리 아래로 넘실대는 구름바다로 자연을 사랑하는 이들도 반갑게 맞이한답니다.'),
  'jian/torch': ('혁명의 불꽃', '\'작은 불씨 하나가 온 들판을 태울 수 있다\'는 말은 혁명이 이 산에서 전국으로 퍼져 나간 과정을 담고 있어요. 징강산 일대의 기념비와 박물관, 보존된 옛 지휘부들은 그 시절의 고된 투쟁을 기록하고 있고, 역사의 오솔길을 걷는 이들은 탁 트인 산악 풍경까지 함께 즐길 수 있답니다.'),
  'jian/academy': ('바이루저우 서원', '간장강 한가운데 섬 위에 송나라 때 세워진 바이루저우 서원은 수백 년 동안 학자들을 길러 냈어요. 민족 영웅 문천상도 이곳에서 공부했지요. 사방이 강물로 감싸인 고요한 안뜰은 중국 고전 교육 전통의 우아한 기억으로 남아 있답니다.'),
  'jian/pine': ('징강산 소나무', '징강산의 가파른 비탈에 뿌리내린 소나무들은 안개와 바람에도 아랑곳없이 꼿꼿이 서 있어요. 맨바위를 붙잡고 자라는 이 나무들은 끈기와 희망의 상징으로 여겨지죠. 해돋이 무렵 구름바다 위로 솟아오르는 소나무의 실루엣은 쉽게 잊히지 않는 장관이랍니다.'),
  'nanping/wuyi': ('우이산', '붉은 절벽과 푸른 골짜기, 그 사이를 굽이도는 맑은 시내가 어우러진 우이산은 자연과 문화 두 분야 모두에서 유네스코 세계유산으로 등재되었어요. 오래된 암벽 각석과 계단식 차밭, 주희의 서원 유적까지 더해져, 이 산은 중국 사상사의 한 페이지이기도 하답니다.'),
  'nanping/rocktea': ('암차', '우이산 절벽의 미네랄이 풍부한 흙에서 자라는 \'암차\' 우롱차의 왕은 다훙파오, 즉 \'큰 붉은 도포\'예요. 암벽 위 수백 년 된 모수(어미 나무)에서 딴 찻잎은 전설적인 가격에 거래되었고, 그 깊고 구수한 홍배 향은 차의 세계에서 큰 존경을 받고 있답니다.'),
  'nanping/bambooraft': ('구곡계 뗏목', '주취시, 즉 \'아홉 굽이 시내\'는 우이산의 붉은 절벽 사이를 아홉 번 크게 굽이돌며 흘러요. 대나무 뗏목에 올라 사공이 긴 장대로 저어 가는 물길을 따라가다 보면, 절벽 높이 안치된 신비로운 옛 배 모양 관과 굽이마다 달라지는 풍경을 감상할 수 있답니다.'),
  'nanping/scholar': ('주희', '성리학의 큰 스승 주희는 생애의 많은 시간을 우이산 자락에서 보내며 서원을 세우고 제자들을 가르쳤어요. 유교 사상을 새롭게 해석한 그의 학문은 수백 년 동안 중국과 동아시아의 교육과 과거 제도를 빚어냈답니다.'),
  'shenzhen/skyscraper': ('마천루', '40년 전만 해도 어촌이었던 선전은 중국 최초의 경제특구로 지정되면서 마천루의 숲으로 변했어요. 구름을 찌를 듯한 핑안 타워가 우뚝 선 스카이라인은 개혁 시대의 속도를 상징하죠. 하룻밤 사이에 건물이 한 층씩 올라간다는 \'선전 속도\'라는 말이 있을 정도랍니다.'),
  'shenzhen/chip': ('테크 시티', '화창베이 전자 상가에서는 칩과 기판, 드론 부품이 가게에서 가게로 쉴 새 없이 오가요. 텐센트, 화웨이, DJI 같은 거대 기업들이 바로 이 도시에서 자랐죠. \'중국의 실리콘밸리\' 선전에서는 아이디어가 며칠 만에 시제품이 되는데, 그래서 이곳은 하드웨어 스타트업의 세계 수도로 불려요.'),
  'shenzhen/miniature': ('세계지창', '테마파크 \'세계의 창\'은 에펠탑부터 피라미드까지 세계의 유명 건축물을 미니어처로 한자리에 모아 놓았어요. 오후 한나절이면 여러 대륙을 걸어서 여행할 수 있죠. 밤이 되면 공원의 \'에펠탑\'에 불이 켜지는데, 선전의 장난기 넘치고 야심 찬 정신을 그대로 보여 준답니다.'),
  'shenzhen/mangrove': ('선전만', '마천루 아래로 펼쳐진 선전만의 맹그로브 숲은 철새들의 이동 경로에서 중요한 쉼터예요. 백로와 물새들이 갯벌에서 먹이를 찾는 동안, 해안 공원의 산책로는 도시인들에게 자연과 대도시가 나란히 서 있는 보기 드문 풍경을 선물해요.'),
  'xian/terracotta': ('병마용', '진시황의 무덤을 지키는 수천 명의 병마용은 1974년 우물을 파던 농민들이 우연히 발견했어요. 병사들의 얼굴은 하나하나 다 다르죠. 말없이 줄지어 선 이 군대는 불멸을 꿈꾼 황제의 힘을 보여 주며, 세계 8대 불가사의라고도 불린답니다.'),
  'xian/citywall': ('시안 성벽', '시안의 명나라 성벽은 중국에서 가장 온전하게 남은 성벽으로, 육중한 몸체가 옛 시가지를 끊김 없는 직사각형으로 감싸고 있어요. 자전거를 빌려 성벽 위를 한 바퀴 도는 건 시안의 클래식한 체험이죠. 망루에서 내려다보면 현대 도시와 고대 수도가 한 화면에 담겨요.'),
  'xian/drumtower': ('종루', '도시 한복판에 우뚝 선 명나라 시대 종루는 옛 수도의 심장을 표시해요. 예전에는 종소리로 하루의 시간을 알렸답니다. 바로 옆의 고루, 그리고 그 뒤로 이어지는 회족 거리의 먹자골목과 함께 시안의 밤에서 가장 활기찬 광장을 이루고 있어요.'),
  'xian/roujiamo': ('러우자모', '바삭한 빵 안에 향신료와 함께 오랜 시간 푹 삶은 고기를 채워 넣어서, 러우자모는 \'중국식 햄버거\'라고 불려요. 산시(陝西) 길거리 음식의 이 유서 깊은 한 입은 실크로드 수도의 분주함에 꼭 어울리죠. 한 손에 들고 두어 입 베어 물면 천 년의 맛 전통과 이어진답니다.'),
  'suzhou/garden': ('졸정원', '쑤저우의 고전 정원은 가산과 연못, 정자로 좁은 공간 안에 자연을 다시 빚어낸 걸작이에요. 가장 훌륭한 정원들은 유네스코 세계문화유산에 올라 있죠. 창문 하나하나가 그림처럼 구도가 잡혀 있어서, 정원을 거니는 일은 걸음마다 달라지는 두루마리 그림을 펼치는 것 같아요.'),
  'suzhou/watertown': ('수향마을', '운하와 아치형 돌다리, 하얀 회벽 집들이 어우러진 쑤저우는 \'동양의 베네치아\'라고 불려요. 핑장루 같은 옛 골목에서는 물이 집 문 앞을 바로 스치며 흐르죠. 배를 타고 미끄러져 가다 보면 찻집에서 비파 소리와 지역 민요 가락이 들려온답니다.'),
  'suzhou/embroidery': ('쑤저우 자수', '쑤저우 자수는 머리카락보다 가는 실로 비단 위에 수를 놓는 천 년 역사의 공예예요. 최고의 장인들은 한 천의 앞뒤 양면에 서로 다른 그림을 수놓을 수 있죠. 고양이 털의 윤기나 물고기 비늘까지 바늘로 담아내는 이 예술은 이 도시의 인내와 섬세함을 상징해요.'),
  'suzhou/kunqu': ('쿤취', '모든 중국 전통극의 어머니로 불리는 쿤취는 쑤저우 일대에서 태어났어요. 물 흐르듯 이어지는 선율과 우아하게 다듬어진 손동작으로 유명하죠. 유네스코 인류무형문화유산에 오른 이 예술은 지금도 정원의 정자와 아담한 극장에서 공연되고 있답니다.'),
  'kunming/stoneforest': ('스린', '수백만 년 동안 물이 깎아 만든 거대한 석회암 기둥들이 쿤밍 근처에 스린, 즉 \'돌의 숲\'이라 불리는 미로를 이루고 있어요. 이 지역의 사니족은 이 바위들을 아스마 전설로 이야기하죠. 돌로 변한 아름다운 처녀가 지금도 유명한 기둥 하나의 모습으로 방문객을 맞이한답니다.'),
  'kunming/springcity': ('춘성', '높은 윈난 고원의 온화한 기후 덕분에 겨울은 포근하고 여름은 시원해요. 그래서 쿤밍은 꽃이 지지 않는 \'봄의 도시\'라고 불리죠. 아시아 최대급 꽃 시장이 이곳에 있고, 길모퉁이에서도 싱싱한 꽃다발을 판답니다.'),
  'kunming/seagull': ('붉은부리갈매기', '겨울마다 시베리아에서 날아온 수천 마리의 붉은부리갈매기가 쿤밍의 호숫가와 도시 공원을 하얗게 물들여요. 손으로 직접 먹이를 주는 건 시민들이 사랑하는 겨울 의식이죠. 갈매기들의 귀환은 쿤밍에서 거의 하나의 계절 소식처럼 반겨진답니다.'),
  'kunming/ricenoodle': ('궈차오미셴', '궈차오미셴, 즉 \'다리를 건너는 쌀국수\'는 윈난의 대표 요리예요. 펄펄 끓는 육수가 식탁에 오르면 가는 쌀국수와 고명을 눈앞에서 그릇에 더해 완성하죠. 전설에 따르면 한 아내가 다리 건너에서 공부하는 남편에게 밥을 나르며 국물을 뜨겁게 유지하는 이 방법을 생각해 냈다고 해요.'),
  'jinan/spring': ('천성', '지난에서는 지하수가 도시 한복판에서 보글보글 솟아올라요. 유명한 72개 샘 가운데 으뜸은 힘차게 솟구치는 바오투취안이죠. \'샘의 도시\'에서는 오래된 동네 골목 사이로도 맑은 물이 흐르고, 주민들은 지금도 샘물로 차를 우리는 걸 자랑으로 여긴답니다.'),
  'jinan/daminglake': ('다밍후', '샘물이 모여 이룬 다밍호는 버드나무와 연꽃으로 둘러싸인 도심 속 오아시스예요. 여름이면 활짝 핀 연꽃밭 사이로 배들이 미끄러지듯 오가죠. 호숫가의 정자와 찻집들은 중국 문학에도 기록된 지난 특유의 느긋하고 우아한 삶의 리듬을 이어 가고 있어요.'),
  'jinan/buddhamountain': ('첸포산', '첸포산(천불산)의 산비탈에는 수백 년에 걸쳐 수백 개의 불상이 새겨졌어요. 가장 오래된 마애불은 수나라 때까지 거슬러 올라가죠. 산길을 오르면 돌 감실 속 불상들과 함께, 정상에서 샘의 도시 지난이 한눈에 내려다보이는 전망까지 만날 수 있답니다.'),
  'jinan/poet': ('리칭자오', '중국 최고의 여성 시인으로 꼽히는 이청조는 송나라 때 이 샘의 도시에서 태어났어요. 섬세하고 애잔한 그녀의 사(詞)는 사랑과 유랑, 상실을 노래하죠. 바오투취안 옆의 기념관은 그 시들이 태어난, 물소리 가득한 세계를 오늘까지 전해 주고 있어요.'),
  'ningbo/library': ('톈이거', '명나라 때 세워진 톈이거는 아시아에서 가장 오래된 개인 도서관이에요. 책을 사랑한 관료가 세웠죠. 귀한 필사본을 습기와 불로부터 지키기 위해 정원과 연못, 출입을 엄격히 제한하는 가문의 규칙까지 갖춰, 마치 책의 사원처럼 설계되었답니다.'),
  'ningbo/port': ('닝보-저우산항', '닝보-저우산항은 화물 물동량 기준으로 세계에서 가장 붐비는 항구예요. 거대한 컨테이너선과 우뚝 솟은 크레인들이 해안을 기계의 숲으로 만들죠. 닝보의 뱃길 역사는 아주 깊어서, 이 도시는 고대 해상 실크로드의 출발 관문 중 하나였답니다.'),
  'ningbo/tangyuan': ('탕위안', '닝보식 탕위안은 달콤한 깨소를 채운 매끈한 찹쌀 경단이에요. 한 입 베어 물면 따뜻한 소가 작은 서프라이즈처럼 흘러나오죠. 위안샤오제(등불 축제)의 대표 간식인 이 경단은 동그란 모양으로 가족의 화합과 재회를 상징한답니다.'),
  'ningbo/seafood': ('해산물', '동중국해를 마주한 닝보의 식탁은 바다에서 차려져요. 조기와 게, 조개류가 이곳 요리의 뼈대죠. 이 고장 입맛은 \'짭짤하면서도 신선한\' 균형을 최고로 쳐서, 생선 본연의 맛을 덮지 않는 담백한 찜과 가벼운 절임이 이 요리의 시그니처예요.'),
  'shijiazhuang/bridge': ('자오저우교', '수나라 때 장인 이춘이 세운 자오저우교는 세계에서 가장 오래된 개복식 아치 구조의 돌다리예요. 약 1,400년 동안 홍수와 지진을 견뎌 왔죠. 이 우아한 아치는 중국 공학의 고전 걸작으로 교과서에도 실려 있답니다.'),
  'shijiazhuang/clifftemple': ('창옌산', '창옌산에는 두 절벽 사이에 매달린 듯한 돌다리 위에 사원이 서 있는데, 중국에서 가장 아찔한 풍경 중 하나예요. 푸른 골짜기에서 가파른 돌계단을 올라야 닿을 수 있죠. 영화 \'와호장룡\'의 마지막 장면 배경이 된 곳이기도 해요.'),
  'shijiazhuang/redbase': ('시바이포 혁명 유적지', '스자좡 근처의 시바이포 마을은 내전의 마지막 시기에 혁명 사령부였어요. 새로운 중국의 건국 계획이 이곳 흙벽 안마당에서 세워졌죠. 지금은 \'홍색 관광\'의 성지 중 하나로, 소박한 시골집들이 역사의 큰 결정들을 증언하고 있답니다.'),
  'shijiazhuang/pharma': ('제약 도시', '스자좡은 중국 최대의 의약품 생산 중심지 중 하나예요. 특히 항생제와 원료 의약품으로 \'약의 도시\'라고 불리죠. 철도 교차점으로 성장한 이 젊은 성도는 공업 도시의 정체성에 제약과 현대 제조업을 버무려 가고 있어요.'),
  'taiyuan/jincitemple': ('진사', '타이위안 외곽의 진츠 사원은 신성한 샘과 수백 년 된 측백나무, 송나라 시대 시녀상들을 품은 북중국에서 가장 우아한 사원 정원이에요. 목조 성모전에 모셔진 시녀상들은 저마다 표정이 다르죠. 마치 천 년 동안 소곤소곤 이야기를 나눠 온 것 같답니다.'),
  'taiyuan/coalcart': ('석탄의 도시', '산시(山西)의 산들은 석탄 광맥으로 가득하고, 중국 에너지의 상당 부분이 여기서 캐내져요. 타이위안은 바로 그 부의 수도죠. 광업은 도시에 공업과 철도, 중장비 문화를 안겨 주었고, 오늘날 타이위안은 석탄 유산과 청정에너지 사이에서 균형을 찾아가고 있어요.'),
  'taiyuan/vinegar': ('라오천추(산시 식초)', '산시의 노숙성 식초는 수수와 곡물을 오랫동안 천천히 발효시켜 만들어요. 짙은 색과 훈연 향이 감도는 새콤함으로 식탁의 주인공 대접을 받죠. 이곳 사람들은 국수부터 만두까지 모든 음식에 식초를 둘러 먹는데, 여기서 식초는 양념이 아니라 거의 정체성에 가깝답니다.'),
  'taiyuan/twinpagoda': ('쌍탑', '도시 남동쪽에 나란히 솟은 두 개의 팔각 명나라 전탑은 수백 년째 변함없는 타이위안의 상징이에요. 벽돌을 쌓아 올린 탑신은 조적 공예의 섬세함을 보여 주죠. 봄이면 탑 주위를 둘러싼 매화가 여행에서 가장 사진 찍기 좋은 순간을 선사한답니다.'),
  'hohhot/lamatemple': ('다자오 사원', '명나라 때 세워진 다자오 사원은 후허하오터의 정신적 심장이에요. 가장 큰 보물은 은으로 만든 불상이죠. 초원 위 티베트 불교의 이 중심지는 향 연기와 마니차, 낮게 울리는 독경 소리에 싸여 도시의 소음과는 완전히 다른 세계를 보여 준답니다.'),
  'hohhot/dairy': ('유제품의 도시', '중국 최대의 유제품 브랜드들이 후허하오터에서 태어났어요. 초원의 젖 문화가 이곳에서 현대 산업으로 성장해, 도시는 \'우유의 수도\'라고 불리죠. 식탁 위에서는 밀크티와 말린 우유 과자, 크림 같은 몽골 별미들이 공장 제품들과 나란히 살아 숨 쉬고 있어요.'),
  'hohhot/wrestling': ('몽골 씨름', '몽골 씨름 뵈흐는 나담 축제의 꽃이에요. 씨름꾼들은 수놓은 조끼를 입고 독수리 춤을 추며 경기장에 들어서죠. 승자는 힘 못지않게 기품으로도 박수를 받는데, 초원에서 씨름은 말타기, 활쏘기와 함께 \'사나이의 세 가지 기예\'로 꼽힌답니다.'),
  'hohhot/prairie': ('초원', '후허하오터 바로 너머로 몽골 초원이 지평선까지 펼쳐져요. 여름이면 푸른 바다처럼 일렁이는 목초지에서 말 떼와 양들이 풀을 뜯죠. 게르에 묵는 손님들은 밀크티와 양고기 잔치로 환영받고, 밤이 되면 도시에서 잊고 지내던 별들이 하늘을 가득 채운답니다.'),
  'sanya/resortbeach': ('야롱완 해변', '하이난섬 남쪽 끝의 싼야는 중국의 열대 휴양 수도예요. 야룽만의 분처럼 고운 모래와 터키석빛 바다 덕분에 \'중국의 하와이\'라고 불리죠. 야자수가 늘어선 해변에는 일 년 내내 여름이 이어져서, 겨울에도 바다 수영을 즐길 수 있는 몇 안 되는 중국 해안이랍니다.'),
  'sanya/guanyin': ('남산 해상 관음상', '난산 앞바다 위로 솟은 108미터의 관음상은 세계에서 가장 높은 여신상 중 하나예요. 세 개의 얼굴이 각각 육지와 바다, 먼바다를 바라보고 있죠. 자비의 여신 발치까지 이어지는 둑길에는 순례자와 호기심 많은 여행자들이 함께 걸어요.'),
  'sanya/diving': ('스쿠버 다이빙', '따뜻하고 투명한 바다를 가진 싼야는 중국의 다이빙 천국이에요. 우즈저우섬 주변의 산호초에는 알록달록한 물고기가 가득하죠. 초보자도 강사와 함께 얕은 산호초에서 다이빙할 수 있고, 스노클만 있어도 수면 아래 열대 정원을 들여다볼 수 있답니다.'),
  'sanya/coconutdrink': ('코코넛', '싼야에서 코코넛은 일상의 한 부분이에요. 해변을 따라 상인들이 싱싱한 코코넛을 큰 칼로 쪼개 빨대를 꽂아 건네주죠. 시원한 코코넛 물은 열대 더위의 가장 자연스러운 처방이고, 밀크는 현지 닭 요리와 디저트에 향을 더하며, 껍데기는 수공예품으로 다시 태어난답니다.'),
  'yangzhou/slenderlake': ('서우시후(수서호)', '서우시후, 즉 \'날씬한 서호\'라는 이름은 항저우의 유명한 호수에 보내는 우아한 인사예요. 가늘고 긴 물길은 버드나무와 하얀 아치교, 정자들로 장식되어 있죠. 청나라 황제들이 남방 순행에서 감탄했던 이 풍경은 지금도 수묵화처럼 단아하답니다.'),
  'yangzhou/friedrice': ('양저우 볶음밥', '양저우 볶음밥은 새우와 달걀, 파를 넣고 밥알이 하나하나 살아 있게 볶아 낸 황금빛 클래식이에요. 그 이름은 전 세계 중식당에서 살아 숨 쉬죠. 비결은 단순함인데, 밥알마다 달걀을 입히고 재료는 신선하게 쓰되 절대 욕심내지 않는 거랍니다.'),
  'yangzhou/morningtea': ('자오차', '양저우의 하루는 \'아침 차\' 의식으로 시작돼요. 진하게 우린 차와 함께 찐빵, 종잇장처럼 얇게 채 썰어 낸 별미, 국물 가득한 만두가 상에 오르죠. 오래된 찻집에서 이 아침 식사는 몇 시간씩 이어지는데, 서두르는 건 거의 실례에 가깝답니다.'),
  'yangzhou/gegarden': ('거원', '부유한 소금 상인이 지은 거위안 정원은 대나무 잎 모양에서 이름을 따왔어요. 이 정원의 가장 유명한 볼거리는 서로 다른 돌로 사계절을 표현한 가산이죠. 몇 걸음 만에 봄에서 겨울까지 거닐며 고전 정원 예술의 정점을 만날 수 있답니다.'),
  'weihai/navalisland': ('류궁도', '웨이하이 앞바다의 류궁섬은 청나라의 근대 해군인 북양함대의 기지였어요. 함대는 이곳에서 일본 해군과의 전쟁에 패했죠. 지금 섬은 박물관과 옛 포대 유적을 통해 중국 해군사의 아프지만 교훈이 담긴 한 페이지를 들려준답니다.'),
  'weihai/swan': ('스완 레이크', '겨울마다 시베리아에서 날아온 수백 마리의 큰고니가 웨이하이 근처 해안 석호에 자리를 잡아요. 아침 안개 속을 미끄러지듯 헤엄치는 하얀 새들은 사진가와 자연 애호가들을 불러 모으죠. 마을 사람들은 고니를 이웃처럼 여기며 돌보고 먹이를 준답니다.'),
  'weihai/seacucumber': ('해삼', '웨이하이의 차고 깨끗한 바다에서 자라는 해삼은 중국 식탁에서 가장 귀한 진미 중 하나예요. 몸에 좋다고 여겨져 특별한 날의 대접이자 격식 있는 선물이 되죠. 해안을 따라 늘어선 해삼 양식장은 도시의 중요한 생계 수단이랍니다.'),
  'weihai/cape': ('중국 동단', '웨이하이 동쪽의 청산터우곶은 중국 땅이 바다와 만나는 가장 동쪽 끝자락 중 하나로, 해가 이 나라에서 가장 먼저 인사하는 곳이에요. 전설에 따르면 진시황이 여기까지 와서 바다 너머 불로장생의 땅을 찾았다고 하죠. 그래서 이 곶은 \'하늘이 끝나는 곳\'이라고도 불린답니다.'),
  'handan/taichi': ('태극권', '한단 근처의 성곽 마을 광푸는 태극권 양식(楊式)과 우식(武式)이 태어난 곳이에요. 전설적인 고수 양루찬이 바로 여기서 수련했죠. 아침이면 성벽 아래와 안마당에서 느리고 물 흐르는 듯한 동작을 연습하는 사람들이 이 \'부드러운\' 무술의 살아 있는 유산을 이어 가요.'),
  'handan/congtai': ('총대', '충타이 누대는 전국시대의 강국 조나라가 남긴 유적이에요. 왕들이 의식과 열병을 지켜보던 높은 단이 지금은 공원 한가운데 서 있죠. 누대에 오르면 고대 수도로서 2천 년이 넘는 한단의 역사가 한눈에 내려다보인답니다.'),
  'handan/idiom': ('성어의 도시', '한단은 \'성어의 도시\'예요. 1,500개가 넘는 중국 성어가 이 땅에서 벌어진 사건과 이야기에 뿌리를 두고 있거든요. 가장 유명한 것은 남의 걸음을 흉내 내다 제 걸음마저 잊어버린 사람을 뜻하는 \'한단지보\'인데, 이 성어가 도시의 이름을 언어 속에 영원히 새겨 놓았답니다.'),
  'handan/ciporcelain': ('자주요', '츠저우 도자기는 흰 분장토 위에 자유로운 붓질로 그려 낸 대담한 검은 무늬로 유명해요. 꽃과 물고기, 시구가 민간 예술 특유의 소박함으로 그릇에 담기죠. 송나라 때부터 이어진 이 전통은 궁중 도자기와 마주 선, 일상생활의 도자기로 자리하고 있답니다.'),
  'daqing/oilpump': ('유전', '다칭 유전의 발견은 젊은 중화인민공화국을 석유 수입 의존에서 벗어나게 해 주었어요. 도시는 그야말로 유정 위에서 자라났죠. 고개를 천천히 끄덕이는 채유기들이 지금도 벌판 곳곳에서 일하고 있고, 다칭은 중국 최대의 유전으로 역사에 이름을 남겼답니다.'),
  'daqing/oilworker': ('철인', '석유 노동자 왕진시는 살을 에는 추위 속에서 유정을 뚫어 낸 근성으로 \'철인\'이라는 별명을 얻었어요. 시추 사고 때 진흙 구덩이에 뛰어들어 온몸으로 이수를 저었다는 이야기가 전해지죠. 그의 이름을 딴 박물관과 \'철인 정신\'이 다칭의 건설 신화를 살아 있게 한답니다.'),
  'daqing/reedlake': ('습지', '유정들 사이에 놀라운 자연이 숨어 있어요. 다칭의 드넓은 갈대 호수와 습지는 두루미와 고니, 철새 물새들의 보금자리거든요. 가을이 되어 황금빛 갈대가 바람에 일렁이면, 이 공업 도시는 새들의 낙원으로 변신한답니다.'),
  'daqing/hotspring': ('온천', '다칭 주변에는 땅속 깊은 곳에서 솟아나는 뜨거운 광천수가 있어서, 추운 둥베이의 겨울에 몸을 녹이는 치유의 쉼터가 되어 줘요. 린뎬현은 온천 마을로 이름을 알렸죠. 김이 모락모락 나는 온천에 몸을 담그는 건 석유 도시의 혹독한 기후에 대한 달콤한 응답이랍니다.'),
  'zibo/bbq': ('쯔보 바비큐', '쯔보 바비큐는 세 가지 세트로 유명해요. 작은 숯불 화로, 가는 꼬치, 그리고 얇고 부드러운 전병이죠. 꼬치를 직접 마저 구운 뒤 쪽파와 소스를 곁들여 전병에 싸 먹는데, 이 정겨운 방식이 소셜미디어를 휩쓸며 하룻밤 사이에 도시를 전국적인 화제로 만들었답니다.'),
  'zibo/cuju': ('추쥐', '세계에서 가장 오래된 축구인 축국은 고대 제나라의 수도 린쯔에서 행해졌어요. FIFA도 이곳을 축구의 기원으로 인정하죠. 가죽 공을 발로 차 올리며 즐기던 이 놀이는 궁중 오락부터 군사 훈련까지 이어지는 풍부한 역사를 지니고 있답니다.'),
  'zibo/ceramic': ('쯔보 도자기', '쯔보의 가마는 천 년 넘게 불을 지펴 왔어요. 이 도시는 북중국에서 가장 뿌리 깊은 도자기 중심지 중 하나죠. 일상 그릇부터 예술 자기까지 이어지는 생산 전통은 오늘날 박물관과 공방에서 살아 숨 쉬고, 도자기 박람회는 전국의 장인들을 도시로 불러 모은답니다.'),
  'zibo/glass': ('류리', '색색의 녹인 유리를 손으로 빚는 류리는 빛과 노니는 쯔보의 공예예요. 보산 지역이 이 예술의 유서 깊은 중심지로 유명하죠. 장인들이 집게로 벌겋게 달아오른 유리를 당기고 구부리면, 구슬과 새, 꽃병이 태어나 햇빛 속에서 스테인드글라스처럼 반짝인답니다.'),
  'taian/mounttai': ('태산', '오악의 으뜸인 타이산은 중국에서 가장 신성한 봉우리예요. 황제들은 수백 년 동안 하늘에 자신의 통치를 고하는 제사를 이곳에서 올렸죠. 유네스코 유산인 이 산의 바위마다 시인과 서예가들의 글씨가 새겨져 있어서, 돌 하나하나가 역사의 한 페이지랍니다.'),
  'taian/sunrise': ('태산 일출', '타이산 등반의 가장 큰 보상은 정상에서 구름바다 위로 떠오르는 해를 보는 거예요. 수천 명이 밤새 산을 올라 옥황봉에서 새벽을 기다리죠. 지평선이 붉게 물드는 순간 사람들 사이에서 터져 나오는 환호성은 쌓인 피로를 한순간에 잊게 해 준답니다.'),
  'taian/stonesteps': ('태산 돌계단', '정상까지 이어지는 약 7,000개의 돌계단은 순례자들이 수백 년 동안 한 걸음씩 올라온 체력의 시험대예요. 가장 가파른 구간은 \'하늘로 오르는 열여덟 굽이\'라 불리는 십팔반이죠. 이 계단을 매일 오르내리며 짐을 나르는 짐꾼들은 이 산의 조용한 영웅들이랍니다.'),
  'taian/daitemple': ('다이묘', '산기슭의 다이먀오 사원은 황제들이 타이산 의식을 앞두고 머물며 준비하던 웅장한 사원 단지예요. 궁궐 양식의 본전은 타이산 신의 행차를 그린 거대한 벽화로 유명하죠. 안마당의 오래된 측백나무들은 역사의 산증인이랍니다.'),
  'lianyungang/monkey': ('화과산', '\'서유기\' 속 원숭이 왕 손오공의 고향, 꽃과 열매의 산 화과산이 바로 이곳에 솟아 있어요. 폭포 뒤로 들어가면 수렴동 동굴이 나타나죠. 바위 위를 뛰어다니는 진짜 원숭이들이 전설과 풍경의 경계를 흐려 놓는답니다.'),
  'lianyungang/seaport': ('롄윈강항', '롄윈강은 유라시아 대륙을 가로지르는 대륙횡단 철도의 태평양 쪽 끝이에요. 여기서 짐을 실은 기차들이 중앙아시아를 지나 유럽까지 달려가죠. 실크로드의 동쪽 바다 관문으로 불리는 이 항구는 고대 무역로의 현대판 연장선 같아요.'),
  'lianyungang/mountain': ('윈타이산', '윈타이산의 가파른 봉우리들은 장쑤성에서 가장 높은 지점을 품고 있어요. 낮은 평야로 유명한 이 성에서 이 산줄기는 놀라운 예외죠. 숲으로 덮인 비탈과 사원들, 바다가 내려다보이는 능선까지 갖춰, 도시 사람들의 자연 탈출구가 되어 준답니다.'),
  'lianyungang/crystal': ('수정의 고장', '롄윈강의 둥하이현에는 세계 최대급 수정 시장이 있어요. 이 땅에서 캐낸 맑은 수정은 보석부터 산업 원료까지 온갖 분야에 쓰이죠. 마을 시장의 좌판들은 반짝반짝 빛나는 돌로 가득 찬답니다.'),
  'maanshan/libai': ('이백', '중국 최고의 시인으로 꼽히는 이백은 말년을 이 강가 도시 부근에서 보냈어요. 그의 무덤은 가까운 당투에 있죠. 술과 달과 자유를 시로 빚어낸 대시인의 자취가 기념 공원에 살아 있고, 마안산은 스스로를 자랑스럽게 \'시의 도시\'라고 소개한답니다.'),
  'maanshan/steel': ('철강 도시', '마강 제철소는 마안산을 중국의 주요 철강 기지 중 하나로 만들었어요. 용광로들이 수십 년째 양쯔강 기슭에서 연기를 피워 올리죠. 이 도시는 한쪽에는 끓는 쇳물을, 다른 쪽에는 이백의 시를 두고 중공업의 정체성과 시적인 과거의 균형을 맞추고 있답니다.'),
  'maanshan/rivercliff': ('채석기', '양쯔강으로 곧장 떨어지는 차이스지 절벽은 이 강에서 가장 시적인 풍경 중 하나를 보여 줘요. 전설에 따르면 이백이 물에 비친 달을 안으려다 강에 빠져 불멸의 존재가 되었다고 하죠. 절벽 위의 정자와 오솔길들이 지금도 그 이야기를 속삭이고 있답니다.'),
  'maanshan/moonwine': ('이백의 달과 술', '이백의 시를 채운 두 가지 큰 이미지, 달과 술은 지금도 마안산에서 기려져요. 도시는 그를 기억하며 시 축제를 열죠. 강가에서 잔을 들고 달을 바라보는 건, 천 년 전 시인과 같은 감정을 나누는 가장 소박한 방법이랍니다.'),
  'longyan/tulou': ('융딩 토루', '융딩의 산속에 흩어져 있는 거대한 원형 토루는 하카족이 흙과 나무로 지은 요새 주택으로, 유네스코 세계문화유산이에요. 두꺼운 흙벽 안에서 수십 가구가 어우러져 살아가죠. 안마당에서 피어오르는 밥 짓는 연기에는 수백 년 공동체 생활의 향기가 배어 있답니다.'),
  'longyan/redmeeting': ('구톈 회의', '1929년 홍군의 원칙과 방향을 정한 역사적인 구톈 회의가 룽옌의 이 산골 마을에서 열렸어요. 하얀 회벽의 회의장은 오늘날까지 잘 보존되어 있죠. 마을은 혁명사의 전환점 하나를 직접 보려는 사람들의 발길이 이어지는 곳이랍니다.'),
  'longyan/hakka': ('객가 문화', '전란을 피해 북중국에서 남쪽으로 이주한 하카족은 \'손님 가족\'이라는 뜻의 이름을 그 여정에서 얻었어요. 룽옌의 산속에서 그들은 고유한 언어와 소금구이 닭 같은 음식, 그리고 강한 가족 유대를 수백 년째 지켜 오고 있답니다.'),
  'longyan/mountain': ('관즈산', '관즈산은 옛 관리의 모자를 닮았다는 붉은 바위 봉우리로 유명해요. 단샤 지형이라 불리는 이 붉은 절벽들은 맑은 못과 가파른 골짜기에 둘러싸여 있죠. 바위를 깎아 만든 계단과 호수 위 뱃놀이까지 갖춰, 이 산은 남부 푸젠의 자연 진주로 꼽힌답니다.'),
  'sanming/danxia': ('타이닝 단샤 지형', '푸젠성 북서부의 타이닝은 붉은 사암 절벽과 좁은 협곡, 동굴로 이루어진 유네스코 지질공원이에요. 물이 수백만 년에 걸쳐 깎아 만든 이 돌의 미로를 배로 둘러보며, 붉은 절벽 사이로 초록빛 물길이 미끄러지듯 흐르는 풍경을 감상할 수 있어요.'),
  'sanming/shaxian': ('사현 샤오츠', '사셴(사현)의 소박한 음식은 저렴하고 든든한 메뉴로 중국 전역에 퍼진 하나의 현상이 되었어요. 종잇장처럼 얇은 완탕과 땅콩 소스 비빔면, 푹 쪄낸 탕 요리가 중국 거의 모든 거리에 있는 사셴 분식집에서 한결같이 따뜻하게 차려져요.'),
  'sanming/forest': ('녹색의 수도', '산밍은 중국에서 산림 비율이 가장 높은 도시 중 하나로, 산등성이부터 골짜기까지 온통 초록으로 덮여 있어요. 한때 목재 도시였지만 지금은 생태 관광으로 방향을 바꾸어, 맑은 공기와 숲길 트레킹 코스로 \'녹색 수도\'라는 이름을 자랑스럽게 지니고 있어요.'),
  'sanming/goldenlake': ('진후', '진후(金湖), 곧 \'황금 호수\'는 타이닝의 붉은 단샤 절벽 사이로 길게 뻗은 넓은 인공 호수예요. 유람선을 타면 좁은 물협곡과 깎아지른 바위 절벽, 바위굴 속에 지어진 간루사 앞을 지나게 되는데, 물과 돌이 만나는 보기 드문 절경이에요.'),
  'ningde/mudflat': ('샤푸 갯벌', '샤푸 해안에서는 날마다 썰물이 빠져나가면 시시각각 변하는 빛에 반짝이는 광활한 갯벌이 드러나요. 해초 양식장과 줄지어 선 대나무 장대, 얕은 물에서 일하는 어민들의 모습이 이 해안을 세계적으로 유명한 사진가들의 성지로 만들었어요.'),
  'ningde/whitetea': ('푸딩 백차', '푸딩은 중국 백차의 고향이에요. 은빛 솜털이 덮인 찻잎을 볶지 않고 그저 시들려 말리기만 하죠. \'1년이면 차, 3년이면 약, 7년이면 보물\'이라는 말은 이 섬세한 차가 세월이 흐를수록 얼마나 귀해지는지를 잘 보여줘요.'),
  'ningde/taimu': ('타이무산', '타이무산은 둥글둥글한 화강암 봉우리와 좁은 바위틈, 동굴 통로를 품고 바다 위로 솟아 있어요. 예로부터 \'바다 위의 선경\'이라 불려 왔으며, 바위 사이를 누비는 등산로를 따라가면 안개와 바다가 만나는 전망대에 닿아요.'),
  'ningde/croaker': ('조기', '닝더의 아늑한 싼두아오만은 중국 최대의 대황어(큰조기) 양식 기지예요. 물 위에 떠 있는 가두리 양식장이 바다 위에 마을을 이루고, 살이 희고 결이 고운 이 생선은 그대로 쪄내기만 해도 푸젠 밥상의 주인공이 돼요.'),
  'shaoguan/redcliff': ('단샤산', '단샤산은 전 세계 \'단샤 지형\'이라는 이름의 유래가 된 붉은 사암 산으로, 유네스코 세계유산에 등재되어 있어요. 바람과 물이 조각한 탑과 기둥들이 해질 무렵 숯불처럼 붉게 타오르고, 구불구불한 산길과 유람선이 이 붉은 미로 속으로 안내해 줘요.'),
  'shaoguan/chantemple': ('남화사', '사오관 근처의 난화사는 선불교의 육조 혜능이 가르침을 펼친 곳이에요. 1,500년 가까운 역사를 지닌 남방 선종의 성지로, 지금도 순례자들이 향 연기 속에서 대사의 발자취를 따라가요.'),
  'shaoguan/ancestor': ('주지항', '난슝의 주지샹(주지 골목)은 송나라 때 북쪽에서 내려온 이주민 가족들이 남쪽에 정착하기 전 머물던 길목이었어요. 오늘날 수백만 명의 광둥 사람들이 이 좁은 돌길에 자기 가문의 족보를 잇대고, 뿌리를 찾는 이들이 해마다 조상의 이름을 찾아 이곳에 와요.'),
  'shaoguan/yaodance': ('야오족', '사오관의 산간 지역에 사는 야오족은 눈부신 자수 옷과 긴북춤으로 유명해요. 추수 축제 때면 북소리가 골짜기에 울려 퍼지고, 자수 문양은 글자 없는 언어처럼 씨족의 역사를 대대로 전해 줘요.'),
  'zhanjiang/oyster': ('잔장 굴', '잔장의 따뜻하고 깨끗한 남쪽 바다에서 자란 굴은 크고 우유처럼 통통해요. 저녁이면 길거리 노점에서 마늘과 기름을 얹어 숯불에 지글지글 구워지는데, 바다 향 가득한 이 맛은 이 도시 밤 문화의 빼놓을 수 없는 의식이에요.'),
  'zhanjiang/navy': ('해군 기지', '깊고 아늑한 천연 항구를 지닌 잔장은 중국 해군 남해함대의 모항이에요. 한때 \'광저우완\'이라는 이름의 프랑스 조차지였던 이 항구 도시는 오늘날 남중국해로 향하는 중국의 전략적 관문이 되었어요.'),
  'zhanjiang/mangrove': ('맹그로브 숲', '잔장 해안을 따라 펼쳐진 맹그로브 숲은 중국 최대의 맹그로브 보호구역이에요. 밀물과 썰물에 따라 잠겼다 드러나는 이 바닷물 숲에는 백로와 말뚝망둥어, 게가 살고, 뒤엉킨 뿌리는 폭풍으로부터 해안을 지키며 어린 물고기들의 요람이 되어 줘요.'),
  'zhanjiang/donghai': ('둥하이섬', '잔장 앞바다의 둥하이섬은 수 킬로미터나 끊김 없이 이어지는 해변으로 유명해요. 꾸준히 부는 바람이 서퍼들을 불러 모으고, 수십 명이 어깨를 맞대어 한 마리 용이 되는 전통 \'인룡춤\'으로도 잘 알려져 있어요.'),
  'maoming/lychee': ('리치 산지', '마오밍은 세계에서 손꼽히는 리치 산지로, 초여름이면 언덕이 붉은 열매로 물들어요. 옛날에는 이곳 리치가 황궁에 진상품으로 바쳐졌고, 과수원의 수백 년 된 리치 나무들은 지금도 열매를 맺고 있어요.'),
  'maoming/refinery': ('석유화학 기지', '마오밍은 1950년대에 유혈암(오일셰일) 가공으로 성장한 공업 도시로, 오늘날 남중국 최대급 석유화학 단지를 품고 있어요. 정유 공장과 에틸렌 설비가 농업이 발달한 이 푸른 지역에 든든한 경제의 기둥이 되어 줘요.'),
  'maoming/ladyxian': ('선 부인', '6세기에 살았던 셴 부인(冼夫人)은 남방의 여러 민족을 평화롭게 하나로 묶은 지혜로운 여성 지도자였어요. 마오밍과 그 주변에는 그녀에게 바쳐진 사당이 수백 곳에 이르고, 해마다 열리는 추모 제례는 1,500년 가까이 이어져 온 존경의 증거예요.'),
  'maoming/seaside': ('중국 제일 해변', '\'중국 제일의 해변\'으로 이름을 알린 마오밍의 해안에는 황금빛 모래가 수 킬로미터나 펼쳐져요. 해안을 따라 심어진 카수아리나 숲이 바람을 막는 초록 병풍이 되어 주고, 가족들은 낮에는 바다에서 헤엄치고 저녁에는 해산물 식당에서 하루를 마무리해요.'),
  'zhaoqing/sevenstar': ('칠성암', '북두칠성을 닮았다는 일곱 개의 석회암 봉우리가 싱후(星湖) 호수 위로 솟아 있어요. 바위 속에는 수백 년에 걸친 글씨가 새겨진 동굴들이 숨어 있고, 호숫가 둑길을 거닐다 보면 왜 이곳이 \'광둥의 구이린\'이라 불리는지 알게 돼요.'),
  'zhaoqing/inkstone': ('돤옌 벼루', '서재의 네 가지 보물 가운데 가장 유명한 벼루는 자오칭의 단계연(돤 벼루)이에요. 당나라 때부터 이곳 채석장에서 캐낸 보랏빛 돌은 장인의 손에서 예술품으로 다시 태어나죠. 좋은 단계연은 먹물을 천천히 마르게 하고 붓을 상하게 하지 않아요.'),
  'zhaoqing/dinghu': ('딩후산', '딩후산은 1956년에 지정된 중국 최초의 자연보호구역이에요. 손대지 않은 아열대 우림과 폭포, 칭윈사가 어우러진 이 산은 도시 사람들이 천연 \'산소 바\'라고 부르며 아끼는 시원한 쉼터예요.'),
  'zhaoqing/songwall': ('송대 성벽', '자오칭 성벽은 송나라 때 쌓아 올려져 성 둘레가 거의 온전하게 오늘날까지 남아 있어요. 벽돌 층마다 여러 왕조가 보수한 흔적이 새겨져 있어서, 성벽 위를 걷는 일은 천 년 가까운 도시 역사를 한 바퀴 도는 산책이 돼요.'),
  'huizhou/westlake': ('후이저우 서호', '후이저우 서호는 버드나무 늘어선 둑길과 돌다리, 작은 섬들이 어우러진 우아한 고전 풍경이에요. 이곳으로 유배 온 대시인 소동파가 시로 호수를 영원히 남겼고, 호숫가 둑길 하나는 지금도 그의 이름을 지니고 있어요.'),
  'huizhou/luofu': ('뤄푸산', '뤄푸산은 남중국에서 가장 신성한 도교 명산 중 하나로, 수백 년 동안 은둔자와 연단술사들을 봉우리로 불러들였어요. 약초로 유명한 숲 속에는 사원과 샘물, 그리고 구름 속으로 이어지는 오솔길이 기다리고 있어요.'),
  'huizhou/alchemy': ('거홍의 연단술', '진(晉)나라의 연단술사이자 의사였던 갈홍은 뤄푸산에 들어가 단약을 달이고 의학서를 썼어요. 그가 옛 처방집에 남긴 개똥쑥에 관한 기록은 수백 년이 지난 뒤 현대 말라리아 치료제의 발견에 영감을 주었어요.'),
  'huizhou/xunliao': ('쉰랴오완', '쉰랴오만은 얕은 청록빛 바다와 길게 이어진 옅은 모래사장으로 광둥 해안에서 사랑받는 휴양지예요. 한때 어촌이던 마을들이 지금은 신선한 해산물을 차려 내고, 잔잔한 바다는 아이와 함께하는 가족 여행에 안성맞춤이에요.'),
  'meizhou/weilongwu': ('객가 위룽우', '메이저우는 전 세계에 흩어져 사는 하카(객가)족의 정신적 수도로 여겨져요. 언덕에 기대어 지은 말굽 모양의 전통 가옥 웨이룽우는 대가족 문중 전체를 한 지붕 아래 모았고, 그 마당에서는 지금도 문중 잔치가 열려요.'),
  'meizhou/saltchicken': ('옌쥐지', '소금구이 통닭은 하카 요리에서 가장 유명한 고전이에요. 종이에 싼 닭 한 마리를 뜨겁게 달군 굵은 소금 속에 파묻어 익히는데, 소금이 살을 마르게 하기는커녕 육즙을 가둬 주어 생강 향이 감도는 비단결처럼 부드러운 맛이 완성돼요.'),
  'meizhou/football': ('축구의 고향', '메이저우는 근대 축구가 중국에서 가장 먼저 뿌리내린 곳 중 하나로, \'중국 축구의 요람\'이라 불려요. 전설의 골잡이 리후이탕이 이 땅에서 태어났고, 마을 운동장에서 프로 구단까지 그 열정은 지금도 살아 있어요.'),
  'meizhou/plum': ('매화', '메이저우라는 이름은 \'매화 매(梅)\' 자에서 왔고, 도시를 적시는 강도 메이장, 곧 매화강이에요. 한겨울 추위 속에 피는 매화는 강인하고 부지런한 하카 사람들의 정신을 상징하며, 도시 곳곳에서 문양으로 만날 수 있어요.'),
  'jiangmen/diaolou': ('카이핑 댜오러우', '카이핑의 논 사이로 솟은 댜오러우 망루들은 20세기 초 해외에서 돌아온 이민자들이 지은 건물이에요. 도적과 홍수를 막는 요새로 설계된 이 집들은 서양식 기둥과 중국식 지붕을 한데 섞었고, 지금은 유네스코 세계유산이에요.'),
  'jiangmen/qiaoxiang': ('화교의 고향', '장먼과 그 주변의 우이(五邑) 지역은 전 세계에 흩어진 수백만 화교의 본향이에요. 아메리카부터 동남아시아까지 뻗어 나간 이 디아스포라가 고향에 학교와 도로, 저택을 지어 주었고, 도시는 지금도 동서양이 어우러진 독특한 정취로 유명해요.'),
  'jiangmen/chenpi': ('천피', '신후이의 말린 귤껍질 \'천피(진피)\'는 햇볕에 말린 뒤 여러 해 동안 묵혀 숙성시켜요. 광둥 요리에 깊은 향을 더하고 전통 의학에서도 귀하게 쓰이는데, 잘 묵은 귤껍질은 오래된 명품 와인처럼 대접받아요.'),
  'jiangmen/birds': ('냐오탕궈', '신후이의 \'새들의 천국\'은 가지에서 뿌리를 내려 작은 섬 하나를 통째로 뒤덮은 한 그루의 거대한 반얀나무예요. 수천 마리의 백로와 물새가 이곳에 깃들고, 작가 바진의 유명한 수필 덕분에 이 초록 섬은 온 중국의 사랑을 받게 되었어요.'),
  'yangjiang/knife': ('칼의 도시', '양장은 중국의 칼과 가위의 수도로, 중국 주방칼의 큰 몫이 이 도시의 공방과 공장에서 만들어져요. 수백 년 이어진 대장장이 전통이 현대 철강 기술과 만나면서, 이곳 브랜드들은 세계 곳곳의 주방으로 뻗어 나갔어요.'),
  'yangjiang/shipwreck': ('난하이 1호', '난하이 1호는 해상 실크로드에서 침몰해 수백 년 동안 바다 밑에 잠들어 있던 송나라 무역선이에요. 배는 통째로 인양되어 지금은 하이링섬의 유리 수조 박물관에 안치되어 있고, 선창에서는 수만 점의 도자기와 보물이 세상 빛을 보았어요.'),
  'yangjiang/hailing': ('하이링다오', '하이링섬은 초승달 모양의 다자오만과 부드러운 백사장을 지닌, 광둥에서 가장 사랑받는 바다 휴양 섬 중 하나예요. 낮에는 파도 속에서 헤엄치고 저녁에는 어항에서 갓 올라온 해산물을 맛보죠. 이 섬에는 난하이 1호 침몰선 박물관도 자리하고 있어요.'),
  'yangjiang/kite': ('연의 도시', '양장은 북쪽의 웨이팡과 함께 중국의 2대 연 도시로 꼽혀요. 대나무 뼈대의 전통 연이 몇 대에 걸쳐 손으로 만들어져 왔고, 해마다 가을 중양절이면 하늘이 알록달록한 날개로 가득 차요.'),
  'qingyuan/rafting': ('칭위안 래프팅', '산에서 쏟아져 내리는 세찬 계곡물 덕분에 칭위안은 중국에서 \'래프팅의 고향\'이라 불려요. 여름이면 수천 명이 물보라 이는 코스에서 래프팅을 즐기고, 골짜기의 시원한 숲과 바위 웅덩이는 도시의 더위에서 벗어나는 최고의 피서지가 돼요.'),
  'qingyuan/chicken': ('칭위안 닭요리', '얼룩 깃털을 지닌 칭위안 토종닭은 뼈가 가늘고 맛이 깊어 광둥 요리에서 가장 귀하게 찾는 닭이에요. 자유롭게 놓아 기른 이 품종은 대개 그저 삶기만 해서 생강·파 소스와 함께 내는데, 그 소박함이 곧 품질의 증거예요.'),
  'qingyuan/hotspring': ('온천', '칭위안의 산골짜기에서 솟는 미네랄 가득한 온천수는 이 도시를 광둥의 온천 중심지로 만들었어요. 노천탕에서 김이 피어오르고 주위에서는 대나무 숲이 사각거리죠. 광저우에서 온 주말 여행객들이 이곳에서 몸을 담그며 피로를 풀어요.'),
  'qingyuan/yaoterrace': ('야오족 다랑논', '롄난의 야오족 마을에서는 계단식 논이 산비탈을 층층이 감싸며 올라가요. 수백 년 동안 손으로 쌓아 올린 이 논은 봄에는 물거울로, 가을에는 황금 계단으로 변신하고, 그 사이에는 유서 깊은 야오족 마을들이 지금도 살아 숨 쉬어요.'),
  'chaozhou/guangjibridge': ('광지교', '한장강을 가로지르는 광지교는 송나라 때 짓기 시작한 다리로, 가운데 구간이 나란히 묶인 배들로 이루어진 독특한 구조예요. 이 배다리 구간은 날마다 열려 배들에게 길을 내주며, 그 덕분에 중국 4대 고대 교량의 하나로 꼽혀요.'),
  'chaozhou/woodcarving': ('금박 목조각', '차오저우의 금박 목조각은 한 장의 판 위에 장면을 겹겹이 새겨 넣는 전설적인 공예예요. 고기잡이 그물부터 경극의 영웅까지 모든 디테일이 정교하게 조각되고, 금박을 입힌 작품들이 사원과 저택을 반짝임으로 가득 채워요.'),
  'chaozhou/chaoxiu': ('차오저우 자수', '차오저우 자수는 광둥 자수 가운데 가장 화려한 갈래로, 금실과 은실을 심 위에 수놓아 도드라진 입체 효과를 내요. 용과 봉황이 천에서 금방이라도 튀어나올 듯 생생하며, 혼례복과 경극 의상이 이 예술로 장식되어 왔어요.'),
  'chaozhou/kaiyuan': ('카이위안사', '이 사원은 당나라 개원(開元) 연간인 738년에 세워져 지금까지 그 연호를 이름으로 지니고 있어요. 천 년 넘게 예불이 끊이지 않은 마당에는 커다란 향로가 연기를 피우고, 차오저우 목조각의 가장 아름다운 작품들이 법당을 장식하고 있어요.'),
  'jieyang/citygate': ('진셴먼', '진셴먼, 곧 \'어진 이를 맞이하는 문\'은 옛 제양의 모습을 간직한 우아한 상징이에요. 겹겹의 처마를 얹은 목조 누각이 해자를 내려다보고, 그 이름에는 지혜롭고 어진 사람을 반기고자 하는 도시의 바람이 담겨 있어요.'),
  'jieyang/jade': ('옥의 도시', '제양에 속한 양메이 마을은 중국 최대의 옥 가공·거래 중심지 중 하나예요. 미얀마에서 온 비취 원석이 이곳에서 잘리고 조각되고 연마되는데, 시장 골목에서는 장인들이 돌 속에 숨은 초록빛을 마치 도박하듯 읽어 내요.'),
  'jieyang/jieyanglou': ('지에양러우', '제양루는 전통 처마와 웅장한 자태로 고대 건축을 오늘에 되살린 현대의 기념비적 건물이에요. 안에서는 문화 전시가 열리고, 이 누각은 차오산 사람들이 자기 뿌리에 품은 자부심을 돌과 나무로 빚어낸 모습이에요.'),
  'jieyang/beefbroth': ('차오산 소고기탕', '차오산의 소고기 탕과 훠궈는 신선함에 바쳐진 요리예요. 소의 부위마다 저마다의 이름이 있고, 맑게 끓는 국물에 몇 초 단위로 정확히 데쳐 내죠. 사차 소스를 곁들이는 이 소박함 속의 장인 정신이 지역의 자랑이에요.'),
  'yunfu/marble': ('석재의 왕국', '윈푸는 중국의 석재 가공 수도로 알려져 있어요. 대리석과 화강암이 몇 세대에 걸쳐 이 도시에서 잘리고 다듬어져 왔죠. 도로변에 늘어선 수천 개의 공방이 조리대 상판과 조각상, 외장재를 전 세계로 실어 보내는데, 돌은 그야말로 이 도시의 밥줄이에요.'),
  'yunfu/patriarch': ('육조 혜능', '선불교의 육조 혜능은 윈푸에 속한 신싱에서 태어나 말년을 이곳에서 보냈어요. 그를 기려 세운 궈언사는 순례자들이 모여드는 고요한 성지인데, 나무꾼 소년에서 깨달은 조사가 된 그의 이야기가 바로 이 땅에서 시작되었어요.'),
  'yunfu/tianlu': ('톈루산', '톈루산은 구름에 닿는 능선과 차밭으로 덮인 산비탈을 지닌 윈푸의 초록 왕관이에요. 아침이면 골짜기가 구름바다로 가득 차는 날이 많아서, 일출을 보러 오른 등산객들은 안개 위로 솟아오른 봉우리들의 장관으로 보상을 받아요.'),
  'yunfu/xijiang': ('시강', '시장(西江), 곧 서강은 주장(珠江) 수계의 본류이자 남중국에서 가장 붐비는 물길 중 하나예요. 화물 바지선이 밤낮으로 윈푸 앞을 지나가고, 이 강은 지금도 석재와 농산물을 광저우로, 다시 세계로 실어 나르는 생명의 동맥이에요.'),
  'liuzhou/luosifen': ('뤄쓰펀', '류저우의 우렁이 쌀국수 뤄쓰펀은 우렁이로 우려낸 국물과 톡 쏘는 냄새의 절인 죽순으로 유명해요. 멀리서부터 그 냄새로 호불호가 갈리지만, 한번 맛을 들이면 끊기 어렵죠. 즉석 포장 제품이 나오면서 이 지역 별미는 중국을 넘어 세계로 퍼졌어요.'),
  'liuzhou/autocity': ('자동차 도시', '류저우는 광시의 산업 심장이자 중국의 주요 자동차 생산 기지 중 하나예요. 이곳에서 만들어지는 작고 저렴한 전기차는 도시 거리의 상징이 되었고, 아무리 좁은 주차 공간에도 쏙 들어가는 이 꼬마 차를 주민들은 진심으로 아껴요.'),
  'liuzhou/karst': ('류저우 카르스트 지형', '류장강이 허리띠처럼 도시를 감아 돌고, 사방으로는 석회암 봉우리들이 솟아 있어요. 이 커다란 물굽이 덕분에 류저우는 \'찻주전자 도시\'라는 별명을 얻었고, 공업 도시 한복판에서 강변 공원과 카르스트 봉우리가 뜻밖의 자연미를 선사해요.'),
  'liuzhou/liuhou': ('류쭝위안', '당나라의 대문장가 유종원은 유배지였던 류저우에서 지방관으로 일하며 우물을 파게 하고 가난한 이들을 보살폈어요. 도심의 류허우 공원에는 그를 모신 사당이 서 있고, 이 시인은 생애 마지막 몇 해를 보낸 이 도시와 떼려야 뗄 수 없는 이름이 되었어요.'),
  'wuzhou/gemstone': ('보석의 도시', '우저우는 세계 인조 보석의 수도예요. 전 세계 합성 지르코니아(큐빅)의 대부분이 이 강변 도시의 공방에서 커팅되고 연마되죠. 장인들의 손끝이 조그만 돌에 면을 하나하나 깎아 넣고, 반짝이는 보석들은 여기서 세계 곳곳의 주얼리 시장으로 흩어져요.'),
  'wuzhou/liubaotea': ('류바오차', '우저우의 류바오차는 여러 해 숙성을 거치며 부드럽게 깊어지는 흑차(발효차)예요. 옛날에는 강배에 실려 동남아시아의 광산 노동자들에게 보내졌는데, 습한 기후에서 몸의 균형을 잡아 준다고 믿었기 때문이죠. 오래 묵은 바구니 차는 이제 수집가들이 앞다투어 찾는 귀한 물건이 되었어요.'),
  'wuzhou/turtlejelly': ('귀령고', '우저우는 약초로 만드는 검은 젤리 구이링가오의 고향으로 여겨져요. 살짝 쌉싸름한 이 젤리는 꿀을 넣어 달게 해서 차게 먹는데, 눅눅한 남방의 여름에 몸속 \'열기\'를 빼 준다고 믿어 온 시원한 전통이에요.'),
  'wuzhou/dragonmother': ('용모묘', '시장강 기슭의 룽무(龍母) 사원은 강가 사람들의 수호신으로 받드는 여신에게 바쳐진 곳이에요. 전설에 따르면 용의 어머니는 다섯 마리 용을 거두어 기르고 사람들을 홍수로부터 지켜 주었대요. 명절이면 사원이 향 연기와 소원 리본으로 가득 차요.'),
  'beihai/silverbeach': ('인탄', '베이하이의 인탄, 곧 \'은빛 해변\'은 석영이 풍부한 새하얀 모래가 햇빛에 은처럼 반짝여요. \'천하제일 해변\'이라 불리는 해안은 수 킬로미터나 이어지고, 얕고 따뜻한 바다는 헤엄치고 거닐기에 끝없이 넓은 공간을 내어 줘요.'),
  'beihai/pearl': ('진주의 도시', '베이하이에 속한 허푸는 한나라 때부터 진주로 유명했고, 이곳의 \'남주(남쪽 진주)\'는 황실에 바치는 가장 귀한 진상품으로 꼽혔어요. \'진주가 허푸로 돌아온다\'는 고사가 바로 이 해안에서 태어났고, 오늘날에도 진주 양식장과 보석 시장이 그 전통을 이어 가요.'),
  'beihai/weizhou': ('웨이저우섬', '베이하이 앞바다의 웨이저우섬은 중국에서 가장 젊은 화산섬으로 알려져 있어요. 용암이 빚어낸 검은 절벽과 산호초, 바나나 밭이 섬을 둘러싸고, 19세기에 선교사들이 지은 석조 성당은 이 섬에서 가장 뜻밖의 볼거리예요.'),
  'beihai/oldstreet': ('베이하이 라오제', '베이하이의 옛 거리는 19세기 말 항구가 대외 무역에 열리면서 들어선 아케이드식 치러우 건물들로 늘어서 있어요. 아치형 건물 정면에는 동남아시아와 유럽의 정취가 배어 있고, 오늘날 이 거리는 굴전 노점과 옛 영사관의 흔적 속에 과거를 살아 숨 쉬게 해요.'),
  'qinzhou/nixingpottery': ('니싱도기', '친저우의 니싱 도자기는 유약을 전혀 바르지 않고 굽는데도 가마 속에서 저절로 청동빛, 붉은빛, 보랏빛을 띠어요. 강의 양쪽 기슭에서 캔 흙을 섞어 빚는 이 공예는 중국 4대 도자 전통의 하나로 꼽혀요.'),
  'qinzhou/dolphin': ('흰돌고래', '친저우의 싼냥만은 희귀한 중국흰돌고래의 가장 잘 알려진 서식지 중 하나예요. 나이가 들수록 분홍빛으로 변하는 이 우아한 포유류는 유람선 곁으로 모습을 드러내곤 하죠. 주민들은 \'바다의 판다\'라 부르는 이 돌고래를 자랑스럽게 지켜요.'),
  'qinzhou/oysterfarm': ('오이스터 랜드', '친저우의 얕고 영양이 풍부한 마오웨이해는 중국에서 손꼽히는 새끼 굴(종패) 산지예요. 바다는 줄지어 떠 있는 양식 뗏목으로 뒤덮여 있고, 크고 통통한 수확 덕분에 이 도시는 남방의 굴 수도가 되었죠. 축제철이면 굴구이 불판이 꺼질 줄 몰라요.'),
  'qinzhou/general': ('펑쯔차이 장군', '청나라 장군 펑쯔차이는 노령에도 다시 군대로 돌아가, 베트남 국경의 전난관에서 침략에 맞서 역사적인 승리를 거두었어요. 고향 친저우에는 그의 옛 저택이 박물관으로 보존되어 있고, 그의 이름은 나라를 지킨 상징으로 오래도록 기억되고 있어요.'),
  'guigang/lotus': ('연꽃의 도시', '구이강은 중국에서 \'연꽃의 도시\'라 불려요. 여름이면 주변의 연못과 들판이 분홍빛, 하얀빛 꽃으로 뒤덮이죠. 연근과 연밥은 이곳 식탁에서 빠질 수 없는 재료이고, 해마다 열리는 연꽃 축제가 도시를 축제 분위기로 가득 채워요.'),
  'guigang/uprising': ('진톈 봉기', '1851년 구이핑의 진톈촌에서 홍수전이 태평천국 봉기의 깃발을 올렸어요. 19세기 최대의 민중 운동 중 하나가 이곳에서 시작되어 중국의 절반을 뒤흔들었고, 지금은 마을의 기념 유적지가 그 격동의 시대를 들려줘요.'),
  'guigang/nanshan': ('난산사', '구이강의 난산사는 석회암 언덕의 천연 동굴 속에 자리 잡은 천년 고찰이에요. 동굴 벽에는 여러 왕조에 걸쳐 새겨진 글과 시가 줄지어 남아 있고, 서늘한 돌 법당 안에는 불상들이 고요히 앉아 있어요.'),
  'guigang/sugarcane': ('사탕수수', '광시는 중국 설탕의 최대 산지이고, 구이강의 기름진 강가 평야는 그 달콤한 수확의 중요한 몫을 맡고 있어요. 가을이면 사탕수수가 사람 키를 훌쩍 넘게 자라고, 수확철에는 공장으로 사탕수수를 실어 나르는 트럭들이 도로를 가득 메워요.'),
  'yulin/medicine': ('한약재 시장', '위린의 약재 시장은 남중국 최대의 전통 약재 거래 중심지 중 하나예요. 통로마다 말린 뿌리와 나무껍질, 꽃의 향기가 뒤섞이고, 수백 년의 지식을 물려받은 상인들은 약초 하나하나의 성질을 훤히 꿰고 있어요.'),
  'yulin/goldenpalace': ('윈톈궁', '윈톈궁은 전통 궁궐 건축을 어마어마한 규모로 재해석한 웅장한 문화 건축물이에요. 층마다 정교한 조각과 청동상, 신화 속 장면들이 전시되어 있고, 금빛 탑들은 도시 스카이라인에서 가장 눈길을 끄는 존재예요.'),
  'yulin/lychee': ('리치 과수원', '위린의 따뜻한 언덕과 골짜기는 리치와 용안 과수원으로 덮여 있어요. 초여름이면 가지가 붉은 열매 송이의 무게로 휘어지고, 시장 좌판은 달콤한 향의 과일로 넘쳐 나죠. 가족들은 수확하는 날을 잔칫날처럼 즐겨요.'),
  'yulin/beef': ('위린 소고기', '위린의 대표 간식 뉴바는 얇게 저민 소고기를 양념 소스에 천천히 말리고 조려서 만들어요. 색이 짙고 은은하게 달면서도 감칠맛이 진한 이 고기는 밥반찬으로도, 차와 함께하는 곁들이로도 즐기는데, 그 조리법은 집집마다 대대로 전해 내려와요.'),
  'baise/redbase': ('바이서 봉기', '1929년 젊은 덩샤오핑이 이끈 바이써 봉기는 유장강(右江) 기슭에 혁명 근거지를 세웠어요. 그래서 이 도시는 중국 \'붉은 기억\' 답사길의 중요한 정거장이 되었고, 기념관과 옛 사령부 건물이 그 시대를 오늘에 전해 줘요.'),
  'baise/sinkhole': ('러예 싱크홀', '러예현의 거대한 싱크홀, 곧 톈컹은 지구에서 가장 밀집된 싱크홀 군락 중 하나를 이뤄요. 수백 미터 깊이의 구덩이 바닥에는 손대지 않은 원시림이 자라고, 지하 강과 동굴 시스템 덕분에 이곳은 지질학자와 동굴 탐험가들이 아끼는 명소가 되었어요.'),
  'baise/mango': ('망고의 수도', '바이써의 덥고 볕 좋은 골짜기는 중국에서 가장 중요한 망고 산지 중 하나예요. 한여름이면 산비탈이 황금빛으로 물들고, 트럭들이 달콤한 열매를 전국 방방곡곡으로 실어 나르죠. 망고는 이 산간 지역의 생계이자 자랑스러운 상징이 되었어요.'),
  'baise/aluminum': ('알루미늄 도시', '바이써의 산에는 보크사이트가 풍부하게 묻혀 있어요. 이 광석 덕분에 도시는 중국 알루미늄 산업의 남방 거점이 되었죠. 광산과 제련소가 지역 경제의 등뼈를 이루고, 붉은 흙 아래의 이 \'은빛\' 금속이 수천 가구의 일자리가 되어 줘요.'),
  'hechi/longevity': ('바마 장수촌', '허츠에 속한 바마는 인구 대비 100세를 넘긴 주민이 유난히 많은, 세계적으로 유명한 \'장수의 고장\'이에요. 맑은 공기와 소박한 식사, 서두르지 않는 삶이 그 비결로 꼽히고, 해마다 수천 명이 건강을 찾아 이 골짜기로 찾아와요.'),
  'hechi/folksong': ('류삼저', '허츠의 이저우는 전설적인 가수 류싼제의 고향으로 기려지는, 좡족 민요의 본고장이에요. 이야기 속 \'노래의 요정\'은 즉흥 노래 대결로 지주들을 통쾌하게 이겨 내는데, 이 전통은 오늘날에도 노래 축제에서 흥겹게 이어지고 있어요.'),
  'hechi/bronzedrum': ('동고', '청동북은 좡족과 야오족 같은 남방 민족들에게 가장 신성한 물건 중 하나이고, 허츠는 살아 있는 청동북 문화의 심장으로 여겨져요. 돋을새김 무늬의 북은 명절마다 울리며 복과 보호를 불러온다고 믿어지고, 많은 마을이 수백 년 된 북을 가보처럼 간직해요.'),
  'hechi/geopark': ('카르스트 지질공원', '허츠의 카르스트 지대는 싱크홀과 거대한 동굴 홀, 지하 강이 어우러진 자연의 실험실이에요. 펑산 일대의 천연 돌다리와 동굴 천창이 이 지질공원의 스타인데, 빛이 수직굴을 타고 쏟아져 내리는 곳마다 숨겨진 세계가 저 아래 모습을 드러내요.'),
  'laibin/sugarcity': ('설탕의 도시', '라이빈의 평야는 눈길 닿는 곳마다 사탕수수로 덮여 있어 \'중국의 설탕 수도\'라 불려요. 겨울 수확이 시작되면 공장 굴뚝에서 연기가 피어오르고, 사탕수수가 설탕과 당밀, 종이로 변신하는 동안 달콤한 냄새가 마을들을 감싸요.'),
  'laibin/yao': ('다야오산 야오족', '라이빈에 속한 진슈의 다야오산은 야오족의 서로 다른 다섯 지파가 함께 사는 터전인데, 지파마다 옷차림과 방언, 의례가 달라요. 산골 마을 축제에서는 은장신구와 수놓은 머리 장식이 반짝이고, 이런 다채로움이 진슈를 살아 있는 문화 박물관으로 만들어요.'),
  'laibin/hongshui': ('훙수이허', '훙수이강은 실어 나르는 붉은 흙에서 이름을 얻은 강으로, 광시의 산줄기를 가르며 힘차게 흘러요. 골짜기를 따라 들어선 댐들이 남방 곳곳에 전기를 보내고, 강가 마을들은 카르스트 봉우리 사이로 강이 빚어낸 절경을 누리며 살아요.'),
  'laibin/shengtang': ('성탕산', '성탕산은 다야오산맥의 최고봉이자 광시의 지붕으로 꼽히는 봉우리 중 하나예요. 봄이면 산비탈이 붉은 만병초 꽃으로 불타오르고, 정상에서는 구름바다와 일출, 바람에 흩날리는 안개가 산을 오른 이들에게 보상이 되어 줘요.'),
  'chongzuo/waterfall': ('더톈 폭포', '더톈 폭포는 중국과 베트남 국경의 강 위로 넓은 계단을 이루며 쏟아지는, 아시아 최대의 국경 폭포예요. 대나무 뗏목을 타면 물의 장막이 뿜어내는 서늘한 물보라 가까이 다가갈 수 있고, 주위의 카르스트 봉우리들이 이 풍경을 한 폭의 중국화로 만들어 줘요.'),
  'chongzuo/langur': ('흰머리랑구르', '흰머리랑구르는 충쭤의 석회암 언덕에서만 살아가는, 세계에서 가장 희귀한 영장류 중 하나로 꼽히는 원숭이예요. 밤에는 절벽 틈에서 자고 낮에는 가파른 바위를 뛰어다니며 지내는데, 보호구역 덕분에 개체 수가 조금씩 회복되고 있어요.'),
  'chongzuo/rockart': ('화산 암각화', '약 2천 년 전 뤄웨족이 쭤장강 절벽에 그린 붉은 그림에는 개구리 자세로 춤추는 수천 명의 사람이 담겨 있어요. 손이 닿지 않는 절벽 면에 어떻게 그렸는지는 아직도 수수께끼로 남아 있고, 이 암벽화는 유네스코 세계유산에 등재되어 있어요.'),
  'chongzuo/borderpass': ('우의관', '유이관, 곧 \'우정의 관문\'은 중국과 베트남을 잇는 유서 깊은 국경 관문이자 중국의 이름난 관문 중 하나예요. 푸른 산 사이에 선 아치형 누각은 수백 년 동안 군대와 대상, 사신들을 맞이했고, 오늘날에도 국경 무역의 활기찬 관문 역할을 이어 가고 있어요.'),
  'beijing/great-wall': ('만리장성', '만리장성은 중국 북쪽 국경을 지키기 위해 수백 년에 걸쳐 쌓은, 총길이 2만 킬로미터가 넘는 세계에서 가장 긴 방어 시설이에요. 베이징에서 가장 가까운 바다링 구간은 돌계단과 성벽, 능선을 따라 늘어선 망루 덕분에 방문객이 가장 많은 곳이랍니다.'),
  'beijing/temple': ('천단공원', '천단은 명나라와 청나라 황제들이 해마다 풍년을 기원하며 하늘에 제사를 올리던 신성한 사원 단지예요. 못을 하나도 쓰지 않고 지은 3층의 둥근 푸른 지붕은 중국 건축에서 가장 널리 알려진 상징 중 하나랍니다.'),
  'beijing/pagoda': ('톈닝사 탑', '요나라 때 세워진 이 벽돌탑은 높이 약 57미터에 13층으로 이루어져 있어요. 섬세한 부조 조각과 팔각형 몸체를 지닌 이 탑은 베이징에 남아 있는 가장 오래된 건축물 중 하나로, 도시의 천 년 역사를 지켜본 증인이랍니다.'),
  'beijing/opera': ('경극', '경극은 노래와 대사, 무술, 곡예가 어우러진 200년 역사의 중국 전통 무대 예술이에요. 배우들의 알록달록한 얼굴 분장인 롄푸(검보)는 인물의 성격을 말해 주는데, 빨간색은 충성심을, 흰색은 교활함을 상징한답니다.'),
  'zunyi/huiyi': ('쭌이 회의', '대장정이 가장 어두웠던 1935년, 공산당 지도부가 이 회색 석조 저택에 모여 혁명의 방향을 다시 정하고 마오쩌둥이 지도자로 떠오르는 길을 열었어요. 지금은 박물관이 된 이 집 덕분에 쭌이는 중국 \'홍색 관광\' 지도의 중심에 자리하고 있어요.'),
  'zunyi/moutai': ('마오타이진', '츠수이강 기슭의 작은 마을 마오타이는 중국의 국주(國酒)로 불리는 전설적인 바이주의 고향이에요. 수수를 증류해 여러 해 숙성시키는 이 독한 술은 국가 연회에 빠지지 않는 존재가 되었고, 마을 공기에서도 발효 향이 짙게 감돌아요.'),
  'zunyi/loushan': ('러우산관', '산을 가르는 험준한 러우산관은 대장정 당시 홍군이 거둔 역사적인 승리의 무대예요. 마오쩌둥은 이곳에서 지은 유명한 시로 고개를 영원히 남겼고, 오늘날 방문객들은 안개 낀 바위를 오르며 돌에 새겨진 그 시구를 읽어요.'),
  'zunyi/chishui': ('츠수이 폭포', '츠수이의 붉은 단샤 절벽에서 폭포가 쏟아지는 계곡은 대나무 숲과 공룡 시대부터 살아남은 거대한 나무고사리로 가득한 살아 있는 자연 박물관이에요. 비가 온 뒤 강물이 붉게 흐른다고 해서 \'붉은 물\'이라는 이름을 얻었고, 이 경관은 유네스코 중국 단샤 자연유산의 일부예요.'),
  'liupanshui/coolcity': ('쿨 시티', '여름이 시원한 고원에 자리한 리우판수이는 \'중국의 시원한 수도\'라는 칭호를 자랑스럽게 지니고 있어요. 무더위에 지친 쓰촨과 충칭 사람들이 여름마다 이곳으로 피서를 오고, 도시는 이 상쾌한 공기를 축제와 고원 관광으로 잘 살리고 있어요.'),
  'liupanshui/coal': ('서남부의 석탄 바다', '풍부한 석탄층 위에 세워진 리우판수이는 오랫동안 중국 서남부의 에너지 아궁이 역할을 했어요. 20세기의 대규모 산업화 물결 속에서 광산과 철강으로 성장했고, 오늘날에는 광부 도시의 정체성을 녹색 에너지와 관광으로 조화시키려 노력하고 있어요.'),
  'liupanshui/grassland': ('우멍 초원', '구름과 이웃한 우멍 고원의 끝없는 초원에는 말 떼와 지평선에 늘어선 풍력 발전기가 점점이 자리해요. 서늘한 여름이면 이족과 먀오족 마을 사람들이 가축을 방목하고, 고원의 안개가 한순간에 내려앉아 온 풍경을 동화 나라로 바꿔 놓기도 해요.'),
  'liupanshui/kiwi': ('홍심 키위', '서늘하고 안개 낀 고원에서 자라는 붉은 과육 키위는 리우판수이의 달콤한 초록 보물이에요. 속이 루비처럼 붉게 물드는 이 과일은 보통 키위보다 더 달고, 수확철이면 산골 마을이 키위 상자로 넘쳐나요.'),
  'anshun/huangguoshu': ('황궈수 폭포', '중국 최대 폭포인 황궈수 폭포는 77미터 높이에서 우렁차게 쏟아지며 물안개 속에 무지개를 뿌려요. 폭포 뒤편의 물커튼 동굴(수렴동)을 지나며 물줄기 너머를 바라볼 수 있는데, 고전 드라마 \'서유기\'의 장면들도 이곳에서 촬영되었어요.'),
  'anshun/dixi': ('디시', '나무로 깎은 전사 가면을 쓰고 징 소리에 맞춰 마을 광장에서 펼쳐지는 디시(地戲)는 \'중국 오페라의 살아 있는 화석\'이라 불려요. 명나라 주둔군 병사들과 함께 구이저우에 전해진 이 의식극은 약 600년 동안 변함없는 열정으로 옛 전쟁 서사시를 들려주고 있어요.'),
  'anshun/batik': ('바틱', '부이족과 먀오족 여인들은 녹인 밀랍으로 천에 새와 꽃, 소용돌이 무늬를 그린 뒤 천을 쪽빛 염료에 담가요. 밀랍의 가는 균열 사이로 스며든 물감이 모든 작품을 하나뿐인 것으로 만들기에, 안순 바틱은 \'쌍둥이가 없는\' 공예로 불려요.'),
  'anshun/tunpu': ('툰푸 마을', '약 600년 전 명나라 군대가 세운 석조 주둔 마을에 사는 툰푸 사람들은 지금도 조상들의 난징식 옷차림과 옛 방언을 지키고 있어요. 돌담 골목을 걷다 보면 시간이 멈춘 명나라 마을에 들어선 듯한 기분이 들어요.'),
  'bijie/azalea': ('바이리 진달래', '봄이 오면 비제의 산줄기가 진홍빛, 분홍빛, 보랏빛 두견화로 불타오르고, \'백리두견(百里杜鵑)\' 지대는 세계 최대의 천연 두견화 숲으로 꼽혀요. 4월 축제 기간에는 이족과 먀오족 마을 사람들이 꽃바다 한가운데서 노래로 봄을 맞이해요.'),
  'bijie/zhijin': ('즈진 동굴', '거대한 석순이 돌숲처럼 솟아오른 즈진 동굴은 \'지하 궁전\'이라는 별명을 지닌, 중국에서 가장 장관인 동굴 중 하나예요. 대성당만 한 크기의 공간에서는 \'은빛 비의 나무(銀雨樹)\' 같은 섬세한 석회암 조형물이 방문객을 매혹시켜요.'),
  'bijie/caohai': ('차오하이 학', '웨이닝 고원의 얕고 수초 무성한 차오하이호는 해마다 겨울이면 희귀한 검은목두루미의 월동지가 돼요. 아침 안개가 걷히면 수천 마리 새들의 울음소리가 호수를 가득 채우고, 뱃사공들은 갈대숲 사이로 조용히 방문객을 태우고 다녀요.'),
  'bijie/potato': ('비제 감자', '서늘하고 볕 좋은 고원에서 자라는 감자는 비제를 중국의 감자 곳간 중 하나로 만들었고, 웨이닝 감자는 전국적으로 유명해요. 길거리 노점에서 숯불에 굽고, 바삭하게 튀기고, 매운 양념에 버무려지는 소박한 감자는 고원 밥상의 왕이에요.'),
  'qujing/rapeseed': ('뤄핑 유채꽃밭', '늦겨울마다 뤄핑 평야는 황금빛 유채꽃으로 뒤덮이고, 밭 사이로 섬처럼 솟은 카르스트 봉우리들이 풍경에 동화 같은 정취를 더해요. 이 꽃바다는 양봉가와 사진가, 꿀 애호가들을 사방에서 불러 모아요.'),
  'qujing/ham': ('쉬안웨이 햄', '수백 년 동안 소금에 절여 산속 공기에 말려 온 쉬안웨이 햄은 윈난 밥상의 자랑이에요. 장밋빛 붉은 살과 깊은 풍미 덕분에 중국에서 가장 유명한 햄으로 꼽히며, 국물 요리부터 명절 월병까지 온갖 음식에 들어가요.'),
  'qujing/jiulong': ('주룽 폭포', '\'아홉 마리 용\'이라는 이름의 주룽강은 뤄핑 근처에서 계단처럼 층층이 이어지는 폭포들을 만드는데, 폭포마다 너비와 개성이 달라요. 물이 풍부한 계절에 황금빛 유채밭과 어우러지는 이 풍경은 중국에서 가장 아름다운 폭포 행렬로 꼽혀요.'),
  'qujing/sandforest': ('차이서사림', '루량의 채색 모래숲에서는 바람과 비가 깎아 낸 모래 기둥들이 노란색과 붉은색부터 흰색과 보라색까지 다양한 빛깔로 반짝여요. 빛에 따라 색이 변하는 이 천연 조각 정원은 영화 촬영팀과 사진가들이 즐겨 찾는 무대예요.'),
  'yuxi/fuxian': ('푸셴호', '중국에서 가장 깊은 호수 중 하나인 푸셴호는 수정처럼 맑은 물을 담은 채 윈난 고원에 박혀 있는 산속 거울이에요. 물밑에 옛 마을의 흔적이 잠들어 있다는 전설이 전해지고, 호숫가 마을 어부들은 지금도 이 호수의 명물인 작은 캉랑어를 잡아요.'),
  'yuxi/nieer': ('니얼', '중국 국가(國歌)의 작곡가 녜얼의 집안은 위시 출신이라, 도시는 그를 고향 사람으로 자랑스럽게 여겨요. 그의 이름을 딴 음악 공원과 기념관, 축제를 통해 위시는 젊은 나이에 안타깝게 세상을 떠난 작곡가의 선율을 대대로 이어 가고 있어요.'),
  'yuxi/chengjiang': ('청장 화석군', '청장의 5억 3천만 년 전 캄브리아기 화석층은 동물 생명의 여명을 놀랍도록 세밀하게 보여 주는 유네스코 세계유산이에요. 부드러운 조직까지 돌에 새겨진 이 생물들은 \'캄브리아기 대폭발\'의 가장 풍부한 증인으로 꼽혀요.'),
  'yuxi/kiln': ('위시 가마', '원나라 시대까지 거슬러 올라가는 옛 위시 가마는 윈난 청화백자가 태어난 곳으로 여겨져요. 유명한 징더전에서 멀리 떨어져 독자적인 양식을 발전시킨 이곳 도공들은 코발트 무늬 그릇으로 서남 지역 도자 전통에 자신들의 이름을 남겼어요.'),
  'dali/threepagodas': ('숭성사 삼탑', '창산 기슭에서 천 년 동안 솟아 있는 세 개의 우아한 탑은 옛 남조와 대리국의 상징이에요. 수백 년의 지진을 견뎌 낸 이 탑들은 뒤로는 눈 덮인 봉우리, 앞으로는 탑이 비치는 연못과 어우러져 다리에서 가장 사랑받는 그림엽서 같은 풍경을 이뤄요.'),
  'dali/erhai': ('얼하이호', '귀 모양을 닮아 이름 붙은 얼하이호는 창산과 다리 평야 사이에 펼쳐진 고원 호수예요. 호숫가에는 바이족 마을의 흰 벽 집들이 늘어서 있고, 자전거로 호숫길을 달리거나 해 뜰 무렵 고기잡이배를 바라보는 일은 다리 여행의 대표적인 즐거움이에요.'),
  'dali/cangshan': ('창산', '열아홉 개 봉우리와 그 사이를 흘러내리는 열여덟 개 시냇물을 지닌 창산은 다리 뒤편에 초록 장막처럼 솟아 있어요. 중국어로 대리석을 \'다리(大理)의 돌\'이라 부르는 것도 여기서 유래했는데, 이 산에서 캐낸 무늬 대리석은 수백 년 동안 궁궐과 사원을 장식해 왔어요.'),
  'dali/wind': ('풍화설월', '샤관의 바람, 상관의 꽃, 창산의 눈, 얼하이의 달 — 다리의 네 가지 아름다움은 한 편의 시처럼 읊어져요. 바이족 여인들의 머리 장식에도 이 네 가지 상징이 수놓여 있으니, 도시가 자신의 자연을 이토록 우아한 공식으로 요약하는 셈이에요.'),
  'lijiang/oldtown': ('리장 고성', '물길과 자갈길, 기와지붕 목조 가옥으로 짜인 리장 고성은 나시족 문화의 살아 있는 심장이에요. 성벽 없이 지어진 것으로 유명한 이 유네스코 도시는 한때 차마고도 대상들의 쉼터였고, 지금도 골목마다 흐르는 물소리가 발걸음을 따라와요.'),
  'lijiang/snowmountain': ('옥룡설산', '해발 5,596미터의 빙하 봉우리를 지닌 위룽쉐산(옥룡설산)은 잠든 용처럼 리장 위에서 빛나요. 나시족은 이 산을 신성하게 여기는데, 케이블카가 방문객을 빙하 공원으로 실어 나르는 동안 산기슭의 블루문 밸리는 터키석빛 물웅덩이로 사람들을 매혹시켜요.'),
  'lijiang/dongba': ('동파 문자', '나시족 사제들의 그림 문자인 둥바 문자는 세계에서 아직 쓰이고 있는 유일한 상형 문자로 여겨져요. 수천 권의 필사본이 자연의 정령에게 바치는 의식과 나시족의 우주관을 기록하고 있으며, 이 독보적인 기록물은 유네스코 세계기록유산에 등재되었어요.'),
  'lijiang/tigerleaping': ('호도협', '전설에 따르면 호랑이 한 마리가 진사강의 가장 좁은 지점을 단숨에 뛰어넘었다고 해서 협곡에 이 이름이 붙었어요. 위룽쉐산과 하바쉐산 사이로 깊어지는 후탸오샤(호도협)는 세계에서 가장 깊은 협곡 중 하나이고, 벼랑을 따라 이어지는 높은 산길은 트레커들의 꿈이에요.'),
  'lincang/dianhong': ('뎬훙 홍차', '펑칭의 황금빛 새순으로 만드는 홍차 뎬훙은 지난 세기에 태어난 젊은 차인데도 짧은 시간에 윈난의 이름을 세계에 알렸어요. 꿀과 캐러멜 향이 도는 찻물로 중국에서 가장 인정받는 홍차 중 하나로 꼽히며, 오래된 차나무의 잎이 특별한 깊이를 더해 줘요.'),
  'lincang/wadrum': ('와족 목고', '와족은 나무 북을 신성하게 여기는데, 전설에 따르면 북소리가 하늘과 사람 사이에 다리를 놓아 준다고 해요. 창위안의 산골 마을에서는 여인들이 긴 머리카락을 휘날리며 추는 북춤이 수확철과 축제날마다 온 계곡을 우렁찬 소리로 가득 채워요.'),
  'lincang/teatrees': ('고차수', '린창의 안개 낀 산에는 수백 년, 심지어 천 년이 넘은 야생 차나무와 고차수가 자라고 있어, 차가 태어난 숲이 이곳에 고이 간직되어 있어요. 봄 수확철이면 마을 사람들이 사다리를 타고 거대한 나무에 오르는데, 이 오래된 잎으로 세계에서 가장 인기 있는 푸얼차가 만들어져요.'),
  'lincang/lancang': ('란창강', '메콩강의 상류인 란창강은 티베트에서 내려와 린창의 깊은 계곡을 가르며 남쪽 동남아시아로 흘러가요. 강을 따라 늘어선 댐들이 지역에 불을 밝히고, 강변 비탈에는 차밭과 열대 과수원이 층층이 올라가요.'),
  'puer/tea': ('보이차', '이 산악 도시의 이름을 딴 긴압 푸얼차는 세월이 흐를수록 맛이 깊어지고 가치도 높아지는 살아 있는 보물이에요. 떡처럼 눌러 만든 찻잎은 수십 년을 보관할 수 있고, 옛날에는 노새 대상들이 이 차 덩어리를 지고 산을 넘어 티베트와 황실로 날랐어요.'),
  'puer/coffee': ('중국 커피의 수도', '중국 커피의 대부분이 푸얼의 안개 낀 비탈에 자리한 아라비카 농장에서 자라니, 차의 수도에서 뜻밖에도 라테 향이 나는 셈이에요. 커피 농장들은 시음 투어를 열고, 젊은 바리스타들은 이 지역 원두를 세계 무대에 올리려는 꿈을 키우고 있어요.'),
  'puer/teahorse': ('차마고도', '노새 대상들이 차 덩어리를 티베트로 나르고 돌아오는 길에 말을 데려오던 옛 차마고도는 푸얼에서 출발해 구름 덮인 고개로 이어졌어요. 돌을 깐 대상로의 흔적과 옛 역참 마을들이 그 고된 교역의 기억을 지금도 간직하고 있어요.'),
  'puer/peafowl': ('녹공작', '푸얼의 열대 숲은 중국에서 가장 희귀한 새 중 하나인 녹색공작의 마지막 피난처예요. 이곳 보호구역은 이 장엄한 새뿐 아니라 야생 코끼리와 긴팔원숭이의 보금자리이기도 해서, 도시는 차만큼이나 숲을 자랑스러워해요.'),
  'baoshan/volcano': ('텅충 화산군', '텅충 평원에는 97개의 휴화산 원뿔이 늘어서 있어 풍경이 달 표면을 연상시켜요. 방문객들은 분화구 가장자리에 오르거나 열기구를 타고 화산 위를 떠다니고, 검은 용암석은 마을 집들의 벽에까지 쓰여 있어요.'),
  'baoshan/rehai': ('러하이 온천', '텅충의 \'뜨거운 바다(러하이)\' 계곡에서는 간헐천이 김을 뿜고 온천이 부글부글 끓는데, 그중 가장 유명한 것은 거대한 \'큰 끓는 솥\'이에요. 방문객들은 온천 증기에 익힌 달걀을 맛본 뒤 미네랄이 풍부한 물에 몸을 담그며 화산 땅의 치유력을 누려요.'),
  'baoshan/heshun': ('허순 고진', '수백 년 동안 미얀마와 그 너머로 장사를 다니던 상인들의 돌 마을 허순에서는 벌어들인 재산이 우아한 저택과 학교가 되어 고향으로 돌아왔어요. 중국에서 가장 오래된 마을 도서관 중 하나가 있는 이 마을은 연꽃 연못과 돌다리로 평온함을 자아내요.'),
  'baoshan/gaoligong': ('가오리공산', '미얀마 국경을 따라 뻗은 가오리궁산은 나비 계곡과 따뜻한 숲, 수천 종의 식물을 품은 생명의 보고예요. 열대 계곡에서 눈 덮인 능선까지 이어지는 이 산맥은 긴팔원숭이부터 보기 힘든 새들까지 수많은 희귀 생물의 안식처예요.'),
  'deyang/sanxingdui': ('삼성퇴 유적', '1986년 발견된 제사 구덩이에서 나온 퉁방울눈의 거대한 청동 가면들은 3천 년 전의 신비로운 촉(蜀) 문명을 세상에 드러냈어요. 황금 지팡이와 신성한 청동 신수(神樹)로 가득한 싼싱두이는 중국 고고학 최대의 놀라움 중 하나로 꼽혀요.'),
  'deyang/jiannanchun': ('젠난춘', '몐주에서 증류되는 젠난춘은 당나라 궁정에 올린 술 가운데 이름이 전해지는 유서 깊은 바이주예요. 끊임없이 사용되어 온 오래된 발효 구덩이와 꽃향기 도는 풍미 덕분에 쓰촨 술 전통에서 가장 명망 있는 이름 중 하나로 자리하고 있어요.'),
  'deyang/nianhua': ('몐주 연화', '몐주의 손으로 채색한 목판 연화(설맞이 그림)는 수호신과 통통한 아기, 풍요의 상징들로 문 앞에 복을 걸어 줘요. 중국의 대표적인 연화 전통으로 꼽히는 이 예술에서는 장인의 생생한 마지막 붓질이 모든 판화를 저마다 다른 작품으로 만들어요.'),
  'deyang/turbine': ('중공업의 도시', '중국의 거대한 터빈과 발전기, 발전소 설비의 상당 부분이 더양의 드넓은 공장에서 만들어져요. \'중장비의 수도\'로 불리는 이 도시는 중국의 에너지 인프라를 조용히 떠받치는 강철 근육 중 하나예요.'),
  'mianyang/libai': ('이백의 고향', '시선(詩仙) 이백은 장유의 산자락에서 어린 시절을 보냈고, 달빛과 술에 바친 그의 시구도 이곳에서 싹텄어요. 그의 이름을 딴 기념관과 박물관은 해마다 시를 사랑하는 사람들을 이 전설적인 당나라 대가의 발자취 앞에 모이게 해요.'),
  'mianyang/sciencecity': ('과학기술도시', '중국에서 유일하게 공식 \'과학기술 도시\' 칭호를 지닌 몐양은 연구소와 전자 공장으로 미래를 지어 가요. 창훙 텔레비전의 고향이기도 한 이 도시는 실험복을 입은, 쓰촨의 가장 똑똑한 얼굴이에요.'),
  'mianyang/qiang': ('창족 석조 망루', '베이촨의 산골 마을에는 창족의 돌 망루가 수백 년째 서 있는데, 정교하게 쌓아 올린 이 탑들은 방어 시설이자 위신의 상징이었어요. 흰 돌 신앙과 양모 자수를 이어 가는 창족 마을들은 유서 깊은 산악 문화를 살아 숨 쉬게 해요.'),
  'mianyang/mifen': ('몐양 미펀', '닭고기, 소고기, 내장 국물에 김이 오르는 가느다란 쌀국수는 이른 아침 몐양을 깨워요. 가늘디가는 면발은 몇 초 만에 익고, 노점 앞에서 그릇에 고개를 숙인 사람들의 모습은 이 도시의 가장 변함없는 아침 의식이에요.'),
  'nanchong/langzhong': ('랑중 고성', '풍수 원리에 따라 세워진 고성 가운데 가장 잘 보존된 곳 중 하나인 랑중은 자링강 물굽이의 품에 안겨 잠들어 있어요. 한나라 천문학자 낙하굉의 고향으로서 \'중국 설 문화의 발상지\'로 불리고, 식초 향이 감도는 골목들은 명·청 시대의 모습을 간직하고 있어요.'),
  'nanchong/silk': ('비단의 도시', '2천 년이 넘는 뽕나무 재배와 직조 전통을 지닌 난충은 중국 서부의 비단 수도라는 칭호를 지니고 있어요. 실크로드에 옷감을 대던 이 도시는 지금도 제사 공장과 비단 박물관으로 살아가며, 윤기 흐르는 옷감을 세계 시장으로 보내고 있어요.'),
  'nanchong/zhangfei': ('장비 소고기', '삼국지의 영웅 장비는 오랫동안 랑중에 주둔했고, 그의 사당이 지금도 도시에 남아 있어요. 겉은 새까맣고 속은 장밋빛으로 붉은, 그의 이름을 딴 장비 쇠고기(양념 육포)는 \'검은 얼굴\'로 유명한 영웅의 모습에 재치 있게 빗댄 음식이에요.'),
  'nanchong/zhude': ('주더의 고향', '인민해방군의 창건 지휘관 중 한 사람인 주더 원수는 이룽의 가난한 농가에서 태어났어요. 소박한 생가와 기념관은 중국 현대사의 순례지가 되었고, 방문객들은 이곳에서 초라한 시작이 지닌 힘을 느껴요.'),
  'yibin/wuliangye': ('우량예', '수수, 쌀, 찹쌀, 밀, 옥수수로 증류하는 우량예는 이 \'다섯 가지 곡물\'에서 이름을 따왔으며, 중국에서 가장 값진 바이주 브랜드 중 하나예요. 이빈의 습한 기후와 수백 년 된 발효 구덩이가 이 술 특유의 겹겹이 쌓인 향을 만들어 줘요.'),
  'yibin/firstcity': ('양쯔강 제1성', '민강과 진사강이 만나는 지점에서 강은 비로소 창장(양쯔강)이라는 이름을 얻기에, 이빈은 \'창장 제일의 도시\'라 불려요. 서로 다른 빛깔의 두 물줄기가 합쳐지는 곶은 오늘날 강변 공원이 되어 도시가 가장 자랑하는 상징적인 풍경이에요.'),
  'yibin/bamboosea': ('수난 죽해', '백여 개의 언덕을 뒤덮은 수난 죽해(대나무 바다)는 바람에 일렁이는 끝없는 초록 바다예요. 시원한 숲길과 숨은 폭포, 죽순으로 차린 요리가 방문객을 감싸고, 영화 촬영팀도 이 푸르름을 무대 삼아 거듭 찾아와요.'),
  'yibin/ranmian': ('란몐', '물을 거의 쓰지 않고 반죽해 향긋한 기름에 비벼 내는 \'란몐\'은 기름에 불이 붙을 만큼 면이 마른 데서 \'불타는 국수\'라는 이름을 얻었어요. 고추와 산초, 볶은 땅콩이 어우러진 이 국수는 이빈의 아침을 확 깨워 주는 스타예요.'),
  'luzhou/laojiao': ('루저우 라오자오', '1573년부터 한 번도 쉬지 않고 사용되어 온 진흙 발효 구덩이는 루저우 \'농향형\' 바이주 전통의 심장이에요. 구덩이 속 살아 있는 미생물은 대대로 전해지고, 명주 장인들은 가장 오래된 구덩이가 술에 가장 깊은 향을 준다고 믿어요.'),
  'luzhou/port': ('양쯔강 항구', '퉈강이 창장과 만나는 자리에 세워진 루저우는 바다로 향하는 쓰촨의 물의 관문이에요. 수백 년 동안 부두에서 소금과 술, 곡식이 실려 나갔고, 오늘날에도 컨테이너 항구가 내륙 지방을 창장 하류와 세계로 이어 줘요.'),
  'luzhou/longan': ('용안 과수원', '\'용의 눈\'이라 불리는 꿀처럼 달콤한 작은 과일 용안은 루저우 강 계곡의 따뜻한 비탈에서 자라요. 이 도시는 중국 최북단의 대규모 용안 과수원 몇 곳을 품고 있고, 늦게 익는 이 과일은 가을이면 시장 좌판을 가득 채워요.'),
  'luzhou/umbrella': ('유지산', '대나무 살에 손으로 그림을 그려 넣는 펀수이 장인들의 수제 기름종이 우산은 400년 역사를 지닌 우아한 공예예요. 수십 가지 공정을 거치는 우산은 비를 막아 줄 뿐 아니라 행운도 펼쳐 주는데, 둥근 모양이 원만함과 행복을 상징하기 때문이에요.'),
  'leshan/giantbuddha': ('러산 대불', '절벽에 새겨진 71미터의 좌불은 세 강이 소용돌이치며 만나는 물목을 1,200년 동안 고요히 지켜보고 있어요. 당나라 승려 해통이 지나는 배들을 지키려고 시작한 이 거대한 불사는 오늘날 유네스코 세계유산이 되었는데, 발가락 위에만도 수십 명이 올라설 수 있어요.'),
  'leshan/emei': ('어메이산', '불교 4대 명산 중 하나인 어메이산은 구름바다 위에서 빛나는 금정(金頂)으로 순례자와 등산객을 불러요. 산길은 오래된 사찰들을 지나 오르고, 운 좋은 날에는 정상에서 \'부처의 빛\'이라 불리는 둥근 무지개를 볼 수 있어요.'),
  'leshan/monkeys': ('어메이산 원숭이', '어메이산 산길에 사는 장난꾸러기 원숭이들은 순례자의 가방을 넉살 좋게 뒤지는 것으로 유명해요. 현지인들은 이들을 \'산의 주인\'이라 부르는데, 난간에 걸터앉아 사진 포즈를 취하는 원숭이들은 산행에서 가장 재미있고도 짓궂은 추억을 남겨 줘요.'),
  'leshan/qiaojiao': ('차오자오 쇠고기국', '약재와 향신료를 넣고 몇 시간씩 고아 내는 쇠고기탕 \'차오자오\'는 손님들이 높은 걸상에 발을 얹은 채 국을 마시던 모습에서 이름을 얻었어요. 약 백 년 동안 러산 거리의 클래식으로 자리해 온 이 김이 모락모락 나는 한 그릇은 소박한 내장 부위마저 잔칫상으로 바꿔 놓아요.'),
  'zigong/saltwell': ('천 미터 염정', '약 2천 년 동안 소금 우물로 살아온 쯔궁에서는 대나무 케이블 시추 기술이 선하이 우물에서 절정에 달했는데, 세계 최초로 깊이 1천 미터를 넘긴 시추공이 바로 여기서 뚫렸어요. 목조 시추탑과 소금 박물관이 이 \'소금 수도\'의 천재성을 지금도 들려줘요.'),
  'zigong/lantern': ('쯔궁 등불 축제', '새해 시즌마다 쯔궁은 거대한 빛의 등불 정원으로 가득한 동화 나라로 변해요. 용과 궁전, 옛이야기 주인공들이 비단과 강철로 솟아오르고, 이 도시의 등불 장인들은 이제 세계 곳곳의 도시에서 이런 빛의 축제를 만들어요.'),
  'zigong/dinosaur': ('공룡 박물관', '다산푸의 쥐라기 지층에서 쏟아져 나온 수천 점의 화석은 쯔궁을 중국의 공룡 수도로 만들었어요. 발굴 현장 위에 그대로 세운 박물관에서는 발견 당시 모습 그대로의 뼈 화석층을 볼 수 있고, 우뚝 솟은 용각류 골격이 방문객을 쥐라기 시대 깊숙이 데려가요.'),
  'zigong/rabbit': ('렁투', '고추기름과 산초, 땅콩을 곁들여 차갑게 내는 토끼 요리 \'렁투\'는 쓰촨에서 가장 대담한 전채 중 하나로, 그 고향이 바로 쯔궁이에요. 소금 일꾼들의 든든한 밥상에서 태어난 이 도시의 요리는 향신료를 아끼지 않는 전통을 오늘까지 이어 가고 있어요.'),
  'panzhihua/steel': ('바나듐·티타늄의 도시', '진사강의 산악 계곡에 들어선 판즈화는 세계에서 가장 풍부한 바나듐·티타늄 광상을 다루는 거대한 철강 도시예요. 20세기의 대규모 산업화 시기에 맨땅에서 일어선 이 도시는 이 지역 특산 목면(케이폭) 나무의 불꽃처럼 붉은 꽃에서 이름을 따왔어요.'),
  'panzhihua/fruitvalley': ('햇살 가득한 과일 골짜기', '덥고 건조한 진사강 계곡의 망고와 석류, 바나나는 햇살 가득한 이 미기후 속에서 겨울까지도 익어 가요. 늦수확 망고는 도시의 자랑이고, 과수원들은 철강 도시에 뜻밖의 열대 풍미를 더해 줘요.'),
  'panzhihua/sunshine': ('겨울 햇살의 도시', '한 해 약 2,700시간의 햇살을 받는 판즈화는 따뜻하고 밝은 겨울을 원하는 이들의 건강 휴양지예요. 북방의 추위를 피해 온 은퇴자들이 겨울을 이곳에서 보내고, 도시는 그 햇살에 스포츠 캠프와 온천 리조트를 더해 화답해요.'),
  'panzhihua/jinsha': ('진사강', '\'황금 모래의 강\'이라는 뜻의 진사강은 창장(양쯔강)의 상류로, 깊은 계곡을 깎으며 판즈화 한복판을 힘차게 흘러요. 강 위의 수력 발전 댐들이 지역에 전력을 공급하고, 다리와 강변 산책로가 강기슭에 활기를 불어넣어요.'),
  'dazhou/gas': ('천연가스의 도시', '다저우 지하에 펼쳐진 푸광 가스전은 중국 최대급 천연가스전으로, 도시를 국가 에너지 기지 중 하나로 만들었어요. 이곳에서 뻗어 나간 파이프라인이 동부의 공업 도시들까지 이어지고, 가스 경제는 쓰촨의 이 산악 지대에 새로운 시대를 열었어요.'),
  'dazhou/ba': ('파나라 유적', '버들잎 모양의 검으로 이름난 고대 파(巴) 전사들의 땅이 바로 이곳으로, 호랑이 문양 청동기들이 뤄자바 유적에서 그들의 이야기를 들려줘요. 강 계곡에 살던 이 전사 민족의 신비로운 문화는 쓰촨 역사의 가장 오래된 지층 중 하나예요.'),
  'dazhou/dengying': ('덩잉뉴러우', '등불에 비치면 빛이 통과할 만큼 얇게 저며 양념하는 \'덩잉\' 쇠고기는 등불 앞에서 펼치던 그림자극에서 이름을 따왔어요. 종잇장처럼 얇고 바삭한 고기에 달콤하면서도 매운 양념이 입혀지는데, 다저우의 이 우아한 간식은 백 년 넘게 밥상을 빛내 왔어요.'),
  'dazhou/hanque': ('취현 한대 석궐', '취셴의 들판에 서 있는 2천 년 된 석궐(石闕)은 한나라 건축의 드물게 살아남은 우아한 유산이에요. 한때 무덤으로 가는 길목을 장식하던 이 조각된 문루들은 신화 속 짐승과 일상 풍경으로 한나라 세계를 돌에 새겨 놓았어요.'),
  'guangyuan/jianmen': ('젠먼관', '\'한 사람이 지키면 만 명도 못 지난다\'는 젠먼관은 칼날처럼 솟은 절벽으로 옛 촉도(蜀道)를 잠그는 자물쇠예요. 삼국시대부터 군대들이 얽히던 요충지였던 이 고개는 \'촉으로 가는 길은 하늘에 오르기보다 어렵다\'는 이백의 시구를 떠올리게 해요.'),
  'guangyuan/wuzetian': ('측천무후의 고향', '중국 역사상 유일한 여황제 측천무후는 광위안에서 태어났다고 전해지며, 황쩌사(皇澤寺)는 천 년 동안 그녀를 기려 왔어요. 도시는 해마다 여성 축제로 이 강인한 통치자를 기념하고, 강가 사찰에는 그녀의 조각상이 고요히 앉아 있어요.'),
  'guangyuan/plankroad': ('고대 잔도', '깎아지른 절벽에 박은 들보 위에 놓인 잔도(棧道)는 \'하늘에 오르기보다 어렵다\'던 촉도를 지날 수 있게 만든 용기의 기념비예요. 밍웨 협곡에는 옛길의 흔적이 아직 남아 있어, 방문객들은 복원된 널판 위를 걸으며 옛 대상들의 심장 박동을 느껴요.'),
  'guangyuan/cypress': ('추이윈랑', '옛길 양쪽으로 수만 그루의 오래된 측백나무가 늘어서 추이윈 회랑을 초록 터널로 만들어요. 전설에 따르면 나무의 일부는 삼국지 영웅 장비의 명으로 심었다고 하며, 이 그늘진 길은 세계에서 가장 오래 보존된 가로수길 중 하나로 꼽혀요.'),
  'yaan/panda': ('판다의 고향', '자이언트판다는 1869년 바오싱에서 처음 학계에 소개되었는데, 프랑스 박물학자 아르망 다비드의 보고서가 세계에 이 사랑스러운 동물을 알렸어요. 비펑샤 판다 기지가 그 유산을 이어 가고 있으며, 야안의 안개 낀 대나무 숲은 여전히 판다의 요람이에요.'),
  'yaan/rain': ('비의 도시', '\'야안의 비\'는 거의 매일 밤 지붕을 씻어 내리고, 아침이면 도시가 갓 헹군 듯한 천 가지 초록빛으로 반짝여요. 현지인들은 야안의 비, 야안의 물고기, 야안의 처녀라는 세 가지 아름다움을 꼽는데, 이 셋이 비의 도시가 지닌 부드럽고 넉넉한 정취를 요약해 줘요.'),
  'yaan/mengding': ('멍딩산 차', '전해지는 이야기로는 약 2천 년 전 멍딩산에서 인류가 처음으로 차나무를 심었다고 해서, 이 산은 차 문화의 요람으로 불려요. 정상의 오래된 차밭에서 딴 잎은 수백 년 동안 황제에게 바쳐졌고, 안개 낀 산비탈에서는 지금도 찻자리 의식이 열려요.'),
  'yaan/yayu': ('야위', '눈 녹은 물이 흐르는 개울에서 자라는 전설의 야위(雅魚)는 보글보글 끓는 전골로 상에 올라, 이 도시의 세 가지 아름다움 중 하나로 꼽혀요. 탄탄하고 흰 살로 유명한 이 물고기의 머릿속에는 칼 모양의 작은 뼈가 숨어 있어, 이 \'칼\'을 둘러싼 온갖 전설이 전해져요.'),
  'xianyang/qincapital': ('진나라 수도', '중국을 처음 통일한 진나라의 수도가 바로 이곳이었고, 진시황은 셴양에서 제국으로 가는 길을 걸었어요. 궁궐이 있던 자리에는 지금 유적지가 펼쳐져 있고, 박물관의 청동기와 궁궐 터가 2천 년이 넘는 옛 권력의 이야기를 속삭여 줘요.'),
  'xianyang/qianling': ('첸링', '측천무후와 남편 당 고종을 산에 새겨 함께 모신 첸링(건릉)은 도굴되지 않고 오늘까지 전해진 보기 드문 당나라 능묘예요. 돌 수호상과 외국 사신 석상들이 참배길을 장식하고, 측천무후가 세운 글자 없는 비석은 그녀에 대한 평가를 역사에 맡기고 있어요.'),
  'xianyang/zhengguo': ('정국거', '전국시대 말에 판 정국거(鄭國渠) 운하는 관중 평야에 물을 대어 진나라의 곡창으로 바꿔 놓았고, 통일의 경제적 토대를 놓았어요. 2천 년이 넘게 이 지역을 먹여 살려 온 이 수리 시설은 고대 공학의 천재적인 걸작이에요.'),
  'xianyang/guokui': ('궈쿠이', '솥뚜껑만큼 크고 두툼하며 바삭한 빵 \'궈쿠이\'는 산시(陝西)의 유명한 \'열 가지 기이함\' 중 하나로 꼽혀요. 장작불에 천천히 구워 며칠씩 두고 먹을 수 있는데, 옛날 병사들이 투구에 구워 먹었다는 이야기가 전해질 만큼 유래가 오래되었어요.'),
  'baoji/bronze': ('청동기의 도시', '주나라의 심장부였던 바오지 땅에서는 명문이 새겨진 청동기 수천 점이 출토되었는데, 그중 하준(何尊)에는 \'중국(中國)\'이라는 이름의 가장 오래된 기록이 담겨 있어요. 이 도시의 청동기 박물관은 3천 년 전의 장인 정신을 세계에서 가장 풍부한 컬렉션 중 하나로 보여 줘요.'),
  'baoji/famen': ('파먼사', '부처님의 손가락뼈 사리를 모신 법문사(파먼쓰)는 당나라 황제들의 성스러운 보물창고였어요. 1987년 탑 아래 숨겨진 지하 궁이 열리자 금과 은, 비단으로 이루어진 눈부신 당나라 보물이 세상에 드러났고, 오늘날에는 거대한 사찰 단지가 이 사리를 모시고 있어요.'),
  'baoji/taibai': ('타이바이산', '친링산맥의 지붕인 해발 3,771미터의 타이바이산은 여름까지 녹지 않는 눈으로 전설을 낳았는데, \'타이바이의 유월 눈\'은 옛 관중의 이름난 풍경 중 하나였어요. 빙하호로 오르는 산길은 중국 남북을 가르는 자연의 경계선 위를 걷게 해 줘요.'),
  'baoji/saozi': ('사오쯔면', '새콤하고 매콤한 고기 소스를 얹은 치산 \'사오쯔몐\'은 가늘고 길고 탱탱한 면발로 주나라 시대 요리의 살아 있는 맛이라 여겨져요. 식초와 볶은 고추의 춤에 당근, 달걀, 목이버섯이 어우러지고, 잔칫날 손님에게 그릇째 연이어 대접하는 것이 수백 년 된 풍습이에요.'),
};
